var TOPICS_DATA = TOPICS_DATA || {};
TOPICS_DATA["sql"] = TOPICS_DATA["sql"] || {};
TOPICS_DATA["sql"]["sql-database-basics"] = {"id":"sql-database-basics","title":"Database Basics","difficulty":"beginner","estimatedMinutes":20,"tldr":["A database is an organized collection of structured data, managed by a Database Management System (DBMS).","RDBMS (Relational DBMS) stores data in tables with rows and columns, enforcing relationships via foreign keys.","SQL (Structured Query Language) is the standard language for querying and managing relational databases.","Popular RDBMS: PostgreSQL, MySQL, SQL Server, Oracle, SQLite. PostgreSQL is the most advanced open-source option."],"laymanDefinition":"A database is like a digital filing cabinet. An RDBMS is a cabinet where files are stored in structured folders (tables), each with labeled columns, and you can link information between folders using references.","deepDive":[{"heading":"DBMS vs RDBMS","text":"DBMS stores data as files with no relationships. RDBMS stores data in tables with defined relationships via foreign keys. RDBMS supports ACID transactions, normalization, and complex queries with JOINs. DBMS is simpler (e.g., XML store), RDBMS is more powerful and widely used."},{"heading":"SQL Data Types","text":"Numeric: INT, SMALLINT, BIGINT, DECIMAL(p,s), FLOAT, REAL. Character: CHAR(n), VARCHAR(n), TEXT. Date/Time: DATE, TIME, TIMESTAMP, INTERVAL. Binary: BLOB, BYTEA. Special: BOOLEAN, UUID, JSON, JSONB, ARRAY (PostgreSQL uses type-specific data types)."},{"heading":"Tables Structure","text":"Tables consist of rows (records) and columns (fields). Each column has a defined data type and optional constraints. The schema defines the table structure. Tables can be linked through primary key / foreign key relationships."},{"heading":"SQL Sublanguages","text":"DDL (Data Definition Language): CREATE, ALTER, DROP. DML (Data Manipulation Language): SELECT, INSERT, UPDATE, DELETE. DCL (Data Control Language): GRANT, REVOKE. TCL (Transaction Control Language): BEGIN, COMMIT, ROLLBACK."},{"heading":"PostgreSQL vs MySQL","text":"PostgreSQL: advanced features (JSONB, full-text search, window functions, CTEs), stricter SQL standards compliance, extensible via extensions, better for complex queries and analytics. MySQL: faster for simple read-heavy workloads, widespread in LAMP stack, simpler replication."}],"interviewAnswer":"Understanding database fundamentals—RDBMS concepts, SQL data types, and table structure—is essential before diving into SQL. Choose PostgreSQL for features or MySQL for simplicity.","interviewQuestions":[{"question":"What is the difference between DBMS and RDBMS?","answer":"DBMS stores data as files with no relationships. RDBMS stores data in tables with relationships via foreign keys, supports ACID, normalization, and SQL queries."},{"question":"What are common SQL data types?","answer":"INT, VARCHAR(n), TEXT, DECIMAL(p,s), DATE, TIMESTAMP, BOOLEAN, UUID, JSON, JSONB. Types vary slightly between databases."},{"question":"What is a table in SQL?","answer":"A table is a collection of related data organized in rows (records) and columns (fields). Each column has a data type and optional constraints."},{"question":"What are the four SQL sublanguages?","answer":"DDL (schema definition), DML (data manipulation), DCL (access control), TCL (transaction control)."},{"question":"What is the difference between PostgreSQL and MySQL?","answer":"PostgreSQL has more advanced features (JSONB, full-text search, CTEs, window functions) and stricter SQL compliance. MySQL is simpler and faster for basic read-heavy workloads."},{"question":"What is a primary key?","answer":"A column or set of columns that uniquely identifies each row in a table. Must be unique and NOT NULL."},{"question":"What is a foreign key?","answer":"A column that references a primary key in another table, establishing a relationship and enforcing referential integrity."},{"question":"What is a schema in SQL?","answer":"A schema is a named collection of database objects (tables, views, functions). It organizes objects and controls access."},{"question":"What is NULL in SQL?","answer":"NULL represents missing or unknown data. It is not the same as 0 or empty string. Comparisons with NULL use IS NULL, not = NULL."},{"question":"What is the difference between CHAR and VARCHAR?","answer":"CHAR(n) is fixed-length (padded with spaces). VARCHAR(n) is variable-length (up to n). VARCHAR uses less space for variable-length data."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Database Basics</text><rect x=\"10\" y=\"40\" width=\"130\" height=\"30\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"75\" y=\"56\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">RDBMS</text><text x=\"75\" y=\"68\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Tables + Relations</text><line x1=\"140\" y1=\"55\" x2=\"170\" y2=\"55\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"180\" y=\"35\" width=\"130\" height=\"35\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"245\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">SQL</text><text x=\"245\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Query Language</text><line x1=\"310\" y1=\"53\" x2=\"340\" y2=\"53\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"350\" y=\"35\" width=\"130\" height=\"35\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"415\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Tables</text><text x=\"415\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Rows x Columns</text><rect x=\"180\" y=\"80\" width=\"130\" height=\"30\" rx=\"4\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1\"/><text x=\"245\" y=\"96\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">DDL</text><text x=\"245\" y=\"108\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">CREATE/ALTER/DROP</text><rect x=\"180\" y=\"120\" width=\"130\" height=\"30\" rx=\"4\" fill=\"#6610f2\" stroke=\"#6610f2\" stroke-width=\"1\"/><text x=\"245\" y=\"136\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">DML</text><text x=\"245\" y=\"148\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">SELECT/INSERT/UPDATE</text><rect x=\"180\" y=\"160\" width=\"130\" height=\"30\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"245\" y=\"176\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">DCL</text><text x=\"245\" y=\"188\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">GRANT/REVOKE</text><text x=\"240\" y=\"210\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Database Basics: RDBMS organizes data in tables with SQL for queries.</text></svg>","codeExamples":[{"title":"Create a Database","useCase":"Create and use a database.","code":"CREATE DATABASE company;\n\\c company; -- PostgreSQL: connect to database\nUSE company; -- MySQL: select database","description":"Creates a database named company and connects to it."},{"title":"Create a Table","useCase":"Define table structure.","code":"CREATE TABLE employees (\n  id SERIAL PRIMARY KEY,\n  name VARCHAR(100) NOT NULL,\n  email VARCHAR(255) UNIQUE NOT NULL,\n  salary DECIMAL(10,2) DEFAULT 0,\n  department VARCHAR(50),\n  hired_at DATE DEFAULT CURRENT_DATE\n);","description":"Creates employees table with various column types and constraints."},{"title":"Insert Sample Data","useCase":"Add rows to table.","code":"INSERT INTO employees (name, email, salary, department)\nVALUES ('Alice', 'alice@example.com', 75000, 'Engineering');","description":"Inserts a row into the employees table."},{"title":"Basic SELECT Query","useCase":"Query data from table.","code":"SELECT name, salary, department\nFROM employees\nWHERE salary > 50000\nORDER BY salary DESC;","description":"Selects names and salaries for employees earning >50k, sorted descending."},{"title":"Update and Delete","useCase":"Modify and remove data.","code":"UPDATE employees SET salary = 80000 WHERE id = 1;\nDELETE FROM employees WHERE id = 1;","description":"Updates salary then deletes the employee record."}],"mcqQuestions":[{"question":"What does RDBMS stand for?","options":["Relational Database Management System","Random Database Management System","Remote Database Management System","Relational Data Model System"],"answer":0,"explanation":"RDBMS stands for Relational Database Management System."},{"question":"Which SQL sublanguage handles data manipulation?","options":["DDL","DML","DCL","TCL"],"answer":1,"explanation":"DML (Data Manipulation Language) handles SELECT, INSERT, UPDATE, DELETE."},{"question":"What is a primary key?","options":["A unique identifier for rows","A foreign reference","A data type","An index type"],"answer":0,"explanation":"Primary key uniquely identifies each row."},{"question":"Which data type is variable-length string?","options":["CHAR","VARCHAR","TEXT","STRING"],"answer":1,"explanation":"VARCHAR is variable-length, CHAR is fixed-length."},{"question":"What does NULL represent?","options":["Zero","Empty string","Missing/unknown data","False"],"answer":2,"explanation":"NULL represents missing or unknown data."},{"question":"Which database has advanced JSONB support?","options":["MySQL","PostgreSQL","SQLite","SQL Server"],"answer":1,"explanation":"PostgreSQL excels with JSONB support for JSON operations."}]};
TOPICS_DATA["sql"]["sql-create-database"] = {"id":"sql-create-database","title":"CREATE & DROP Database","difficulty":"beginner","estimatedMinutes":15,"tldr":["CREATE DATABASE creates a new database. DROP DATABASE permanently deletes a database and all its data.","Use IF NOT EXISTS / IF EXISTS to avoid errors when database already exists or does not exist.","Database naming conventions: lowercase, underscores, meaningful names. Avoid SQL reserved words.","PostgreSQL uses CREATE DATABASE with encoding, locale, and template options. MySQL uses simpler syntax."],"laymanDefinition":"Creating a database is like setting up a new filing cabinet. Dropping it is like throwing that cabinet into a shredder — everything inside is gone forever.","deepDive":[{"heading":"CREATE DATABASE Syntax","text":"PostgreSQL: CREATE DATABASE dbname WITH ENCODING \\'UTF8\\' LC_COLLATE \\'en_US.UTF-8\\'. MySQL: CREATE DATABASE dbname CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci. Most basic: CREATE DATABASE dbname;"},{"heading":"DROP DATABASE","text":"DROP DATABASE dbname; — permanently deletes the database. Cannot be undone. All tables, data, indexes, views, functions dropped. PostgreSQL requires you to disconnect all connections first with pg_stat_activity."},{"heading":"IF EXISTS / IF NOT EXISTS","text":"CREATE DATABASE IF NOT EXISTS dbname; — creates only if not existing, skips without error. DROP DATABASE IF EXISTS dbname; — drops only if exists, skips without error. Prevents script failures."},{"heading":"Database Templates (PostgreSQL)","text":"PostgreSQL creates databases from a template. Default: template1. You can create custom templates. Options include encoding, locale, and collation settings that are copied from the template."},{"heading":"Connection Management","text":"Cannot drop a database while connections exist. PostgreSQL: use pg_terminate_backend() or ALTER DATABASE dbname ALLOW_CONNECTIONS = false first. MySQL: DROP DATABASE works while connected to another database."}],"interviewAnswer":"Creating and dropping databases are foundational DDL operations. Always use IF EXISTS / IF NOT EXISTS in scripts and be extremely careful with DROP.","interviewQuestions":[{"question":"How do you create a database in PostgreSQL?","answer":"CREATE DATABASE dbname; Or with options: CREATE DATABASE dbname ENCODING \\'UTF8\\'."},{"question":"What does DROP DATABASE do?","answer":"Permanently deletes the database and all its data. Cannot be recovered without a backup."},{"question":"What is IF NOT EXISTS?","answer":"A clause that prevents an error if the database already exists. Creates only if not present."},{"question":"Can you drop a database with active connections?","answer":"No. PostgreSQL requires terminating connections first. MySQL allows dropping while on a different database."},{"question":"What is a template database?","answer":"PostgreSQL creates databases from a template (default template1). Templates can have custom settings."},{"question":"How do you list databases?","answer":"PostgreSQL: \\l or SELECT datname FROM pg_database. MySQL: SHOW DATABASES."},{"question":"What naming conventions are recommended?","answer":"Lowercase, underscores, meaningful names. Avoid SQL reserved words (SELECT, TABLE, etc.)."},{"question":"How do you switch databases?","answer":"PostgreSQL: \\c dbname. MySQL: USE dbname."},{"question":"What is the maximum database name length?","answer":"63 characters by default in PostgreSQL (can be increased). MySQL allows up to 64 characters."},{"question":"How do you create a database with a specific encoding?","answer":"PostgreSQL: CREATE DATABASE dbname ENCODING \\'UTF8\\' LC_COLLATE \\'en_US.UTF-8\\'. MySQL: CREATE DATABASE dbname CHARACTER SET utf8mb4."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">CREATE & DROP Database</text><rect x=\"10\" y=\"40\" width=\"130\" height=\"30\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"75\" y=\"56\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">CREATE DATABASE</text><text x=\"75\" y=\"68\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">New Database</text><line x1=\"140\" y1=\"55\" x2=\"170\" y2=\"55\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"180\" y=\"40\" width=\"130\" height=\"30\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"245\" y=\"56\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">IF NOT EXISTS</text><text x=\"245\" y=\"68\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Skip if exists</text><line x1=\"310\" y1=\"55\" x2=\"340\" y2=\"55\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"350\" y=\"40\" width=\"130\" height=\"30\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"415\" y=\"56\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Ready</text><text x=\"415\" y=\"68\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Use Database</text><line x1=\"180\" y1=\"70\" x2=\"180\" y2=\"100\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"180\" y=\"105\" width=\"130\" height=\"30\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"245\" y=\"121\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">DROP DATABASE</text><text x=\"245\" y=\"133\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Permanent Delete</text><text x=\"240\" y=\"170\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">CREATE/DROP Database: Foundational DDL. Handle with care.</text></svg>","codeExamples":[{"title":"Create Basic Database","useCase":"Simple creation.","code":"CREATE DATABASE company;","description":"Creates a database named company with default settings."},{"title":"Create with Options (PostgreSQL)","useCase":"Specify encoding and locale.","code":"CREATE DATABASE company\n  ENCODING 'UTF8'\n  LC_COLLATE 'en_US.UTF-8'\n  LC_CTYPE 'en_US.UTF-8';","description":"Creates database with specific encoding and locale settings."},{"title":"Drop with IF EXISTS","useCase":"Safe dropping.","code":"DROP DATABASE IF EXISTS old_database;","description":"Drops only if exists, prevents error."},{"title":"List and Connect","useCase":"PostgreSQL commands.","code":"\\l -- list all databases\n\\c company -- connect to company database\n\n-- SQL equivalent:\nSELECT datname FROM pg_database;","description":"Lists databases and connects to one in PostgreSQL."},{"title":"MySQL Version","useCase":"MySQL-specific syntax.","code":"CREATE DATABASE IF NOT EXISTS company\n  CHARACTER SET utf8mb4\n  COLLATE utf8mb4_unicode_ci;\nSHOW DATABASES;\nUSE company;","description":"MySQL version with character set and collation."}],"mcqQuestions":[{"question":"What does CREATE DATABASE do?","options":["Creates a table","Creates a new database","Creates a user","Creates a schema"],"answer":1,"explanation":"CREATE DATABASE creates a new database."},{"question":"What does DROP DATABASE do?","options":["Removes all tables","Permanently deletes the database","Disconnects users","Archives the data"],"answer":1,"explanation":"DROP DATABASE permanently deletes the entire database."},{"question":"What does IF NOT EXISTS prevent?","options":["Duplicate data","Error if DB already exists","SQL injection","Data loss"],"answer":1,"explanation":"IF NOT EXISTS prevents error when database already exists."},{"question":"What command lists databases in PostgreSQL?","options":["SHOW DATABASES","\\l","LIST DB","SELECT databases"],"answer":1,"explanation":"\\l lists databases in PostgreSQL."},{"question":"What is the default PostgreSQL template database?","options":["template0","template1","postgres","default"],"answer":1,"explanation":"template1 is the default template database."},{"question":"What is the max database name length in PostgreSQL?","options":["32","63","128","256"],"answer":1,"explanation":"63 characters is the default maximum name length."}]};
TOPICS_DATA["sql"]["sql-create-alter-drop-table"] = {"id":"sql-create-alter-drop-table","title":"CREATE, ALTER & DROP Table","difficulty":"beginner","estimatedMinutes":20,"tldr":["CREATE TABLE defines a new table structure with columns, data types, and constraints.","ALTER TABLE modifies an existing table: add/drop columns, modify types, add/drop constraints.","DROP TABLE permanently deletes the table and its data. TRUNCATE removes all rows but keeps the table structure.","RENAME TABLE renames a table. Use IF EXISTS variants to avoid errors."],"laymanDefinition":"Creating a table is like designing a spreadsheet template. ALTER is like adding or removing columns later. DROP is shredding the whole spreadsheet.","deepDive":[{"heading":"CREATE TABLE Syntax","text":"CREATE TABLE tablename (column1 type constraints, column2 type constraints, table constraints);. Supports: DEFAULT values, column constraints, table-level constraints. Use IF NOT EXISTS to skip existing tables."},{"heading":"ALTER TABLE Operations","text":"Add column: ALTER TABLE t ADD COLUMN c TYPE. Drop column: ALTER TABLE t DROP COLUMN c. Modify type: ALTER TABLE t ALTER COLUMN c TYPE newtype. Rename column: ALTER TABLE t RENAME COLUMN old TO new. Add constraint: ALTER TABLE t ADD CONSTRAINT pk PRIMARY KEY (id)."},{"heading":"DROP TABLE vs TRUNCATE","text":"DROP TABLE deletes the table structure and data permanently. TRUNCATE TABLE removes all rows but keeps the table structure (faster than DELETE for all rows). TRUNCATE cannot be rolled back in some databases. DROP requires CASCADE if other objects depend on the table."},{"heading":"RENAME TABLE","text":"PostgreSQL: ALTER TABLE old RENAME TO new. MySQL: RENAME TABLE old TO new. SQL Server: sp_rename. Cannot rename across databases."},{"heading":"Temporary Tables","text":"CREATE TEMPORARY TABLE tmp (...) — table exists only for the session. Automatically dropped on session end. Useful for intermediate results. PostgreSQL also supports UNLOGGED tables for faster writes (no WAL logging, not crash-safe)."}],"interviewAnswer":"CREATE, ALTER, DROP, and TRUNCATE are essential DDL operations. Understanding the differences between DROP and TRUNCATE is critical for data management.","interviewQuestions":[{"question":"How do you create a table in SQL?","answer":"CREATE TABLE table_name (column1 datatype constraints, column2 datatype constraints, ...);"},{"question":"How do you add a column?","answer":"ALTER TABLE table_name ADD COLUMN column_name datatype;"},{"question":"How do you drop a column?","answer":"ALTER TABLE table_name DROP COLUMN column_name;"},{"question":"What is the difference between DROP and TRUNCATE?","answer":"DROP deletes the table structure and data. TRUNCATE removes all rows but keeps the structure. TRUNCATE is faster and cannot be filtered."},{"question":"What is a temporary table?","answer":"A table that exists only for the database session. Automatically dropped when the session ends. Created with CREATE TEMPORARY TABLE."},{"question":"How do you rename a table?","answer":"PostgreSQL: ALTER TABLE old_name RENAME TO new_name. MySQL: RENAME TABLE old_name TO new_name."},{"question":"What is IF NOT EXISTS in CREATE TABLE?","answer":"Prevents an error if the table already exists. Creates only if not present."},{"question":"Can you add a primary key after creating a table?","answer":"Yes: ALTER TABLE t ADD PRIMARY KEY (id);"},{"question":"What does CASCADE do in DROP TABLE?","answer":"Automatically drops objects that depend on the table (views, foreign keys). Without CASCADE, DROP fails if dependencies exist."},{"question":"What is TRUNCATE vs DELETE without WHERE?","answer":"TRUNCATE is faster, uses less transaction log, resets auto-increment counters. DELETE can be rolled back and triggers row-level triggers."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">CREATE, ALTER & DROP Table</text><rect x=\"10\" y=\"40\" width=\"130\" height=\"30\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"75\" y=\"56\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">CREATE TABLE</text><text x=\"75\" y=\"68\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">New structure</text><line x1=\"140\" y1=\"55\" x2=\"170\" y2=\"55\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"180\" y=\"35\" width=\"130\" height=\"35\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"245\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">ALTER TABLE</text><text x=\"245\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Modify columns</text><line x1=\"310\" y1=\"53\" x2=\"340\" y2=\"53\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"350\" y=\"35\" width=\"130\" height=\"35\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"415\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">DROP TABLE</text><text x=\"415\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Delete structure</text><rect x=\"180\" y=\"80\" width=\"130\" height=\"30\" rx=\"4\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1\"/><text x=\"245\" y=\"96\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">TRUNCATE</text><text x=\"245\" y=\"108\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Remove rows</text><rect x=\"180\" y=\"125\" width=\"130\" height=\"30\" rx=\"4\" fill=\"#6610f2\" stroke=\"#6610f2\" stroke-width=\"1\"/><text x=\"245\" y=\"141\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">RENAME</text><text x=\"245\" y=\"153\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Rename table</text><text x=\"240\" y=\"195\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Table DDL: CREATE, ALTER, DROP, TRUNCATE, and RENAME operations.</text></svg>","codeExamples":[{"title":"Create Table with Constraints","useCase":"Full definition.","code":"CREATE TABLE products (\n  id SERIAL PRIMARY KEY,\n  name VARCHAR(100) NOT NULL,\n  price DECIMAL(10,2) CHECK (price >= 0),\n  category VARCHAR(50) DEFAULT 'General',\n  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP\n);","description":"Creates products table with various constraints and defaults."},{"title":"ALTER TABLE Add/Drop Column","useCase":"Modify table structure.","code":"ALTER TABLE products ADD COLUMN description TEXT;\nALTER TABLE products DROP COLUMN description;\nALTER TABLE products ALTER COLUMN price TYPE NUMERIC(12,2);","description":"Adds, drops, and modifies column types."},{"title":"DROP vs TRUNCATE","useCase":"Key difference demo.","code":"-- Removes all rows, keeps structure\nTRUNCATE TABLE products;\n\n-- Removes table and all data permanently\nDROP TABLE products;\n\n-- Drop with CASCADE (handles dependencies)\nDROP TABLE products CASCADE;","description":"TRUNCATE removes data only. DROP removes everything."},{"title":"RENAME Table","useCase":"Rename examples.","code":"-- PostgreSQL\nALTER TABLE products RENAME TO inventory;\n\n-- MySQL\nRENAME TABLE products TO inventory;","description":"Renames the table in PostgreSQL and MySQL syntax."},{"title":"Temporary Table","useCase":"Session-specific table.","code":"CREATE TEMPORARY TABLE temp_results AS\nSELECT department, AVG(salary) as avg_salary\nFROM employees\nGROUP BY department;\n\nSELECT * FROM temp_results; -- auto-dropped on session end","description":"Creates a temporary table for intermediate results."}],"mcqQuestions":[{"question":"Which command deletes the table structure?","options":["TRUNCATE","DROP","DELETE","REMOVE"],"answer":1,"explanation":"DROP deletes the table structure. TRUNCATE only removes rows."},{"question":"Which command removes all rows but keeps structure?","options":["DROP","TRUNCATE","DELETE","CLEAR"],"answer":1,"explanation":"TRUNCATE removes all rows, keeps the table."},{"question":"How do you add a column?","options":["ADD COLUMN","ALTER TABLE ADD","ALTER TABLE ADD COLUMN","INSERT COLUMN"],"answer":2,"explanation":"ALTER TABLE ... ADD COLUMN adds a column."},{"question":"What does CASCADE do in DROP TABLE?","options":["Drops dependencies automatically","Prevents drop","Backs up table","Renames table"],"answer":0,"explanation":"CASCADE drops dependent objects."},{"question":"When is a temporary table dropped?","options":["On commit","On session end","On transaction end","Manually"],"answer":1,"explanation":"Temporary tables are dropped when the session ends."},{"question":"Which operation is faster for removing all rows?","options":["DELETE FROM","TRUNCATE","DROP","Both same"],"answer":1,"explanation":"TRUNCATE is faster than DELETE FROM for removing all rows."}]};
TOPICS_DATA["sql"]["sql-constraints"] = {"id":"sql-constraints","title":"Constraints","difficulty":"intermediate","estimatedMinutes":25,"tldr":["Constraints enforce rules on data in tables, ensuring data integrity and consistency.","Common constraints: PRIMARY KEY (unique ID), FOREIGN KEY (referential integrity), UNIQUE (no duplicates), CHECK (value conditions), DEFAULT (fallback value), NOT NULL (required field).","Constraints can be column-level (inline) or table-level (after columns). Table-level constraints can reference multiple columns.","PostgreSQL uses SERIAL/BIGSERIAL for auto-increment. MySQL uses AUTO_INCREMENT. PostgreSQL also supports GENERATED AS IDENTITY."],"laymanDefinition":"Constraints are like the rules for filling out a form: some fields must be filled (NOT NULL), some must be unique (UNIQUE), some must match another form (FOREIGN KEY), and some have automatic values (DEFAULT).","deepDive":[{"heading":"PRIMARY KEY","text":"Uniquely identifies each row. Must be unique and NOT NULL. Can be single column (id INT PRIMARY KEY) or composite (PRIMARY KEY (order_id, product_id)). Automatically creates a unique index. Only one primary key per table."},{"heading":"FOREIGN KEY","text":"Enforces referential integrity between tables. Ensures values in a column match values in the referenced table\\'s primary key. Options: ON DELETE CASCADE (delete child rows), ON DELETE SET NULL (set child FK to NULL), ON DELETE RESTRICT (prevent delete)."},{"heading":"UNIQUE and NOT NULL","text":"UNIQUE ensures all values in a column are different. Multiple UNIQUE constraints per table. NULL values are allowed (one NULL in PostgreSQL, multiple in MySQL). NOT NULL ensures the column always has a value."},{"heading":"CHECK and DEFAULT","text":"CHECK validates that values meet a condition: CHECK (salary > 0), CHECK (status IN (\\'active\\', \\'inactive\\')). DEFAULT provides a fallback value when no value is specified: DEFAULT CURRENT_DATE, DEFAULT 0."},{"heading":"Auto-Increment (SERIAL vs AUTO_INCREMENT)","text":"PostgreSQL: SERIAL creates an auto-incrementing integer column. BIGSERIAL for bigint. Newer: GENERATED AS IDENTITY (standard SQL). MySQL: AUTO_INCREMENT starts at 1 by default, can be customized. SQL Server: IDENTITY(1,1)."}],"interviewAnswer":"Constraints are the backbone of data integrity in SQL databases. They prevent invalid data at the database level, which is more reliable than application-level validation alone.","interviewQuestions":[{"question":"What is a PRIMARY KEY constraint?","answer":"Uniquely identifies each row. Must be unique and NOT NULL. Only one per table. Can be single or composite."},{"question":"What is a FOREIGN KEY constraint?","answer":"Enforces that values in a column match values in another table\\'s primary key. Maintains referential integrity."},{"question":"What does ON DELETE CASCADE do?","answer":"When a parent row is deleted, all child rows referencing it are automatically deleted."},{"question":"What is the difference between UNIQUE and PRIMARY KEY?","answer":"PRIMARY KEY is automatically NOT NULL. UNIQUE allows NULL values. One PK per table, multiple UNIQUE constraints allowed."},{"question":"What does CHECK do?","answer":"Validates that column values satisfy a boolean expression. Example: CHECK (age >= 0 AND age <= 150)."},{"question":"What does DEFAULT do?","answer":"Sets a default value for a column when no value is provided in INSERT."},{"question":"What is SERIAL in PostgreSQL?","answer":"An auto-incrementing integer column. Creates a sequence behind the scenes. Equivalent to AUTO_INCREMENT in MySQL."},{"question":"What is GENERATED AS IDENTITY?","answer":"A SQL standard syntax for auto-incrementing columns. Newer alternative to SERIAL in PostgreSQL."},{"question":"Can a table have multiple FOREIGN KEYs?","answer":"Yes. Each foreign key references a primary key in another table (or the same table for self-referencing)."},{"question":"What happens if you delete a parent row with RESTRICT?","answer":"The delete is prevented if child rows reference the parent. Use CASCADE or SET NULL to allow deletion."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Constraints</text><rect x=\"10\" y=\"40\" width=\"110\" height=\"30\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"65\" y=\"56\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">PRIMARY KEY</text><text x=\"65\" y=\"68\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Unique ID</text><rect x=\"10\" y=\"80\" width=\"110\" height=\"30\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"65\" y=\"96\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">FOREIGN KEY</text><text x=\"65\" y=\"108\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Reference</text><rect x=\"10\" y=\"120\" width=\"110\" height=\"30\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"65\" y=\"136\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">UNIQUE</text><text x=\"65\" y=\"148\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">No duplicates</text><rect x=\"10\" y=\"160\" width=\"110\" height=\"30\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"65\" y=\"176\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">NOT NULL</text><text x=\"65\" y=\"188\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Required</text><rect x=\"130\" y=\"40\" width=\"110\" height=\"30\" rx=\"4\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1\"/><text x=\"185\" y=\"56\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">CHECK</text><text x=\"185\" y=\"68\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Condition</text><rect x=\"130\" y=\"80\" width=\"110\" height=\"30\" rx=\"4\" fill=\"#6610f2\" stroke=\"#6610f2\" stroke-width=\"1\"/><text x=\"185\" y=\"96\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">DEFAULT</text><text x=\"185\" y=\"108\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Fallback value</text><line x1=\"240\" y1=\"55\" x2=\"270\" y2=\"55\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"240\" y1=\"95\" x2=\"270\" y2=\"95\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"280\" y=\"40\" width=\"200\" height=\"100\" rx=\"4\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1\"/><text x=\"380\" y=\"56\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Data Integrity</text><text x=\"380\" y=\"68\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Ensures valid, consistent, and reliable data in the database.</text><text x=\"240\" y=\"190\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Constraints: Rules ensuring data integrity at the database level.</text></svg>","codeExamples":[{"title":"PRIMARY KEY Examples","useCase":"Single and composite PK.","code":"-- Single column primary key\nCREATE TABLE users (id SERIAL PRIMARY KEY, name VARCHAR(100));\n\n-- Composite primary key\nCREATE TABLE order_items (\n  order_id INT,\n  product_id INT,\n  quantity INT,\n  PRIMARY KEY (order_id, product_id)\n);","description":"Single and composite primary key definitions."},{"title":"FOREIGN KEY with CASCADE","useCase":"Referential integrity.","code":"CREATE TABLE orders (\n  id SERIAL PRIMARY KEY,\n  user_id INT REFERENCES users(id) ON DELETE CASCADE,\n  total DECIMAL(10,2)\n);","description":"Foreign key with ON DELETE CASCADE — deleting a user deletes their orders."},{"title":"CHECK and DEFAULT","useCase":"Value constraints.","code":"CREATE TABLE employees (\n  id SERIAL PRIMARY KEY,\n  name VARCHAR(100) NOT NULL,\n  salary DECIMAL(10,2) CHECK (salary > 0),\n  status VARCHAR(20) DEFAULT 'active' CHECK (status IN ('active', 'inactive')),\n  joined_at DATE DEFAULT CURRENT_DATE\n);","description":"CHECK validates salary > 0, status in list. DEFAULT sets fallback values."},{"title":"Auto-Increment Comparison","useCase":"SERIAL vs IDENTITY vs AUTO_INCREMENT.","code":"-- PostgreSQL (old style)\nCREATE TABLE t (id SERIAL PRIMARY KEY);\n\n-- PostgreSQL (new standard)\nCREATE TABLE t (id INT GENERATED ALWAYS AS IDENTITY PRIMARY KEY);\n\n-- MySQL\nCREATE TABLE t (id INT AUTO_INCREMENT PRIMARY KEY);","description":"Auto-increment syntax across databases."},{"title":"Multiple UNIQUE Constraints","useCase":"Unique on different columns.","code":"CREATE TABLE users (\n  id SERIAL PRIMARY KEY,\n  email VARCHAR(255) UNIQUE,\n  username VARCHAR(50) UNIQUE,\n  phone VARCHAR(20) UNIQUE\n);","description":"Multiple UNIQUE constraints enforce uniqueness on email, username, and phone."}],"mcqQuestions":[{"question":"Which constraint ensures a column has no duplicates?","options":["PRIMARY KEY","UNIQUE","FOREIGN KEY","CHECK"],"answer":1,"explanation":"UNIQUE ensures no duplicate values. PRIMARY KEY also ensures uniqueness."},{"question":"What does ON DELETE CASCADE do?","options":["Prevents deletion","Deletes child rows automatically","Sets FK to NULL","Creates backup"],"answer":1,"explanation":"CASCADE deletes child rows when parent is deleted."},{"question":"Which constraint checks a boolean condition?","options":["CHECK","DEFAULT","UNIQUE","NOT NULL"],"answer":0,"explanation":"CHECK evaluates a boolean condition for each row."},{"question":"What is PostgreSQL equivalent of MySQL AUTO_INCREMENT?","options":["SEQUENCE","SERIAL","INCREMENT","AUTO"],"answer":1,"explanation":"SERIAL creates an auto-incrementing column in PostgreSQL."},{"question":"How many PRIMARY KEY constraints per table?","options":["One","Two","Unlimited","Depends on DB"],"answer":0,"explanation":"Only one PRIMARY KEY per table (can be composite)."},{"question":"What does RESTRICT do on DELETE?","options":["Deletes all","Prevents deletion if referenced","Sets to NULL","Cascades"],"answer":1,"explanation":"RESTRICT prevents deletion if foreign key references exist."}]};
TOPICS_DATA["sql"]["sql-crud"] = {"id":"sql-crud","title":"CRUD Operations","difficulty":"beginner","estimatedMinutes":20,"tldr":["CRUD stands for Create (INSERT), Read (SELECT), Update (UPDATE), Delete (DELETE) — the four basic data operations.","INSERT adds new rows: INSERT INTO table (columns) VALUES (values); Can insert multiple rows in one statement.","SELECT retrieves data: SELECT columns FROM table WHERE condition; Supports filtering, sorting, and joining.","UPDATE modifies existing rows: UPDATE table SET column = value WHERE condition; Always use WHERE to avoid updating all rows."],"laymanDefinition":"CRUD operations are the ABCs of database interaction — they let you create new records, read existing ones, update them, and delete them.","deepDive":[{"heading":"INSERT Statement","text":"Insert single row: INSERT INTO t (c1, c2) VALUES (v1, v2). Multi-row: INSERT INTO t (c1) VALUES (v1), (v2), (v3). Insert from query: INSERT INTO t SELECT * FROM other_t. RETURNING clause (PostgreSQL) returns inserted data."},{"heading":"SELECT Statement","text":"SELECT column1, column2 FROM table WHERE condition ORDER BY column LIMIT n. SELECT * returns all columns (avoid in production). WHERE filters rows. ORDER BY sorts results. LIMIT / OFFSET restricts results."},{"heading":"UPDATE Statement","text":"UPDATE table SET column1 = value1, column2 = value2 WHERE condition. Without WHERE, all rows are updated! RETURNING clause returns updated rows. Can update from another table using subquery or FROM clause."},{"heading":"DELETE Statement","text":"DELETE FROM table WHERE condition. Without WHERE, all rows are deleted (use TRUNCATE for performance). DELETE can use RETURNING (PostgreSQL). DELETE FROM using JOIN or USING for multi-table deletes."},{"heading":"RETURNING Clause (PostgreSQL)","text":"PostgreSQL extension: INSERT ... RETURNING * returns inserted rows. UPDATE ... RETURNING id returns updated row IDs. DELETE ... RETURNING * returns deleted rows. Extremely useful for getting auto-generated values without a separate query."}],"interviewAnswer":"CRUD operations are the foundation of database interaction. Mastering INSERT, SELECT, UPDATE, DELETE with all their variations is essential for any SQL developer.","interviewQuestions":[{"question":"What does INSERT do?","answer":"Adds new rows to a table. INSERT INTO table (columns) VALUES (values);"},{"question":"How do you select specific columns?","answer":"SELECT column1, column2 FROM table; Avoid SELECT * in production queries."},{"question":"What happens if UPDATE has no WHERE clause?","answer":"All rows in the table are updated. Always use WHERE with UPDATE unless that is intentional."},{"question":"How do you delete specific rows?","answer":"DELETE FROM table WHERE condition; Without WHERE, all rows are deleted."},{"question":"What is the RETURNING clause?","answer":"A PostgreSQL extension that returns affected rows from INSERT, UPDATE, or DELETE operations."},{"question":"How do you insert multiple rows at once?","answer":"INSERT INTO t (c1) VALUES (v1), (v2), (v3); — single statement, multiple rows."},{"question":"What columns should you avoid selecting with *?","answer":"Large text/BLOB columns, sensitive data (passwords), unnecessary columns. SELECT * causes unnecessary data transfer."},{"question":"How do you limit results in SELECT?","answer":"PostgreSQL/MySQL: LIMIT n. SQL Server: SELECT TOP n. Oracle: FETCH FIRST n ROWS ONLY."},{"question":"What is the difference between DELETE and TRUNCATE?","answer":"DELETE can have WHERE, triggers row-level triggers, slower, can be rolled back. TRUNCATE removes all rows fast, resets sequences, cannot be filtered."},{"question":"How do you insert data from another table?","answer":"INSERT INTO target_table SELECT * FROM source_table WHERE condition;"}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">CRUD Operations</text><rect x=\"10\" y=\"40\" width=\"100\" height=\"30\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"60\" y=\"56\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">CREATE</text><text x=\"60\" y=\"68\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">INSERT</text><rect x=\"10\" y=\"80\" width=\"100\" height=\"30\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"60\" y=\"96\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">READ</text><text x=\"60\" y=\"108\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">SELECT</text><rect x=\"10\" y=\"120\" width=\"100\" height=\"30\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"60\" y=\"136\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">UPDATE</text><text x=\"60\" y=\"148\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">UPDATE</text><rect x=\"10\" y=\"160\" width=\"100\" height=\"30\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"60\" y=\"176\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">DELETE</text><text x=\"60\" y=\"188\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">DELETE</text><line x1=\"110\" y1=\"55\" x2=\"140\" y2=\"55\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"110\" y1=\"95\" x2=\"140\" y2=\"95\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"110\" y1=\"135\" x2=\"140\" y2=\"135\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"110\" y1=\"175\" x2=\"140\" y2=\"175\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"150\" y=\"40\" width=\"230\" height=\"160\" rx=\"4\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1\"/><text x=\"265\" y=\"56\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">CRUD Operations</text><text x=\"265\" y=\"68\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Create / Read / Update / Delete — The four fundamental data operations.</text><text x=\"240\" y=\"225\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">CRUD: INSERT, SELECT, UPDATE, DELETE — the four basic data operations.</text></svg>","codeExamples":[{"title":"INSERT Examples","useCase":"Various insert techniques.","code":"-- Single row\nINSERT INTO users (name, email) VALUES ('Alice', 'alice@example.com');\n\n-- Multiple rows\nINSERT INTO users (name, email) VALUES ('Bob', 'bob@x.com'), ('Carol', 'carol@x.com');\n\n-- With RETURNING (PostgreSQL)\nINSERT INTO users (name, email) VALUES ('Dave', 'dave@x.com') RETURNING id;","description":"Single insert, multi-row insert, and RETURNING clause."},{"title":"SELECT Examples","useCase":"Filtering and sorting.","code":"SELECT name, salary, department\nFROM employees\nWHERE department = 'Engineering'\nORDER BY salary DESC\nLIMIT 10;","description":"Selects top 10 Engineering salaries."},{"title":"UPDATE with WHERE","useCase":"Safe update pattern.","code":"UPDATE employees\nSET salary = 85000, last_raised = CURRENT_DATE\nWHERE id = 5\nRETURNING id, name, salary;","description":"Updates specific employee, returns updated data."},{"title":"DELETE with Subquery","useCase":"Delete based on related data.","code":"DELETE FROM orders\nWHERE user_id IN (\n  SELECT id FROM users WHERE last_login < '2024-01-01'\n);","description":"Deletes orders of inactive users using a subquery."},{"title":"Conditional UPDATE (CASE)","useCase":"Different updates per row.","code":"UPDATE employees\nSET salary = CASE\n  WHEN department = 'Engineering' THEN salary * 1.10\n  WHEN department = 'Sales' THEN salary * 1.08\n  ELSE salary * 1.05\nEND;","description":"Updates salaries with different percentages per department."}],"mcqQuestions":[{"question":"What does CRUD stand for?","options":["Create, Read, Update, Delete","Copy, Retrieve, Update, Drop","Create, Retrieve, Use, Delete","Copy, Read, Update, Drop"],"answer":0,"explanation":"CRUD: Create, Read, Update, Delete."},{"question":"Which SQL statement creates new rows?","options":["SELECT","INSERT","UPDATE","CREATE"],"answer":1,"explanation":"INSERT adds new rows to a table."},{"question":"What happens if UPDATE has no WHERE?","options":["Updates nothing","Updates all rows","Errors","Updates one row"],"answer":1,"explanation":"Without WHERE, UPDATE modifies all rows."},{"question":"Which clause returns affected rows (PostgreSQL)?","options":["RETURNING","OUTPUT","RESULTS","FEEDBACK"],"answer":0,"explanation":"RETURNING returns affected rows in PostgreSQL."},{"question":"How do you insert multiple rows in one statement?","options":["Multiple VALUES","Multiple INSERTs","INSERT ALL","INSERT MULTIPLE"],"answer":0,"explanation":"Use multiple value tuples: VALUES (v1), (v2)."},{"question":"Which deletes all rows but keeps structure?","options":["DELETE","TRUNCATE","DROP","CLEAR"],"answer":1,"explanation":"TRUNCATE removes all rows, keeps table structure."}]};
TOPICS_DATA["sql"]["sql-select-filtering"] = {"id":"sql-select-filtering","title":"SELECT & Filtering","difficulty":"beginner","estimatedMinutes":25,"tldr":["SELECT retrieves data from one or more tables. WHERE filters rows based on conditions.","DISTINCT removes duplicate rows from results. ORDER BY sorts results ascending (ASC) or descending (DESC).","Aliases (AS) rename columns or tables in query results for clarity.","LIMIT and OFFSET control row count and pagination. FETCH (SQL standard) and TOP (SQL Server) are alternatives."],"laymanDefinition":"SELECT is like asking a specific question from your filing cabinet. WHERE narrows down which files you look at, ORDER BY arranges them, and LIMIT gives you just the first few.","deepDive":[{"heading":"SELECT Clause","text":"SELECT column1, column2 FROM table — returns only specified columns. SELECT * returns all columns (avoid in production — wastes bandwidth, breaks if schema changes). SELECT expressions: SELECT UPPER(name), salary * 1.1 FROM employees."},{"heading":"WHERE Clause","text":"Filters rows before grouping/sorting. Operators: =, <>, <, >, <=, >=. Combine with AND, OR, NOT. Use parentheses to group conditions. Performance tip: index columns used in WHERE."},{"heading":"DISTINCT","text":"SELECT DISTINCT column FROM table — returns unique values, removing duplicates. SELECT DISTINCT col1, col2 — unique combinations. Alternative to GROUP BY for simple deduplication."},{"heading":"ORDER BY","text":"ORDER BY column1 ASC, column2 DESC — sorts results. ASC (default) for ascending, DESC for descending. Can order by column position (ORDER BY 1, 2) but use column names for clarity. NULLS FIRST / NULLS LAST controls NULL placement."},{"heading":"LIMIT / OFFSET / FETCH / TOP","text":"LIMIT n — first n rows (PostgreSQL, MySQL). LIMIT n OFFSET m — skip m, take n. FETCH FIRST n ROWS ONLY — SQL standard. FETCH NEXT n ROWS ONLY AFTER m ROWS. TOP n — SQL Server. OFFSET is inefficient for large pagination (use keyset pagination)."}],"interviewAnswer":"SELECT with WHERE, ORDER BY, DISTINCT, and LIMIT is the most common SQL query pattern. Mastering filtering and sorting is essential before moving to joins and aggregations.","interviewQuestions":[{"question":"What does SELECT do?","answer":"Retrieves data from database tables. Specifies which columns to return."},{"question":"How do you filter rows in SQL?","answer":"Use WHERE clause with conditions: WHERE column = value, WHERE column > value, WHERE column IN (list)."},{"question":"What does DISTINCT do?","answer":"Removes duplicate rows from the result set. Returns only unique values."},{"question":"How do you sort results?","answer":"ORDER BY column ASC (ascending) or DESC (descending). Can sort by multiple columns."},{"question":"What is the difference between LIMIT and OFFSET?","answer":"LIMIT restricts the number of rows. OFFSET skips a number of rows before returning. Used together for pagination."},{"question":"What is a column alias?","answer":"Renaming a column in query output using AS: SELECT name AS employee_name FROM employees;"},{"question":"What does NULLS LAST do?","answer":"In ORDER BY, places NULL values after non-NULL values. NULLS FIRST places them first."},{"question":"What is the difference between WHERE and HAVING?","answer":"WHERE filters rows before grouping. HAVING filters groups after aggregation."},{"question":"How do you select unique combinations of two columns?","answer":"SELECT DISTINCT col1, col2 FROM table; Returns unique pairs."},{"question":"What is keyset pagination?","answer":"Pagination using WHERE id > last_seen_id ORDER BY id LIMIT n — more efficient than OFFSET for large datasets."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">SELECT & Filtering</text><rect x=\"10\" y=\"40\" width=\"130\" height=\"30\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"75\" y=\"56\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">SELECT</text><text x=\"75\" y=\"68\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">col1, col2</text><line x1=\"140\" y1=\"55\" x2=\"170\" y2=\"55\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"180\" y=\"35\" width=\"130\" height=\"30\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"245\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">FROM</text><text x=\"245\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">table_name</text><line x1=\"310\" y1=\"50\" x2=\"340\" y2=\"50\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"350\" y=\"35\" width=\"130\" height=\"30\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"415\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">WHERE</text><text x=\"415\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">condition</text><rect x=\"180\" y=\"75\" width=\"130\" height=\"30\" rx=\"4\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1\"/><text x=\"245\" y=\"91\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">ORDER BY</text><text x=\"245\" y=\"103\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">sort column</text><rect x=\"180\" y=\"115\" width=\"130\" height=\"30\" rx=\"4\" fill=\"#6610f2\" stroke=\"#6610f2\" stroke-width=\"1\"/><text x=\"245\" y=\"131\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">LIMIT n</text><text x=\"245\" y=\"143\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">restrict rows</text><text x=\"240\" y=\"185\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">SELECT: Retrieve, filter, sort, and limit data from tables.</text></svg>","codeExamples":[{"title":"Basic SELECT","useCase":"Simple query examples.","code":"SELECT first_name, last_name, salary\nFROM employees;","description":"Selects specific columns from employees table."},{"title":"WHERE with Multiple Conditions","useCase":"Complex filtering.","code":"SELECT name, salary, department\nFROM employees\nWHERE department = 'Engineering'\n  AND salary > 60000\n  OR (department = 'Sales' AND salary > 50000);","description":"Combines AND/OR for complex filtering conditions."},{"title":"DISTINCT and ORDER BY","useCase":"Unique values sorted.","code":"SELECT DISTINCT department\nFROM employees\nORDER BY department ASC;","description":"Returns unique departments in alphabetical order."},{"title":"LIMIT with OFFSET for Pagination","useCase":"Page-based pagination.","code":"SELECT name, salary\nFROM employees\nORDER BY salary DESC\nLIMIT 10 OFFSET 20; -- Page 3 (rows 21-30)","description":"Returns page 3 of employees sorted by salary (10 per page)."},{"title":"Aliases","useCase":"Renaming columns and tables.","code":"SELECT\n  name AS employee_name,\n  salary * 12 AS annual_salary\nFROM employees AS e\nWHERE e.department = 'Engineering';","description":"Renames columns and uses table alias e."}],"mcqQuestions":[{"question":"Which clause filters rows?","options":["SELECT","WHERE","ORDER BY","LIMIT"],"answer":1,"explanation":"WHERE filters rows based on conditions."},{"question":"What does DISTINCT remove?","options":["Columns","Duplicate rows","NULL values","Indexes"],"answer":1,"explanation":"DISTINCT removes duplicate rows from results."},{"question":"Which clause sorts results?","options":["GROUP BY","ORDER BY","SORT BY","HAVING"],"answer":1,"explanation":"ORDER BY sorts query results."},{"question":"What does LIMIT 10 OFFSET 20 do?","options":["First 10 rows","Skip 20, take 10","Last 10 rows","Skip 10, take 20"],"answer":1,"explanation":"Skips 20 rows then returns 10."},{"question":"How do you rename a column in output?","options":["AS clause","RENAME keyword","ALIAS keyword","NAME keyword"],"answer":0,"explanation":"Use column_name AS alias_name."},{"question":"What is the default sort direction?","options":["ASC","DESC","No default","Depends on column"],"answer":0,"explanation":"Default ORDER BY direction is ASC (ascending)."}]};
TOPICS_DATA["sql"]["sql-where-operators"] = {"id":"sql-where-operators","title":"WHERE Operators","difficulty":"beginner","estimatedMinutes":20,"tldr":["WHERE operators allow precise filtering: comparison, pattern matching, range checks, and NULL handling.","LIKE performs pattern matching with % (any sequence) and _ (single character) wildcards.","BETWEEN checks if a value is within a range (inclusive). IN checks membership in a list.","IS NULL and IS NOT NULL check for NULL values. NULL cannot be compared with = or !=."],"laymanDefinition":"WHERE operators are like different lenses for filtering: LIKE is a fuzzy search, BETWEEN is a range check, IN is a checklist, IS NULL checks for empty spots.","deepDive":[{"heading":"Comparison Operators","text":"= (equal), <> or != (not equal), <, >, <=, >=. String comparisons are case-sensitive in PostgreSQL, case-insensitive in MySQL by default. Use ILIKE (PostgreSQL) or LOWER() for case-insensitive comparison."},{"heading":"LIKE and ILIKE","text":"LIKE \\'pattern\\': % matches any sequence of characters, _ matches a single character. Examples: LIKE \\'A%\\' (starts with A), LIKE \\'%son\\' (ends with son), LIKE \\'%middle%\\' (contains). ILIKE (PostgreSQL) is case-insensitive. SIMILAR TO provides regex-like patterns."},{"heading":"BETWEEN","text":"column BETWEEN x AND y — inclusive of both endpoints. Equivalent to column >= x AND column <= y. Works with numbers, dates, and strings. NOT BETWEEN excludes the range."},{"heading":"IN and NOT IN","text":"column IN (value1, value2, value3) — matches any value in the list. More readable than multiple OR conditions. NOT IN excludes values. Be careful: NOT IN with subquery returning NULLs causes no rows (NULL propagation)."},{"heading":"IS NULL and IS NOT NULL","text":"IS NULL checks for NULL. IS NOT NULL checks for non-NULL. NULL = NULL is false (NULL is not equal to anything). NULL != NULL is also false. Use IS DISTINCT FROM (PostgreSQL) for NULL-safe comparison."}],"interviewAnswer":"WHERE operators give you precise control over which rows are returned. Understanding NULL behavior is particularly important — it is the most common source of bugs in SQL queries.","interviewQuestions":[{"question":"How do you match patterns in SQL?","answer":"Use LIKE with % (any sequence) and _ (single character). LIKE \\'A%\\' matches strings starting with A."},{"question":"What is the difference between LIKE and ILIKE?","answer":"LIKE is case-sensitive. ILIKE (PostgreSQL) is case-insensitive."},{"question":"What does BETWEEN do?","answer":"Checks if a value is within an inclusive range: WHERE age BETWEEN 18 AND 65."},{"question":"What does IN do?","answer":"Checks if a value matches any value in a list: WHERE status IN (\\'active\\', \\'pending\\')."},{"question":"Why does NULL = NULL return false?","answer":"NULL represents unknown. No value equals another unknown value. Use IS NULL to check."},{"question":"How do you check for NULL?","answer":"IS NULL or IS NOT NULL. Never use = NULL or != NULL."},{"question":"What is the problem with NOT IN and NULL subqueries?","answer":"If the subquery returns any NULL, NOT IN returns no rows. Use NOT EXISTS instead."},{"question":"What does _ match in LIKE?","answer":"A single character. LIKE \\'A_\\' matches \\'AB\\', \\'AC\\' but not \\'ABC\\'."},{"question":"What is IS DISTINCT FROM?","answer":"A PostgreSQL operator that treats NULL as a comparable value. NULL IS DISTINCT FROM NULL is false."},{"question":"How do you do a case-insensitive comparison?","answer":"Use ILIKE (PostgreSQL), LOWER(column) LIKE LOWER(\\'value\\'), or use a case-insensitive collation."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">WHERE Operators</text><rect x=\"10\" y=\"40\" width=\"110\" height=\"30\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"65\" y=\"56\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">LIKE</text><text x=\"65\" y=\"68\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Pattern match</text><rect x=\"10\" y=\"80\" width=\"110\" height=\"30\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"65\" y=\"96\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">BETWEEN</text><text x=\"65\" y=\"108\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Range check</text><rect x=\"10\" y=\"120\" width=\"110\" height=\"30\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"65\" y=\"136\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">IN</text><text x=\"65\" y=\"148\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">List match</text><rect x=\"10\" y=\"160\" width=\"110\" height=\"30\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"65\" y=\"176\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">IS NULL</text><text x=\"65\" y=\"188\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Null check</text><rect x=\"130\" y=\"40\" width=\"110\" height=\"30\" rx=\"4\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1\"/><text x=\"185\" y=\"56\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">AND/OR</text><text x=\"185\" y=\"68\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Combine</text><rect x=\"130\" y=\"80\" width=\"110\" height=\"30\" rx=\"4\" fill=\"#6610f2\" stroke=\"#6610f2\" stroke-width=\"1\"/><text x=\"185\" y=\"96\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">NOT</text><text x=\"185\" y=\"108\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Negate</text><line x1=\"240\" y1=\"55\" x2=\"270\" y2=\"55\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"240\" y1=\"95\" x2=\"270\" y2=\"95\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"280\" y=\"40\" width=\"200\" height=\"100\" rx=\"4\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1\"/><text x=\"380\" y=\"56\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">WHERE Operators</text><text x=\"380\" y=\"68\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Comparison, pattern matching, range, list, and NULL checking.</text><text x=\"240\" y=\"190\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">WHERE Operators: LIKE, BETWEEN, IN, IS NULL for precise filtering.</text></svg>","codeExamples":[{"title":"LIKE Pattern Matching","useCase":"Various patterns.","code":"SELECT name FROM employees WHERE name LIKE 'A%'; -- Starts with A\nSELECT name FROM employees WHERE name LIKE '%son'; -- Ends with son\nSELECT name FROM employees WHERE name LIKE '%mith%'; -- Contains mith\nSELECT name FROM employees WHERE name LIKE 'A_'; -- A followed by any char","description":"LIKE patterns for different matching scenarios."},{"title":"BETWEEN Dates","useCase":"Date range filtering.","code":"SELECT * FROM orders\nWHERE order_date BETWEEN '2024-01-01' AND '2024-12-31';","description":"Filters orders within the year 2024 (inclusive)."},{"title":"IN Operator","useCase":"List membership.","code":"SELECT name, department FROM employees\nWHERE department IN ('Engineering', 'Sales', 'Marketing')\nORDER BY department;","description":"Returns employees in specified departments."},{"title":"NULL Checking","useCase":"Handle NULL values.","code":"SELECT name, email FROM users\nWHERE email IS NOT NULL; -- Users with email\n\nSELECT name, phone FROM users\nWHERE phone IS NULL; -- Users without phone","description":"Filters for NULL and NOT NULL values."},{"title":"Combined WHERE","useCase":"Complex conditions.","code":"SELECT name, salary, department\nFROM employees\nWHERE (department = 'Engineering' OR department = 'Sales')\n  AND salary BETWEEN 50000 AND 100000\n  AND name IS NOT NULL\nORDER BY salary DESC;","description":"Combines multiple operators with parentheses for grouping."}],"mcqQuestions":[{"question":"What does % match in LIKE?","options":["One character","Any sequence of characters","A digit","A space"],"answer":1,"explanation":"% matches any sequence of characters in LIKE patterns."},{"question":"Is BETWEEN inclusive?","options":["Yes","No","Depends on DB","Only for numbers"],"answer":0,"explanation":"BETWEEN includes both endpoints."},{"question":"How do you check for NULL?","options":["= NULL","IS NULL","== NULL","EQUALS NULL"],"answer":1,"explanation":"Use IS NULL to check for NULL values."},{"question":"What is the problem with NOT IN and NULL subquery?","options":["Slow performance","Returns no rows if NULL in subquery","Errors","Returns all rows"],"answer":1,"explanation":"NOT IN with NULL subquery returns no rows."},{"question":"What does _ match in LIKE?","options":["Zero chars","One char","Multiple chars","A digit"],"answer":1,"explanation":"_ matches exactly one character."},{"question":"Which PostgreSQL operator is NULL-safe?","options":["IS DISTINCT FROM","<=>","===","IS NOT"],"answer":0,"explanation":"IS DISTINCT FROM treats NULL as a comparable value."}]};
TOPICS_DATA["sql"]["sql-aggregate-functions"] = {"id":"sql-aggregate-functions","title":"Aggregate Functions","difficulty":"intermediate","estimatedMinutes":20,"tldr":["Aggregate functions perform calculations on a set of rows and return a single result.","COUNT(): counts rows. COUNT(*) counts all rows. COUNT(column) counts non-NULL values. COUNT(DISTINCT column) counts unique values.","SUM(), AVG(), MIN(), MAX(): sum, average, minimum, and maximum of numeric values.","Aggregates ignore NULL values (except COUNT(*)). Use COALESCE or IFNULL to handle NULLs in results."],"laymanDefinition":"Aggregate functions are like getting summary statistics. COUNT is like counting items, SUM is the total, AVG is the average, MIN is the smallest, MAX is the largest.","deepDive":[{"heading":"COUNT() Variations","text":"COUNT(*) — total number of rows including NULLs. COUNT(column) — number of non-NULL values in column. COUNT(DISTINCT column) — number of unique non-NULL values. COUNT(*) is typically the fastest."},{"heading":"SUM()","text":"SUM(column) — adds all non-NULL values in a numeric column. Returns NULL if no rows match (use COALESCE to default to 0). SUM(DISTINCT column) sums unique values."},{"heading":"AVG()","text":"AVG(column) — average of non-NULL values. Sum divided by count of non-NULL values. NULLs are not counted in the denominator. For integer columns, result may be truncated — cast to DECIMAL."},{"heading":"MIN() and MAX()","text":"MIN(column) — smallest value (numeric, date, or string). MAX(column) — largest value. For strings, uses alphabetical ordering. For dates, chronological order."},{"heading":"Handling NULLs in Aggregates","text":"Aggregate functions except COUNT(*) ignore NULLs. Use COALESCE: SUM(COALESCE(column, 0)). AVG of all NULLs returns NULL. Use WHERE column IS NOT NULL if you need explicit filtering."}],"interviewAnswer":"Aggregate functions are essential for data analysis. Understanding how they handle NULLs and using DISTINCT variants correctly is key to accurate results.","interviewQuestions":[{"question":"What does COUNT(*) return?","answer":"Total number of rows in the table or group, including rows with NULL values."},{"question":"What is the difference between COUNT(*) and COUNT(column)?","answer":"COUNT(*) counts all rows. COUNT(column) counts only non-NULL values in that column."},{"question":"What does AVG() return?","answer":"The average (mean) of non-NULL numeric values. Sum divided by count."},{"question":"Do aggregate functions include NULLs?","answer":"Most aggregate functions ignore NULLs. COUNT(*) is the exception — it includes all rows."},{"question":"How do you count unique values?","answer":"COUNT(DISTINCT column) — counts unique non-NULL values."},{"question":"What does SUM(column) return if no rows?","answer":"NULL. Use COALESCE(SUM(column), 0) to default to 0."},{"question":"What does MIN() return for string columns?","answer":"The first value in alphabetical order (lexicographic minimum)."},{"question":"Can you use aggregates without GROUP BY?","answer":"Yes. Without GROUP BY, the aggregate applies to all rows and returns a single row."},{"question":"How does AVG handle integer division?","answer":"AVG of integers returns an integer in some databases. Cast to DECIMAL: AVG(column::DECIMAL)."},{"question":"What does MAX() return for dates?","answer":"The most recent date (chronologically latest)."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Aggregate Functions</text><rect x=\"10\" y=\"40\" width=\"100\" height=\"30\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"60\" y=\"56\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">COUNT</text><text x=\"60\" y=\"68\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Count rows</text><rect x=\"10\" y=\"80\" width=\"100\" height=\"30\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"60\" y=\"96\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">SUM</text><text x=\"60\" y=\"108\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Total values</text><rect x=\"10\" y=\"120\" width=\"100\" height=\"30\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"60\" y=\"136\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">AVG</text><text x=\"60\" y=\"148\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Average</text><rect x=\"10\" y=\"160\" width=\"100\" height=\"30\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"60\" y=\"176\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">MIN/MAX</text><text x=\"60\" y=\"188\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Extremes</text><line x1=\"110\" y1=\"55\" x2=\"140\" y2=\"55\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"110\" y1=\"95\" x2=\"140\" y2=\"95\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"110\" y1=\"135\" x2=\"140\" y2=\"135\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"110\" y1=\"175\" x2=\"140\" y2=\"175\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"150\" y=\"40\" width=\"230\" height=\"160\" rx=\"4\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1\"/><text x=\"265\" y=\"56\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Aggregate Functions</text><text x=\"265\" y=\"68\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Summarize data: count, sum, average, min, max — with NULL handling.</text><text x=\"240\" y=\"225\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Aggregate Functions: COUNT, SUM, AVG, MIN, MAX for data summarization.</text></svg>","codeExamples":[{"title":"COUNT Examples","useCase":"Different counting methods.","code":"SELECT\n  COUNT(*) AS total_rows,\n  COUNT(email) AS emails_provided,\n  COUNT(DISTINCT department) AS unique_depts\nFROM employees;","description":"Counts total rows, non-NULL emails, and unique departments."},{"title":"SUM and AVG","useCase":"Salary statistics.","code":"SELECT\n  SUM(salary) AS total_payroll,\n  AVG(salary) AS avg_salary,\n  MIN(salary) AS lowest_salary,\n  MAX(salary) AS highest_salary\nFROM employees;","description":"Computes payroll totals and salary statistics."},{"title":"Aggregate with WHERE","useCase":"Filtered aggregations.","code":"SELECT\n  COUNT(*) AS eng_count,\n  AVG(salary) AS avg_eng_salary\nFROM employees\nWHERE department = 'Engineering';","description":"Aggregates only Engineering employees."},{"title":"Handling NULLs with COALESCE","useCase":"Avoid NULL results.","code":"SELECT\n  COALESCE(AVG(bonus), 0) AS avg_bonus,\n  COALESCE(SUM(bonus), 0) AS total_bonus\nFROM employees;","description":"Returns 0 instead of NULL when no bonuses exist."},{"title":"COUNT and GROUP BY Preview","useCase":"Counts per group.","code":"SELECT department, COUNT(*) AS employee_count\nFROM employees\nGROUP BY department\nORDER BY employee_count DESC;","description":"Counts employees per department, sorted by count."}],"mcqQuestions":[{"question":"Which function counts non-NULL values only?","options":["COUNT(*)","COUNT(column)","COUNT_ALL","COUNT DISTINCT"],"answer":1,"explanation":"COUNT(column) counts only non-NULL values."},{"question":"What does AVG() return for all-NULL input?","options":["0","NULL","-1","Error"],"answer":1,"explanation":"AVG of all NULL values returns NULL."},{"question":"How do you sum unique values?","options":["SUM(column)","SUM(DISTINCT column)","UNIQUE SUM","SUM UNIQUE"],"answer":1,"explanation":"SUM(DISTINCT column) sums unique values."},{"question":"What does MAX() return for dates?","options":["Oldest date","Most recent date","NULL","Current date"],"answer":1,"explanation":"MAX() returns the most recent date."},{"question":"Can you use aggregates without GROUP BY?","options":["Yes","No","Only COUNT","Only with DISTINCT"],"answer":0,"explanation":"Aggregates can be used without GROUP BY for overall results."},{"question":"Which aggregate ignores NULLs?","options":["COUNT(*)","SUM","COUNT(column)","Both SUM and COUNT(column)"],"answer":3,"explanation":"Aggregate functions (except COUNT(*)) ignore NULLs."}]};
TOPICS_DATA["sql"]["sql-group-by"] = {"id":"sql-group-by","title":"GROUP BY & HAVING","difficulty":"intermediate","estimatedMinutes":25,"tldr":["GROUP BY groups rows that have the same values in specified columns, enabling aggregate calculations per group.","HAVING filters groups after aggregation, similar to how WHERE filters rows before aggregation.","GROUP BY columns must appear in SELECT (unless aggregated). SELECT can only have GROUP BY columns and aggregate functions.","GROUP BY works with COUNT, SUM, AVG, MIN, MAX to compute per-group statistics."],"laymanDefinition":"GROUP BY is like sorting items into buckets by category. Once sorted, you can count items in each bucket, find the average weight, or calculate the total value per bucket.","deepDive":[{"heading":"GROUP BY Basics","text":"SELECT department, COUNT(*) FROM employees GROUP BY department. Groups employees by department and counts per group. GROUP BY collapses groups — one row per unique combination of grouping columns."},{"heading":"GROUP BY Rules","text":"SELECT can only include: columns in GROUP BY clause, aggregate functions, or expressions based on those. PostgreSQL is stricter than MySQL about this rule (MySQL allows non-aggregated columns not in GROUP BY — can lead to unexpected results)."},{"heading":"HAVING vs WHERE","text":"WHERE filters individual rows before grouping. HAVING filters groups after aggregation. WHERE cannot use aggregate functions. HAVING can. Order: WHERE → GROUP BY → HAVING → ORDER BY."},{"heading":"Multiple Columns in GROUP BY","text":"GROUP BY col1, col2 — groups on unique combinations. Example: GROUP BY department, status groups by department and status together, creating subgroups."},{"heading":"GROUP BY with Expressions","text":"Group by computed values: GROUP BY EXTRACT(YEAR FROM order_date), GROUP BY UPPER(city). Can alias the expression in SELECT and use in GROUP BY (PostgreSQL: GROUP BY alias, MySQL: use expression)."}],"interviewAnswer":"GROUP BY with HAVING is the standard pattern for grouped aggregations. Understanding the difference between WHERE and HAVING filtering is crucial.","interviewQuestions":[{"question":"What does GROUP BY do?","answer":"Groups rows with same values in specified columns, enabling per-group aggregate calculations."},{"question":"What is the difference between WHERE and HAVING?","answer":"WHERE filters rows before grouping. HAVING filters groups after aggregation. WHERE cannot use aggregate functions."},{"question":"What columns can appear in SELECT with GROUP BY?","answer":"Only GROUP BY columns, aggregate functions, or expressions based on those columns."},{"question":"Can you GROUP BY multiple columns?","answer":"Yes. GROUP BY col1, col2 groups on unique combinations of both columns."},{"question":"What happens if you omit GROUP BY but use an aggregate?","answer":"The aggregate applies to all rows, returning a single row."},{"question":"Can you use aliases in GROUP BY?","answer":"PostgreSQL supports GROUP BY alias. MySQL requires the full expression."},{"question":"How do you filter before grouping?","answer":"Use WHERE before GROUP BY. WHERE processes individual rows, not groups."},{"question":"How do you filter after grouping?","answer":"Use HAVING after GROUP BY. HAVING checks conditions on aggregate results."},{"question":"What is the execution order of clauses?","answer":"FROM → WHERE → GROUP BY → HAVING → SELECT → ORDER BY → LIMIT."},{"question":"Can HAVING use non-aggregated columns?","answer":"Yes, if they appear in GROUP BY. HAVING department = \\'Engineering\\' is valid if GROUP BY department."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">GROUP BY & HAVING</text><rect x=\"10\" y=\"40\" width=\"140\" height=\"30\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"80\" y=\"56\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Raw Data</text><text x=\"80\" y=\"68\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">All rows</text><line x1=\"150\" y1=\"55\" x2=\"180\" y2=\"55\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"190\" y=\"35\" width=\"140\" height=\"30\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"260\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">WHERE</text><text x=\"260\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Filter rows</text><line x1=\"190\" y1=\"65\" x2=\"190\" y2=\"80\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"190\" y=\"85\" width=\"140\" height=\"30\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"260\" y=\"101\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">GROUP BY</text><text x=\"260\" y=\"113\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Group rows</text><line x1=\"330\" y1=\"70\" x2=\"360\" y2=\"70\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"190\" y1=\"115\" x2=\"190\" y2=\"130\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"190\" y=\"135\" width=\"140\" height=\"30\" rx=\"4\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1\"/><text x=\"260\" y=\"151\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">HAVING</text><text x=\"260\" y=\"163\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Filter groups</text><line x1=\"330\" y1=\"150\" x2=\"360\" y2=\"150\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"370\" y=\"35\" width=\"110\" height=\"150\" rx=\"4\" fill=\"#6610f2\" stroke=\"#6610f2\" stroke-width=\"1\"/><text x=\"425\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Result</text><text x=\"425\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">One row per group with aggregate values.</text><text x=\"240\" y=\"210\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">GROUP BY & HAVING: Group rows, apply aggregates, filter groups.</text></svg>","codeExamples":[{"title":"GROUP BY with COUNT","useCase":"Employees per department.","code":"SELECT department, COUNT(*) AS employee_count\nFROM employees\nGROUP BY department\nORDER BY employee_count DESC;","description":"Counts employees per department, sorted by count descending."},{"title":"GROUP BY with Multiple Aggregates","useCase":"Salary stats per dept.","code":"SELECT\n  department,\n  COUNT(*) AS count,\n  ROUND(AVG(salary), 2) AS avg_salary,\n  MAX(salary) AS max_salary\nFROM employees\nGROUP BY department;","description":"Multiple aggregates per department."},{"title":"HAVING to Filter Groups","useCase":"Departments with high avg salary.","code":"SELECT department, AVG(salary) AS avg_salary\nFROM employees\nGROUP BY department\nHAVING AVG(salary) > 70000;","description":"Filters groups where average salary exceeds 70000."},{"title":"WHERE + GROUP BY + HAVING","useCase":"Complete pipeline.","code":"SELECT department, AVG(salary) AS avg_salary\nFROM employees\nWHERE hire_date > '2020-01-01'\nGROUP BY department\nHAVING AVG(salary) > 50000\nORDER BY avg_salary DESC;","description":"Filters recent hires, groups, filters groups, orders."},{"title":"GROUP BY Multiple Columns","useCase":"Subtotals per combination.","code":"SELECT department, status, COUNT(*) AS count\nFROM employees\nGROUP BY department, status\nORDER BY department, status;","description":"Groups by department and status together — unique combinations."}],"mcqQuestions":[{"question":"What does GROUP BY do?","options":["Filters rows","Groups rows for aggregation","Orders results","Limits rows"],"answer":1,"explanation":"GROUP BY groups rows for per-group aggregation."},{"question":"Which filters groups after aggregation?","options":["WHERE","HAVING","FILTER","GROUP FILTER"],"answer":1,"explanation":"HAVING filters groups after aggregation."},{"question":"Can HAVING use aggregate functions?","options":["Yes","No","Only COUNT","Only SUM"],"answer":0,"explanation":"HAVING can use aggregate functions like AVG, COUNT, SUM."},{"question":"What columns are allowed in SELECT with GROUP BY?","options":["Any column","GROUP BY columns + aggregates","Only aggregates","Only GROUP BY columns"],"answer":1,"explanation":"Only GROUP BY columns and aggregate functions."},{"question":"What comes after GROUP BY in execution order?","options":["WHERE","HAVING","ORDER BY","FROM"],"answer":1,"explanation":"Execution order: WHERE → GROUP BY → HAVING → ORDER BY."},{"question":"What does GROUP BY col1, col2 do?","options":["Groups on col1 only","Groups on unique pairs","Two separate groups","Errors"],"answer":1,"explanation":"Groups rows on unique combinations of col1 and col2."}]};
TOPICS_DATA["sql"]["sql-grouping-sets"] = {"id":"sql-grouping-sets","title":"GROUPING SETS, ROLLUP & CUBE","difficulty":"advanced","estimatedMinutes":20,"tldr":["GROUPING SETS allow multiple GROUP BY queries in a single statement, returning combined results.","ROLLUP generates hierarchical subtotals from the most detailed to the grand total level.","CUBE generates subtotals for all possible combinations of grouping columns.","These are advanced reporting features, fully supported in PostgreSQL and SQL Server, partially in MySQL."],"laymanDefinition":"ROLLUP is like getting subtotals in a spreadsheet — department totals, then company total. CUBE is like every possible subtotal combination — by department, by status, by both, and grand total.","deepDive":[{"heading":"GROUPING SETS","text":"GROUP BY GROUPING SETS ((col1), (col2), ()) — runs three groupings: by col1, by col2, and grand total. More efficient than UNION ALL of separate GROUP BY queries. Each grouping set can have multiple columns."},{"heading":"ROLLUP","text":"GROUP BY ROLLUP (col1, col2) — generates subtotals at each level: (col1, col2), (col1), (). Hierarchy: col1 → col1+col2 → grand total. Useful for hierarchical data: year → month → day reports."},{"heading":"CUBE","text":"GROUP BY CUBE (col1, col2) — generates all possible subtotal combinations: (col1, col2), (col1), (col2), (). N columns = 2^N grouping sets. Can be expensive for many columns."},{"heading":"GROUPING() Function","text":"GROUPING(column) returns 1 if the row is a subtotal for that column (NULL means aggregated), 0 for detail rows. Essential for distinguishing NULL in data from NULL representing subtotals."},{"heading":"Use Cases","text":"Financial reports needing multiple aggregation levels. Sales dashboards: by region, by product, by both, total. Inventory summaries. Any report requiring drill-down with totals."}],"interviewAnswer":"ROLLUP, CUBE, and GROUPING SETS are powerful reporting features that produce multiple levels of aggregation in a single query, avoiding multiple UNION queries.","interviewQuestions":[{"question":"What is GROUPING SETS?","answer":"A GROUP BY variant that specifies multiple groupings in one query. More efficient than UNION of separate GROUP BY queries."},{"question":"What does ROLLUP do?","answer":"Generates hierarchical subtotals. GROUP BY ROLLUP (a, b) produces totals at (a,b), (a), and () levels."},{"question":"What does CUBE do?","answer":"Generates subtotals for all combinations. GROUP BY CUBE (a, b) produces (a,b), (a), (b), and ()."},{"question":"What is the GROUPING() function?","answer":"Returns 1 if a row is a subtotal for that column. Helps distinguish true NULLs from subtotal NULLs."},{"question":"How is ROLLUP different from CUBE?","answer":"ROLLUP generates only hierarchical subtotals (top-down). CUBE generates all possible combinations."},{"question":"How many groupings does CUBE of N columns produce?","answer":"2^N grouping sets. CUBE (a, b, c) produces 8 groupings."},{"question":"Can you use WHERE with ROLLUP?","answer":"Yes. WHERE filters rows before the rollup aggregation."},{"question":"What databases support GROUPING SETS?","answer":"PostgreSQL, SQL Server, Oracle fully support. MySQL has partial support for ROLLUP but not CUBE or GROUPING SETS."},{"question":"How is ROLLUP used in reporting?","answer":"Sales reports by year → quarter → month. Employee counts by department → location → total."},{"question":"What is the alternative without GROUPING SETS?","answer":"Multiple GROUP BY queries combined with UNION ALL. Less efficient and more verbose."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">GROUPING SETS, ROLLUP & CUBE</text><rect x=\"10\" y=\"40\" width=\"130\" height=\"30\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"75\" y=\"56\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">GROUP BY</text><text x=\"75\" y=\"68\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Basic grouping</text><line x1=\"140\" y1=\"55\" x2=\"170\" y2=\"55\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"180\" y=\"35\" width=\"130\" height=\"35\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"245\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">GROUPING SETS</text><text x=\"245\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Specific groupings</text><line x1=\"310\" y1=\"53\" x2=\"340\" y2=\"53\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"350\" y=\"35\" width=\"130\" height=\"35\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"415\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">ROLLUP</text><text x=\"415\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Hierarchical totals</text><rect x=\"180\" y=\"80\" width=\"130\" height=\"30\" rx=\"4\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1\"/><text x=\"245\" y=\"96\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">CUBE</text><text x=\"245\" y=\"108\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">All combinations</text><rect x=\"350\" y=\"80\" width=\"130\" height=\"30\" rx=\"4\" fill=\"#6610f2\" stroke=\"#6610f2\" stroke-width=\"1\"/><text x=\"415\" y=\"96\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">GROUPING()</text><text x=\"415\" y=\"108\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Identify subtotals</text><text x=\"240\" y=\"155\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">GROUPING SETS / ROLLUP / CUBE: Multiple aggregation levels in one query.</text></svg>","codeExamples":[{"title":"ROLLUP Example","useCase":"Department subtotals + grand total.","code":"SELECT department, status, COUNT(*) AS count\nFROM employees\nGROUP BY ROLLUP (department, status)\nORDER BY department, status;","description":"Counts employees by dept+status, dept subtotal, and grand total."},{"title":"CUBE Example","useCase":"All combination totals.","code":"SELECT department, status, COUNT(*) AS count\nFROM employees\nGROUP BY CUBE (department, status);","description":"Counts for all combinations: (dept,status), (dept), (status), and total."},{"title":"GROUPING SETS","useCase":"Specific groupings only.","code":"SELECT department, status, COUNT(*) AS count\nFROM employees\nGROUP BY GROUPING SETS ((department), (status), ());","description":"Three groupings: by dept, by status, and grand total only."},{"title":"GROUPING() Function","useCase":"Identify subtotal rows.","code":"SELECT\n  department,\n  status,\n  COUNT(*) AS count,\n  GROUPING(department) AS is_dept_total,\n  GROUPING(status) AS is_status_total\nFROM employees\nGROUP BY ROLLUP (department, status);","description":"GROUPING() returns 1 when the column is part of a subtotal row."},{"title":"ROLLUP with ORDER BY","useCase":"Controlling sort order.","code":"SELECT\n  EXTRACT(YEAR FROM order_date) AS year,\n  EXTRACT(MONTH FROM order_date) AS month,\n  SUM(amount) AS total_sales\nFROM orders\nGROUP BY ROLLUP (year, month)\nORDER BY year, month NULLS LAST;","description":"Monthly and yearly sales with grand total."}],"mcqQuestions":[{"question":"What does ROLLUP generate?","options":["All combinations","Hierarchical subtotals","Specific groupings","No subtotals"],"answer":1,"explanation":"ROLLUP creates hierarchical subtotals."},{"question":"How many groupings for CUBE (a,b,c)?","options":["3","6","8","9"],"answer":2,"explanation":"CUBE with 3 columns = 2^3 = 8 groupings."},{"question":"What does GROUPING() function do?","options":["Counts rows","Identifies subtotal rows","Groups data","Orders results"],"answer":1,"explanation":"GROUPING() identifies subtotal rows (returns 1)."},{"question":"Which is more efficient than multiple UNION GROUP BY?","options":["ROLLUP","GROUPING SETS","CUBE","All of the above"],"answer":3,"explanation":"All are more efficient than multiple UNION queries."},{"question":"Does MySQL fully support CUBE?","options":["Yes","No","Partial","Depends on version"],"answer":1,"explanation":"MySQL does not support CUBE or GROUPING SETS."},{"question":"What is the hierarchy for ROLLUP (a,b)?","options":["(a) then (a,b)","(a,b) then (a) then ()","(a), (b), ()","(a,b) only"],"answer":1,"explanation":"ROLLUP produces (a,b), then (a), then grand total ()."}]};
TOPICS_DATA["sql"]["sql-joins"] = {"id":"sql-joins","title":"Joins (INNER, LEFT, RIGHT, FULL, CROSS)","difficulty":"intermediate","estimatedMinutes":30,"tldr":["Joins combine rows from two or more tables based on a related column between them.","INNER JOIN returns only matching rows from both tables. LEFT JOIN returns all rows from left table plus matched rows from right.","RIGHT JOIN is the opposite of LEFT JOIN. FULL JOIN returns all rows from both tables. CROSS JOIN returns cartesian product.","Joins use ON clause to specify the join condition. Natural JOIN matches columns with same name automatically."],"laymanDefinition":"A JOIN is like inviting people from two different groups to a party. INNER JOIN only invites people confirmed from both groups. LEFT JOIN invites everyone from group A and anyone from group B who responds. FULL JOIN invites everyone from both groups.","deepDive":[{"heading":"INNER JOIN","text":"SELECT * FROM t1 INNER JOIN t2 ON t1.id = t2.fk_id. Returns rows only when the join condition matches in both tables. Most common join type. Can join multiple tables: t1 JOIN t2 ON ... JOIN t3 ON ..."},{"heading":"LEFT JOIN (LEFT OUTER JOIN)","text":"SELECT * FROM t1 LEFT JOIN t2 ON t1.id = t2.fk_id. Returns all rows from t1. If match found in t2, columns populated; if not, t2 columns are NULL. Use WHERE t2.id IS NULL to find rows with no match."},{"heading":"RIGHT JOIN","text":"SELECT * FROM t1 RIGHT JOIN t2 ON t1.id = t2.fk_id. Returns all rows from t2 regardless of match in t1. Mirror of LEFT JOIN. Can always be rewritten as LEFT JOIN by swapping table order."},{"heading":"FULL JOIN (FULL OUTER JOIN)","text":"SELECT * FROM t1 FULL JOIN t2 ON t1.id = t2.fk_id. Returns all rows from both tables. Matching rows combined, non-matching rows get NULL on the other side. Not supported in MySQL (use UNION of LEFT and RIGHT joins)."},{"heading":"CROSS JOIN and Self-Join","text":"CROSS JOIN produces cartesian product — every row of t1 matched with every row of t2. No ON clause needed. Self-join joins a table to itself using aliases: SELECT * FROM employees e1 JOIN employees e2 ON e1.manager_id = e2.id."}],"interviewAnswer":"Joins are fundamental SQL operations for combining data across related tables. Understanding the differences between join types and when to use each is essential for any data retrieval task.","interviewQuestions":[{"question":"What is a JOIN?","answer":"Combines rows from two or more tables based on a related column. The ON clause specifies the matching condition."},{"question":"What is the difference between INNER and LEFT JOIN?","answer":"INNER JOIN returns only matching rows. LEFT JOIN returns all rows from left table, with NULLs for non-matching right table columns."},{"question":"When would you use RIGHT JOIN?","answer":"When you want all rows from the right table regardless of match. Usually LEFT JOIN is preferred by swapping table order."},{"question":"What does FULL JOIN return?","answer":"All rows from both tables. Rows without matches have NULL on the opposite side."},{"question":"What is a CROSS JOIN?","answer":"Returns the cartesian product — every combination of rows from both tables. No ON clause."},{"question":"What is a self-join?","answer":"Joining a table to itself using different aliases. Used for hierarchical data like employee-manager relationships."},{"question":"Can you join more than 2 tables?","answer":"Yes. Chain joins: t1 JOIN t2 ON ... JOIN t3 ON ... Each additional join narrows or expands the result set."},{"question":"What does USING do in a join?","answer":"Shortcut when join columns have the same name: t1 JOIN t2 USING (id). Equivalent to ON t1.id = t2.id."},{"question":"What is a NATURAL JOIN?","answer":"Automatically joins on columns with the same name. Dangerous because schema changes can break it. Avoid in production."},{"question":"Can WHERE filter after JOIN?","answer":"Yes. WHERE filters the joined result. The order of filtering matters: WHERE before JOIN filters individual tables, WHERE after JOIN filters the combined result."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Joins (INNER, LEFT, RIGHT, FULL, CROSS)</text><rect x=\"10\" y=\"35\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"60\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">INNER</text><text x=\"60\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Match only</text><rect x=\"10\" y=\"65\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"60\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">LEFT</text><text x=\"60\" y=\"93\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">All left</text><rect x=\"10\" y=\"95\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"60\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">RIGHT</text><text x=\"60\" y=\"123\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">All right</text><rect x=\"10\" y=\"125\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"60\" y=\"141\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">FULL</text><text x=\"60\" y=\"153\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">All both</text><rect x=\"10\" y=\"155\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1\"/><text x=\"60\" y=\"171\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">CROSS</text><text x=\"60\" y=\"183\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Cartesian</text><line x1=\"110\" y1=\"48\" x2=\"140\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"110\" y1=\"78\" x2=\"140\" y2=\"78\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"110\" y1=\"108\" x2=\"140\" y2=\"108\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"110\" y1=\"138\" x2=\"140\" y2=\"138\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"110\" y1=\"168\" x2=\"140\" y2=\"168\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"150\" y=\"35\" width=\"230\" height=\"155\" rx=\"4\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1\"/><text x=\"265\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">JOIN Types</text><text x=\"265\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">INNER and LEFT are most common. FULL and CROSS for specific use cases.</text><text x=\"240\" y=\"220\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Joins: Combine related data from multiple tables using join conditions.</text></svg>","codeExamples":[{"title":"INNER JOIN Example","useCase":"Employees with their departments.","code":"SELECT e.name, e.salary, d.department_name\nFROM employees e\nINNER JOIN departments d ON e.dept_id = d.id\nORDER BY e.name;","description":"Returns only employees that belong to a department."},{"title":"LEFT JOIN Finding Missing Records","useCase":"Employees without departments.","code":"SELECT e.name, e.salary, d.department_name\nFROM employees e\nLEFT JOIN departments d ON e.dept_id = d.id\nWHERE d.id IS NULL;","description":"Finds employees with no matching department (orphan records)."},{"title":"Self-Join for Hierarchies","useCase":"Employee-manager relationships.","code":"SELECT e1.name AS employee, e2.name AS manager\nFROM employees e1\nLEFT JOIN employees e2 ON e1.manager_id = e2.id\nORDER BY e1.name;","description":"Joins employees table to itself to show reporting structure."},{"title":"FULL JOIN for Comparison","useCase":"All employees and departments.","code":"SELECT e.name, d.department_name\nFROM employees e\nFULL JOIN departments d ON e.dept_id = d.id\nWHERE e.id IS NULL OR d.id IS NULL;","description":"Finds orphaned records on either side of the relationship."},{"title":"Multiple Joins","useCase":"Orders with customer and product details.","code":"SELECT o.id AS order_id, c.name AS customer, p.name AS product, oi.quantity\nFROM orders o\nJOIN customers c ON o.customer_id = c.id\nJOIN order_items oi ON o.id = oi.order_id\nJOIN products p ON oi.product_id = p.id\nORDER BY o.id;","description":"Chains four tables together for a complete order report."}],"mcqQuestions":[{"question":"Which JOIN returns only matching rows?","options":["LEFT JOIN","INNER JOIN","RIGHT JOIN","FULL JOIN"],"answer":1,"explanation":"INNER JOIN returns only rows with matches in both tables."},{"question":"Which JOIN returns all rows from the left table?","options":["LEFT JOIN","INNER JOIN","RIGHT JOIN","CROSS JOIN"],"answer":0,"explanation":"LEFT JOIN returns all left table rows with matching right table data."},{"question":"What does CROSS JOIN produce?","options":["Only matching rows","Cartesian product","All left rows","Combined unique rows"],"answer":1,"explanation":"CROSS JOIN creates every combination of rows from both tables."},{"question":"What is a self-join?","options":["Two different tables","Table joined to itself","Two copies of same data","A view"],"answer":1,"explanation":"Self-join joins a table to itself using different aliases."},{"question":"What is the safe alternative to NATURAL JOIN?","options":["INNER JOIN with ON","LEFT JOIN","CROSS JOIN","FULL JOIN"],"answer":0,"explanation":"Use INNER JOIN with explicit ON clause instead of NATURAL JOIN."},{"question":"Which join type is not supported in MySQL?","options":["LEFT JOIN","RIGHT JOIN","FULL JOIN","INNER JOIN"],"answer":2,"explanation":"MySQL does not support FULL OUTER JOIN directly."}]};
TOPICS_DATA["sql"]["sql-subqueries"] = {"id":"sql-subqueries","title":"Subqueries & EXISTS","difficulty":"intermediate","estimatedMinutes":25,"tldr":["A subquery is a query nested inside another query, enclosed in parentheses. It can return scalar, single column, or multi-column results.","Scalar subqueries return a single value and can be used in SELECT, WHERE, and SET clauses.","IN, ANY, ALL operators compare expressions with subquery results. EXISTS checks if a subquery returns any rows.","Correlated subqueries reference columns from the outer query and execute once per outer row. They can be slower than JOINs."],"laymanDefinition":"A subquery is like asking a question inside another question. \"Show me all employees who earn more than the average salary.\" The inner question (what is the average?) answers first, then the outer question uses that result.","deepDive":[{"heading":"Scalar Subqueries","text":"Return a single value (one row, one column). Used in SELECT: SELECT name, (SELECT AVG(salary) FROM employees) AS avg. Used in WHERE: WHERE salary > (SELECT AVG(salary) FROM employees). Must return exactly one value."},{"heading":"Row and Column Subqueries","text":"Column subquery: SELECT * FROM employees WHERE dept_id IN (SELECT id FROM departments). Multi-column: WHERE (dept_id, salary) IN (SELECT id, max_salary FROM dept_budgets)."},{"heading":"EXISTS and NOT EXISTS","text":"EXISTS (subquery) returns true if the subquery returns at least one row. More efficient than IN for large datasets because it can use early exit. NOT EXISTS finds records with no match in the subquery."},{"heading":"ANY and ALL Operators","text":"column > ANY (subquery) — true if > any value returned. column > ALL (subquery) — true if > all values returned. ANY is equivalent to IN with = operator. ALL with != is equivalent to NOT IN."},{"heading":"Correlated Subqueries","text":"References outer query columns. Executed once per row of the outer query. Example: SELECT * FROM employees e WHERE salary > (SELECT AVG(salary) FROM employees WHERE dept_id = e.dept_id). Can be rewritten as JOIN with GROUP BY for better performance."}],"interviewAnswer":"Subqueries are powerful for dynamic filtering and calculations. Use them when the result depends on an aggregate or another query. Prefer JOINs for simple relationships and EXISTS for large dataset membership tests.","interviewQuestions":[{"question":"What is a subquery?","answer":"A query nested inside another SQL query, enclosed in parentheses. Executed before the outer query (except correlated)."},{"question":"What is a scalar subquery?","answer":"A subquery that returns a single value (one row, one column). Can be used in SELECT, WHERE, and SET clauses."},{"question":"How does EXISTS differ from IN?","answer":"EXISTS checks for row existence and can early-exit. IN retrieves all values first. EXISTS is often faster for large subquery results."},{"question":"What is a correlated subquery?","answer":"A subquery that references columns from the outer query. Executes once for each outer row. Can be slow for large datasets."},{"question":"What does ANY do?","answer":"Compares a value with any value returned by the subquery. x > ANY (1,2,3) is true if x > 1."},{"question":"What does ALL do?","answer":"Compares a value with all values returned. x > ALL (1,2,3) is true only if x > 3."},{"question":"Can subqueries be used in SELECT?","answer":"Yes. Scalar subqueries in SELECT: SELECT name, (SELECT MAX(salary) FROM employees) AS max_sal FROM employees;"},{"question":"Can subqueries be used in FROM?","answer":"Yes. Called a derived table or subquery in FROM: SELECT * FROM (SELECT * FROM employees WHERE salary > 50000) AS high_earners."},{"question":"What is the difference between IN and = ANY?","answer":"They are equivalent. IN is syntactically cleaner for simple cases. = ANY is more explicit."},{"question":"What happens if a scalar subquery returns no rows?","answer":"It evaluates to NULL. The outer query handles it based on NULL comparison rules."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Subqueries & EXISTS</text><rect x=\"10\" y=\"35\" width=\"120\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"70\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Scalar</text><text x=\"70\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Single value</text><rect x=\"10\" y=\"65\" width=\"120\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"70\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Row/Column</text><text x=\"70\" y=\"93\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Multiple values</text><rect x=\"10\" y=\"95\" width=\"120\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"70\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">EXISTS</text><text x=\"70\" y=\"123\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Row existence</text><rect x=\"10\" y=\"125\" width=\"120\" height=\"25\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"70\" y=\"141\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Correlated</text><text x=\"70\" y=\"153\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Per-row exec</text><line x1=\"130\" y1=\"48\" x2=\"160\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"130\" y1=\"78\" x2=\"160\" y2=\"78\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"130\" y1=\"108\" x2=\"160\" y2=\"108\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"130\" y1=\"138\" x2=\"160\" y2=\"138\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"170\" y=\"35\" width=\"210\" height=\"130\" rx=\"4\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1\"/><text x=\"275\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Subqueries</text><text x=\"275\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Nested queries for dynamic filtering and calculations in SQL.</text><text x=\"240\" y=\"195\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Subqueries: Scalar, column, correlated, and EXISTS for powerful dynamic queries.</text></svg>","codeExamples":[{"title":"Scalar Subquery in WHERE","useCase":"Employees above average salary.","code":"SELECT name, salary\nFROM employees\nWHERE salary > (SELECT AVG(salary) FROM employees)\nORDER BY salary DESC;","description":"Finds employees earning more than the company average."},{"title":"IN with Subquery","useCase":"Employees in active departments.","code":"SELECT name, dept_id\nFROM employees\nWHERE dept_id IN (SELECT id FROM departments WHERE status = 'active');","description":"Returns employees belonging to active departments only."},{"title":"EXISTS Example","useCase":"Customers who have placed orders.","code":"SELECT c.name, c.email\nFROM customers c\nWHERE EXISTS (SELECT 1 FROM orders o WHERE o.customer_id = c.id);","description":"EXISTS returns true when the subquery finds at least one order."},{"title":"Correlated Subquery","useCase":"Above-average salary by department.","code":"SELECT e.name, e.salary, e.dept_id\nFROM employees e\nWHERE e.salary > (\n  SELECT AVG(salary) FROM employees\n  WHERE dept_id = e.dept_id\n) ORDER BY e.dept_id;","description":"For each employee, compares salary to their own department average."},{"title":"Subquery in FROM (Derived Table)","useCase":"Second highest salary per dept.","code":"SELECT dept_id, MAX(salary) AS second_highest\nFROM employees\nWHERE salary < (\n  SELECT MAX(salary) FROM employees e2\n  WHERE e2.dept_id = employees.dept_id\n) GROUP BY dept_id;","description":"Uses a subquery to exclude the highest salary, then finds the next highest."}],"mcqQuestions":[{"question":"What does a scalar subquery return?","options":["A list","A single value","A table","Multiple rows"],"answer":1,"explanation":"Scalar subquery returns exactly one value (one row, one column)."},{"question":"What is a correlated subquery?","options":"References outer query","answer":"Executes once","explanation":"Is faster than JOIN"},{"question":"Which is faster for large datasets: EXISTS or IN?","options":["IN","EXISTS","Same","Depends on indexes"],"answer":1,"explanation":"EXISTS can short-circuit on first match, making it faster for large datasets."},{"question":"What does x > ALL (1,2,3) require?","options":["x > 1","x > 3","x > 0","x > 2"],"answer":1,"explanation":"ALL requires the value to be greater than every value in the set."},{"question":"Can a subquery be used in a SELECT clause?","options":["Yes","No","Only in WHERE","Only in FROM"],"answer":0,"explanation":"Scalar subqueries can be used in SELECT, WHERE, FROM, HAVING, and SET clauses."},{"question":"What is a derived table?","options":["A view","A subquery in FROM","A temporary table","An indexed view"],"answer":1,"explanation":"A derived table is a subquery placed in the FROM clause with an alias."}]};
TOPICS_DATA["sql"]["sql-ctes"] = {"id":"sql-ctes","title":"CTEs (Common Table Expressions)","difficulty":"intermediate","estimatedMinutes":25,"tldr":["A CTE is a temporary named result set that exists only within the scope of a single SQL statement.","CTEs improve readability by breaking complex queries into named, reusable blocks defined with the WITH clause.","Unlike subqueries, CTEs can be referenced multiple times in the same query and can reference each other.","CTEs are not materialized by default — the database optimizes them inline like subqueries."],"laymanDefinition":"A CTE is like writing down a temporary calculation on a sticky note before using it in your final answer. You define it once (WITH), then use it by name in your main query. It makes complex SQL look cleaner and more organized.","deepDive":[{"heading":"CTE Syntax","text":"WITH cte_name AS (SELECT ...) SELECT * FROM cte_name. Multiple CTEs: WITH cte1 AS (...), cte2 AS (...) SELECT ... FROM cte1 JOIN cte2. CTEs can reference previously defined CTEs in the same WITH clause."},{"heading":"CTE vs Subquery","text":"CTEs are more readable for complex queries. CTEs can be referenced multiple times (subqueries would be duplicated). CTEs support recursion. Performance: CTEs are typically optimized the same as subqueries (not materialized)."},{"heading":"Multiple CTEs","text":"WITH sales_data AS (...), avg_sales AS (SELECT AVG(total) FROM sales_data) SELECT * FROM avg_sales. Each CTE can access previous CTEs. Order matters — can only reference CTEs defined above."},{"heading":"CTE Use Cases","text":"Breaking down ETL pipelines step by step. Reusable subqueries. Recursive queries (tree structures). Pagination with complex filters. Data cleaning transformations before final query."},{"heading":"Materialized CTEs (PostgreSQL)","text":"PostgreSQL extension: WITH cte AS MATERIALIZED (...) forces materialization — CTE result is computed once and stored. WITH cte AS NOT MATERIALIZED (...) forces inlining. Useful for optimization tuning."}],"interviewAnswer":"CTEs are the preferred way to write complex queries in modern SQL. They improve readability, support recursion, and allow referencing the same result set multiple times without duplication.","interviewQuestions":[{"question":"What does CTE stand for?","answer":"Common Table Expression — a temporary named result set within a query."},{"question":"How do you define a CTE?","answer":"WITH cte_name AS (SELECT query) SELECT * FROM cte_name."},{"question":"What is the advantage of CTEs over subqueries?","answer":"CTEs can be referenced multiple times in the same query. They improve readability for complex queries. They support recursion."},{"question":"Can you define multiple CTEs?","answer":"Yes. Separate with commas: WITH cte1 AS (...), cte2 AS (...). Each can reference previous ones."},{"question":"Are CTEs materialized?","answer":"Not by default. The database optimizer treats them like inline subqueries. PostgreSQL supports MATERIALIZED and NOT MATERIALIZED hints."},{"question":"What is a recursive CTE?","answer":"A CTE that references itself, used for hierarchical or graph data. Defined with WITH RECURSIVE."},{"question":"When should you use a CTE instead of a subquery?","answer":"When the same subquery is needed multiple times, for recursive queries, or for complex multi-step transformations."},{"question":"Can CTEs be used in UPDATE and DELETE?","answer":"Yes. WITH cte AS (...) UPDATE table SET ... FROM cte WHERE ...;"},{"question":"Can a CTE be nested inside another CTE?","answer":"Yes. CTEs can reference previously defined CTEs in the same WITH clause."},{"question":"What is the performance impact of CTEs?","answer":"Generally same as subqueries. PostgreSQL MATERIALIZED hint can prevent repeated computation. PostgreSQL optimizes inlining automatically in most cases."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">CTEs (Common Table Expressions)</text><rect x=\"10\" y=\"35\" width=\"130\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"75\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">WITH cte AS</text><text x=\"75\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Define</text><rect x=\"10\" y=\"65\" width=\"130\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"75\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">SELECT cte</text><text x=\"75\" y=\"93\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Use</text><rect x=\"10\" y=\"95\" width=\"130\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"75\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Multiple CTEs</text><text x=\"75\" y=\"123\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Chain</text><rect x=\"10\" y=\"125\" width=\"130\" height=\"25\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"75\" y=\"141\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Recursive</text><text x=\"75\" y=\"153\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Self-reference</text><line x1=\"140\" y1=\"48\" x2=\"170\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"140\" y1=\"78\" x2=\"170\" y2=\"78\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"140\" y1=\"108\" x2=\"170\" y2=\"108\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"180\" y=\"35\" width=\"200\" height=\"120\" rx=\"4\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1\"/><text x=\"280\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Common Table Expressions</text><text x=\"280\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Temporary named result sets for cleaner, modular SQL queries.</text><text x=\"240\" y=\"195\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">CTEs: Named temporary result sets for readable, modular, and reusable SQL queries.</text></svg>","codeExamples":[{"title":"Basic CTE","useCase":"Simple named query.","code":"WITH high_earners AS (\n  SELECT name, salary, dept_id\n  FROM employees WHERE salary > 80000\n)\nSELECT h.name, h.salary, d.department_name\nFROM high_earners h\nJOIN departments d ON h.dept_id = d.id\nORDER BY h.salary DESC;","description":"Defines high earners CTE, then joins with departments."},{"title":"Multiple CTEs","useCase":"Step-by-step data pipeline.","code":"WITH\n  dept_stats AS (\n    SELECT dept_id, AVG(salary) AS avg_sal\n    FROM employees GROUP BY dept_id\n  ),\n  dept_ranking AS (\n    SELECT d.department_name, ds.avg_sal,\n      RANK() OVER (ORDER BY ds.avg_sal DESC) AS rnk\n    FROM dept_stats ds\n    JOIN departments d ON ds.dept_id = d.id\n  )\nSELECT * FROM dept_ranking WHERE rnk <= 3;","description":"Two CTEs chained together for department salary ranking."},{"title":"CTE in INSERT/UPDATE","useCase":"CTE with data modification.","code":"WITH avg_salary AS (\n  SELECT dept_id, AVG(salary) AS avg_sal\n  FROM employees GROUP BY dept_id\n)\nUPDATE employees e\nSET bonus = e.salary * 0.1\nFROM avg_salary a\nWHERE e.dept_id = a.dept_id\n  AND e.salary < a.avg_sal;","description":"Gives bonus to employees below department average salary."},{"title":"PostgreSQL MATERIALIZED CTE","useCase":"Force or prevent materialization.","code":"WITH\n  heavy_cte AS MATERIALIZED (\n    SELECT * FROM large_table\n    WHERE complex_condition\n  )\nSELECT * FROM heavy_cte h1\nJOIN heavy_cte h2 ON h1.id = h2.related_id\nWHERE h1.status = 'active';","description":"MATERIALIZED forces the CTE to be computed once."},{"title":"CTE with Window Functions","useCase":"Powerful combination.","code":"WITH ranked AS (\n  SELECT\n    name, salary, dept_id,\n    DENSE_RANK() OVER (\n      PARTITION BY dept_id ORDER BY salary DESC\n    ) AS rnk\n  FROM employees\n)\nSELECT * FROM ranked WHERE rnk <= 3\nORDER BY dept_id, rnk;","description":"CTE combined with window functions for top-N per group."}],"mcqQuestions":[{"question":"What does CTE stand for?","options":["Common Table Expression","Common Temporary Expression","Computed Table Element","Central Table Engine"],"answer":0,"explanation":"CTE stands for Common Table Expression."},{"question":"Which keyword defines a CTE?","options":["WITH","CTE","DEFINE","TEMP"],"answer":0,"explanation":"The WITH keyword is used to define CTEs."},{"question":"Can a CTE be referenced multiple times?","options":["Yes","No","Once only","Depends on database"],"answer":0,"explanation":"CTEs can be referenced multiple times in the same query."},{"question":"Are CTEs materialized by default?","options":["Yes","No","Only in PostgreSQL","Only in recursive CTEs"],"answer":1,"explanation":"CTEs are typically not materialized — they are inlined like subqueries."},{"question":"What keyword enables recursive CTEs?","options":["RECURSIVE","ITERATE","REPEAT","LOOP"],"answer":0,"explanation":"WITH RECURSIVE enables recursive CTEs."},{"question":"Which is more readable for complex queries?","options":["Subqueries","CTEs","JOINs","Temporary tables"],"answer":1,"explanation":"CTEs improve readability for complex multi-step queries."}]};
TOPICS_DATA["sql"]["sql-recursive-ctes"] = {"id":"sql-recursive-ctes","title":"Recursive CTEs","difficulty":"advanced","estimatedMinutes":30,"tldr":["Recursive CTEs are CTEs that reference themselves, enabling traversal of hierarchical or graph-structured data.","A recursive CTE has two parts: anchor member (initial result set) and recursive member (references the CTE itself).","The recursive member repeatedly executes until it returns no rows. UNION ALL combines results from all iterations.","Use cases: organizational charts, category trees, bill of materials, graph traversal, number generation."],"laymanDefinition":"A recursive CTE is like starting with one person in a family tree, finding their children, then finding their children's children, and so on until there are no more generations. Each step builds on the previous one.","deepDive":[{"heading":"Anatomy of Recursive CTE","text":"WITH RECURSIVE cte AS (anchor UNION ALL SELECT ... FROM cte WHERE ...) SELECT * FROM cte. Anchor: the starting point. Recursive member: joins back to CTE. Termination: when recursive member returns no rows."},{"heading":"Anchor Member","text":"The first SELECT in a recursive CTE. Runs once to produce the initial result set. Typically a WHERE clause that identifies root nodes: WHERE parent_id IS NULL or WHERE level = 1."},{"heading":"Recursive Member","text":"The second SELECT (after UNION ALL) that references the CTE name. Joins the CTE with the source table to find the next level. Must use UNION ALL (not UNION). Must eventually return no rows to terminate."},{"heading":"Hierarchical Data Patterns","text":"Org charts: anchor = CEO, recursive = direct reports. Category trees: anchor = root categories, recursive = subcategories. File systems: anchor = root directory, recursive = subdirectories."},{"heading":"MAXRECURSION Option","text":"SQL Server: OPTION (MAXRECURSION n) limits recursion depth (default 100). PostgreSQL: no explicit limit but will error on infinite recursion. MySQL: cte_max_recursion_depth system variable. Always add depth tracking for safety."}],"interviewAnswer":"Recursive CTEs are the standard SQL way to handle tree and graph data. They replace recursive functions and procedural code with a declarative, set-based approach.","interviewQuestions":[{"question":"What is a recursive CTE?","answer":"A CTE that references itself to process hierarchical data. Defined with WITH RECURSIVE and contains anchor + recursive members."},{"question":"What are the two parts of a recursive CTE?","answer":"Anchor member: initial query. Recursive member: references the CTE and adds next levels. UNION ALL combines them."},{"question":"How does a recursive CTE terminate?","answer":"When the recursive member returns zero rows, the recursion stops. A WHERE clause in the recursive member controls termination."},{"question":"What is the difference between UNION and UNION ALL in recursive CTEs?","answer":"UNION ALL is required. UNION would attempt deduplication, which breaks the recursion logic and may cause infinite loops."},{"question":"Can you track depth in a recursive CTE?","answer":"Yes. Add depth + 1 AS depth in the recursive member to track the current recursion level."},{"question":"What happens with infinite recursion?","answer":"PostgreSQL limits by work_mem and will error. SQL Server has MAXRECURSION (default 100). MySQL has cte_max_recursion_depth."},{"question":"Can recursive CTEs handle graphs with cycles?","answer":"Yes, by tracking visited nodes using arrays or path columns. Add a cycle detection column to prevent infinite loops."},{"question":"What is a common use case?","answer":"Org charts, category trees, folder structures, travel routes, dependency graphs, generating sequences of numbers/dates."},{"question":"How do you find all descendants?","answer":"Recursive CTE starting from a parent, joining children recursively until no more children found."},{"question":"How do you find the path from root to node?","answer":"Use a path column: CAST(node_name AS TEXT) AS path for anchor, and cte.path || \\' > \\' || t.node_name for recursive member."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Recursive CTEs</text><rect x=\"10\" y=\"35\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"60\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Anchor</text><text x=\"60\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Root rows</text><line x1=\"110\" y1=\"48\" x2=\"140\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"150\" y=\"35\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"200\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Recurse</text><text x=\"200\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Next level</text><line x1=\"150\" y1=\"60\" x2=\"150\" y2=\"80\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"250\" y1=\"48\" x2=\"280\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"290\" y=\"35\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"340\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">UNION ALL</text><text x=\"340\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Combine levels</text><line x1=\"290\" y1=\"60\" x2=\"290\" y2=\"80\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"390\" y1=\"48\" x2=\"420\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"10\" y=\"95\" width=\"280\" height=\"25\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"150\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Stop when no more rows</text><text x=\"150\" y=\"123\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Termination</text><text x=\"240\" y=\"170\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Recursive CTEs: Anchor + Recursive member for hierarchical data traversal.</text></svg>","codeExamples":[{"title":"Org Chart Traversal","useCase":"Employee reporting hierarchy.","code":"WITH RECURSIVE org_chart AS (\n  SELECT id, name, manager_id, 1 AS level\n  FROM employees WHERE manager_id IS NULL\n  UNION ALL\n  SELECT e.id, e.name, e.manager_id, oc.level + 1\n  FROM employees e\n  JOIN org_chart oc ON e.manager_id = oc.id\n)\nSELECT * FROM org_chart ORDER BY level, name;","description":"Traverses from CEO (no manager) down through all reporting levels."},{"title":"Category Tree with Path","useCase":"Nested categories with breadcrumb.","code":"WITH RECURSIVE cat_tree AS (\n  SELECT id, name, parent_id,\n    name::TEXT AS path, 1 AS level\n  FROM categories WHERE parent_id IS NULL\n  UNION ALL\n  SELECT c.id, c.name, c.parent_id,\n    ct.path || ' > ' || c.name,\n    ct.level + 1\n  FROM categories c\n  JOIN cat_tree ct ON c.parent_id = ct.id\n)\nSELECT * FROM cat_tree ORDER BY path;","description":"Builds full path for each category like \"Electronics > Computers > Laptops\"."},{"title":"Number Series Generation","useCase":"Generate date range.","code":"WITH RECURSIVE dates AS (\n  SELECT '2024-01-01'::DATE AS dt\n  UNION ALL\n  SELECT dt + INTERVAL '1 day'\n  FROM dates WHERE dt < '2024-01-31'\n)\nSELECT * FROM dates;","description":"Generates all dates in January 2024 without a calendar table."},{"title":"Cycle Detection","useCase":"Handle circular references safely.","code":"WITH RECURSIVE traverse AS (\n  SELECT id, name, manager_id,\n    ARRAY[id] AS visited, 1 AS level\n  FROM employees WHERE id = 1\n  UNION ALL\n  SELECT e.id, e.name, e.manager_id,\n    t.visited || e.id, t.level + 1\n  FROM employees e\n  JOIN traverse t ON e.manager_id = t.id\n  WHERE NOT e.id = ANY(t.visited)\n)\nSELECT * FROM traverse ORDER BY level;","description":"Uses array tracking to prevent infinite loops in cyclic data."},{"title":"Dependency Resolution","useCase":"Find all prerequisites.","code":"WITH RECURSIVE deps AS (\n  SELECT id, name, 0 AS depth\n  FROM courses WHERE id = 'ADV-SQL'\n  UNION ALL\n  SELECT c.id, c.name, d.depth + 1\n  FROM prerequisites p\n  JOIN deps d ON p.course_id = d.id\n  JOIN courses c ON p.prereq_id = c.id\n)\nSELECT * FROM deps ORDER BY depth DESC;","description":"Finds all prerequisite courses for Advanced SQL in dependency order."}],"mcqQuestions":[{"question":"What is the anchor member?","options":["First query that runs once","Recursive part","Termination condition","Final SELECT"],"answer":0,"explanation":"The anchor runs once to produce the initial result set."},{"question":"What combines anchor and recursive results?","options":["UNION","UNION ALL","JOIN","MERGE"],"answer":1,"explanation":"UNION ALL combines results without deduplication."},{"question":"When does a recursive CTE stop?","options":["Fixed iterations","No more rows from recursive member","Timeout","MAXRECURSION error"],"answer":1,"explanation":"Recursion stops when the recursive member returns zero rows."},{"question":"Which clause must recursive CTEs use?","options":["WITH RECURSIVE","WITH ITERATE","RECURSIVE CTE","WITH LOOP"],"answer":0,"explanation":"WITH RECURSIVE is the required syntax."},{"question":"What prevents infinite recursion in PostgreSQL?","options":["MAXRECURSION","work_mem","No safeguard","Automatic limit"],"answer":2,"explanation":"PostgreSQL does not have MAXRECURSION — it relies on work_mem to eventually error."},{"question":"Can you track depth in a recursive CTE?","options":["Yes","No","Only in anchor","Only in SQL Server"],"answer":0,"explanation":"Add a level counter column incremented in the recursive member."}]};
TOPICS_DATA["sql"]["sql-window-functions"] = {"id":"sql-window-functions","title":"Window Functions","difficulty":"advanced","estimatedMinutes":35,"tldr":["Window functions perform calculations across a set of rows related to the current row, without collapsing rows like GROUP BY.","OVER clause defines the window (partition, order, frame). PARTITION BY divides rows into groups. ORDER BY orders rows within each partition.","Ranking: ROW_NUMBER(), RANK(), DENSE_RANK(), NTILE(n). Value: LEAD(), LAG(), FIRST_VALUE(), LAST_VALUE(). Aggregate: SUM(), AVG() as window functions.","Window functions are evaluated after WHERE and GROUP BY but before ORDER BY and LIMIT."],"laymanDefinition":"A window function is like giving each person in a line a number based on their height WITHOUT making them leave the line. GROUP BY would make them form separate lines by category. Window functions keep everyone in place while still calculating group statistics.","deepDive":[{"heading":"OVER and PARTITION BY","text":"OVER () — window covers entire result set. OVER (PARTITION BY dept_id) — separate window per department. PARTITION BY divides rows into groups where the function operates independently. Without PARTITION BY, the function applies to all rows."},{"heading":"Ranking Functions","text":"ROW_NUMBER() — unique sequential number per row (ties get different numbers). RANK() — same rank for ties, skips numbers. DENSE_RANK() — same rank for ties, no gaps. NTILE(n) — divides rows into n buckets."},{"heading":"Window ORDER BY","text":"OVER (ORDER BY salary) — cumulative/windowed order. Changes behavior of aggregate window functions: SUM(salary) OVER (ORDER BY id) gives running total. For ranking functions, ORDER BY determines the ranking order."},{"heading":"Frame Specification","text":"ROWS BETWEEN UNBOUNDED PRECEDING AND CURRENT ROW — default frame for ORDER BY aggregates. RANGE vs ROWS: RANGE includes peers (same ORDER BY value). ROWS is strict row positions. Frame options: UNBOUNDED PRECEDING, n PRECEDING, CURRENT ROW."},{"heading":"LEAD and LAG","text":"LAG(column, n, default) — access previous row value. LEAD(column, n, default) — access next row value. Default n is 1. Default is used when no previous/next row exists. Useful for comparing current value to previous/next: month-over-month growth."}],"interviewAnswer":"Window functions are arguably the most powerful SQL feature for analytical queries. They enable running totals, moving averages, rankings, period-over-period comparisons, and much more without self-joins or subqueries.","interviewQuestions":[{"question":"What is a window function?","answer":"A function that performs calculations across a set of rows related to the current row, preserving individual row identity."},{"question":"What does PARTITION BY do?","answer":"Divides rows into groups where the window function operates independently. Like GROUP BY but without collapsing rows."},{"question":"What is the difference between ROW_NUMBER, RANK, and DENSE_RANK?","answer":"ROW_NUMBER: unique sequential (ties get different numbers). RANK: ties share rank, gaps. DENSE_RANK: ties share rank, no gaps."},{"question":"What does LEAD() do?","answer":"Accesses the value of the next row in the window order. LAG() accesses the previous row."},{"question":"What is a frame in window functions?","answer":"Defines the set of rows within the window for calculations. ROWS BETWEEN start AND end. Default: RANGE BETWEEN UNBOUNDED PRECEDING AND CURRENT ROW."},{"question":"What is the difference between ROWS and RANGE?","answer":"ROWS: strict physical row positions. RANGE: logical range including peers (rows with same ORDER BY value)."},{"question":"Can you use aggregate functions as window functions?","answer":"Yes. SUM(salary) OVER (PARTITION BY dept_id) gives department total alongside each row."},{"question":"What is a running total?","answer":"SUM(column) OVER (ORDER BY date) — cumulative sum ordered by date."},{"question":"What is a moving average?","answer":"AVG(column) OVER (ORDER BY date ROWS BETWEEN 6 PRECEDING AND CURRENT ROW) — 7-day moving average."},{"question":"Can window functions be used in WHERE?","answer":"No. Window functions are evaluated after WHERE. Use a subquery or CTE to filter on window function results."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Window Functions</text><rect x=\"10\" y=\"35\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"65\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">ROW_NUMBER</text><text x=\"65\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Sequential</text><rect x=\"10\" y=\"65\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"65\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">RANK/DENSE</text><text x=\"65\" y=\"93\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Ranking</text><rect x=\"10\" y=\"95\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"65\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">LEAD/LAG</text><text x=\"65\" y=\"123\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Prev/Next</text><rect x=\"10\" y=\"125\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"65\" y=\"141\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">SUM/AVG</text><text x=\"65\" y=\"153\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Aggregate</text><rect x=\"10\" y=\"155\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1\"/><text x=\"65\" y=\"171\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">NTILE</text><text x=\"65\" y=\"183\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Buckets</text><line x1=\"120\" y1=\"48\" x2=\"150\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"78\" x2=\"150\" y2=\"78\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"108\" x2=\"150\" y2=\"108\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"138\" x2=\"150\" y2=\"138\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"168\" x2=\"150\" y2=\"168\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"35\" width=\"220\" height=\"155\" rx=\"4\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1\"/><text x=\"270\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Window Functions</text><text x=\"270\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Analytical calculations across related rows without collapsing data.</text><text x=\"240\" y=\"220\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Window Functions: ROW_NUMBER, RANK, LEAD/LAG, aggregates — all with OVER clause.</text></svg>","codeExamples":[{"title":"Ranking Employees by Salary","useCase":"Top earners per department.","code":"SELECT\n  name, department, salary,\n  ROW_NUMBER() OVER (PARTITION BY department ORDER BY salary DESC) AS rn,\n  RANK() OVER (PARTITION BY department ORDER BY salary DESC) AS rk,\n  DENSE_RANK() OVER (PARTITION BY department ORDER BY salary DESC) AS dr\nFROM employees\nORDER BY department, rn;","description":"Compares ROW_NUMBER, RANK, and DENSE_RANK on department salary data."},{"title":"Running Total and Moving Average","useCase":"Cumulative sales.","code":"SELECT\n  order_date, amount,\n  SUM(amount) OVER (ORDER BY order_date) AS running_total,\n  AVG(amount) OVER (ORDER BY order_date\n    ROWS BETWEEN 6 PRECEDING AND CURRENT ROW) AS moving_avg_7d\nFROM orders\nORDER BY order_date;","description":"Running total and 7-day moving average of order amounts."},{"title":"LEAD and LAG for Comparison","useCase":"Month-over-month growth.","code":"SELECT\n  month, total_sales,\n  LAG(total_sales, 1) OVER (ORDER BY month) AS prev_month,\n  ROUND((total_sales - LAG(total_sales, 1) OVER (ORDER BY month))\n    / LAG(total_sales, 1) OVER (ORDER BY month) * 100, 2)\n    AS growth_pct\nFROM monthly_sales\nORDER BY month;","description":"Calculates month-over-month sales growth percentage."},{"title":"NTILE for Percentiles","useCase":"Divide employees into quartiles.","code":"SELECT\n  name, salary,\n  NTILE(4) OVER (ORDER BY salary DESC) AS quartile\nFROM employees\nORDER BY salary DESC;","description":"NTILE(4) divides employees into 4 salary quartiles."},{"title":"First and Last Values","useCase":"Salary range per department.","code":"SELECT\n  department, name, salary,\n  FIRST_VALUE(name) OVER (PARTITION BY department ORDER BY salary DESC) AS highest_paid,\n  LAST_VALUE(name) OVER (PARTITION BY department ORDER BY salary DESC\n    ROWS BETWEEN UNBOUNDED PRECEDING AND UNBOUNDED FOLLOWING) AS lowest_paid\nFROM employees\nORDER BY department, salary DESC;","description":"Shows highest and lowest paid employee name per department."}],"mcqQuestions":[{"question":"Which function gives unique sequential numbers?","options":["RANK","ROW_NUMBER","DENSE_RANK","NTILE"],"answer":1,"explanation":"ROW_NUMBER gives unique sequential numbers with no ties."},{"question":"What does PARTITION BY do?","options":["Groups rows","Orders rows","Limits rows","Filters rows"],"answer":0,"explanation":"PARTITION BY divides rows into independent groups."},{"question":"What does LAG() return?","options":["Next row value","Previous row value","First row value","Current row value"],"answer":1,"explanation":"LAG() accesses the value from the previous row."},{"question":"What is the default frame with ORDER BY?","options":["All rows","Current row only","UNBOUNDED PRECEDING TO CURRENT ROW","Previous 10 rows"],"answer":2,"explanation":"Default frame with ORDER BY is RANGE BETWEEN UNBOUNDED PRECEDING AND CURRENT ROW."},{"question":"Can window functions be used in WHERE?","options":["Yes","No","Only with aggregates","Only with ranking"],"answer":1,"explanation":"Window functions execute after WHERE, so they cannot be used directly in WHERE."},{"question":"What does NTILE(10) do?","options":["Top 10","Deciles","10 rows","10 partitions"],"answer":1,"explanation":"NTILE(10) divides rows into 10 approximately equal buckets (deciles)."}]};
TOPICS_DATA["sql"]["sql-set-operations"] = {"id":"sql-set-operations","title":"Set Operations (UNION, INTERSECT, EXCEPT)","difficulty":"intermediate","estimatedMinutes":20,"tldr":["Set operations combine results from two or more queries into a single result set.","UNION combines results and removes duplicates. UNION ALL combines results keeping all duplicates.","INTERSECT returns rows common to both queries. EXCEPT returns rows from first query not in second.","All set operations require same number of columns with compatible data types in all queries."],"laymanDefinition":"Set operations are like combining two guest lists. UNION gives you everyone on both lists (no repeats). INTERSECT gives you people on BOTH lists. EXCEPT gives you people on the first list but NOT the second.","deepDive":[{"heading":"UNION vs UNION ALL","text":"UNION: SELECT a UNION SELECT b — combines results, removes duplicates (slower, requires sort). UNION ALL: combines results, keeps duplicates (faster, no sort). Use UNION ALL when duplicates are acceptable or impossible."},{"heading":"INTERSECT","text":"SELECT a INTERSECT SELECT b — returns rows present in both queries. Can use INTERSECT ALL to keep duplicates. Performance: typically slower than EXISTS or IN for simple cases but more readable."},{"heading":"EXCEPT (MINUS)","text":"SELECT a EXCEPT SELECT b — returns rows in first query not in second. EXCEPT ALL keeps duplicates. Called MINUS in Oracle. Useful for finding missing records: which customers have not placed orders?"},{"heading":"Order and Column Requirements","text":"All queries must have same number of columns. Column data types must be compatible (PostgreSQL is strict about type matching). Column names come from the first query. ORDER BY applies to final result, placed after the last query."},{"heading":"Use Cases","text":"UNION: combining monthly sales tables. INTERSECT: finding common customers across regions. EXCEPT: identifying orphan records, validating data integrity, finding unused products."}],"interviewAnswer":"Set operations are essential for combining data from similar structures. UNION ALL is preferred for performance when duplicates are acceptable. INTERSECT and EXCEPT offer cleaner alternatives to complex JOIN and subquery patterns.","interviewQuestions":[{"question":"What does UNION do?","answer":"Combines results from two queries and removes duplicate rows. UNION ALL keeps all duplicates."},{"question":"What is the difference between UNION and UNION ALL?","answer":"UNION removes duplicates (slower). UNION ALL keeps all rows (faster). Use UNION ALL unless you need deduplication."},{"question":"What does INTERSECT return?","answer":"Rows that appear in both query results. Like an INNER JOIN on the entire row."},{"question":"What does EXCEPT return?","answer":"Rows from the first query that are not in the second query. Like a LEFT JOIN with NULL check."},{"question":"What are the requirements for set operations?","answer":"Same number of columns in all queries. Compatible data types. ORDER BY only at the end."},{"question":"What happens if column types mismatch?","answer":"PostgreSQL will error. Some databases attempt implicit type conversion. Always ensure consistent types."},{"question":"How do you ORDER BY with UNION?","answer":"Place ORDER BY at the end of the combined statement. Column names from the first query are used."},{"question":"Is UNION ALL faster than UNION?","answer":"Yes. UNION ALL does not perform deduplication sorting. Use UNION ALL when duplicates are not a concern."},{"question":"Can you use more than two queries in set operations?","answer":"Yes. Chain them: SELECT a UNION SELECT b UNION SELECT c."},{"question":"What is the alternative to INTERSECT?","answer":"SELECT DISTINCT a.* FROM table1 a JOIN table2 b ON a.id = b.id. INTERSECT is cleaner when comparing entire rows."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Set Operations (UNION, INTERSECT, EXCEPT)</text><rect x=\"10\" y=\"35\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"65\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">UNION</text><text x=\"65\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Combine dedup</text><rect x=\"10\" y=\"65\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"65\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">UNION ALL</text><text x=\"65\" y=\"93\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Combine all</text><rect x=\"10\" y=\"95\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"65\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">INTERSECT</text><text x=\"65\" y=\"123\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Common rows</text><rect x=\"10\" y=\"125\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"65\" y=\"141\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">EXCEPT</text><text x=\"65\" y=\"153\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">First only</text><line x1=\"120\" y1=\"48\" x2=\"150\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"78\" x2=\"150\" y2=\"78\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"108\" x2=\"150\" y2=\"108\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"138\" x2=\"150\" y2=\"138\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"35\" width=\"220\" height=\"125\" rx=\"4\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1\"/><text x=\"270\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Set Operations</text><text x=\"270\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Combine, intersect, and subtract query results like mathematical sets.</text><text x=\"240\" y=\"195\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Set Operations: UNION, INTERSECT, EXCEPT for combining query results.</text></svg>","codeExamples":[{"title":"UNION Example","useCase":"Combine employee and contractor names.","code":"SELECT name, email FROM employees\nUNION\nSELECT name, email FROM contractors\nORDER BY name;","description":"Unified directory of employees and contractors (no duplicates)."},{"title":"UNION ALL for Performance","useCase":"Combine monthly sales tables.","code":"SELECT 'Jan' AS month, * FROM sales_jan\nUNION ALL\nSELECT 'Feb', * FROM sales_feb\nUNION ALL\nSELECT 'Mar', * FROM sales_mar\nORDER BY amount DESC;","description":"UNION ALL is faster when combining disjoint data (no duplicates possible)."},{"title":"INTERSECT for Common Records","useCase":"Customers who bought from both stores.","code":"SELECT customer_id FROM store1_orders\nINTERSECT\nSELECT customer_id FROM store2_orders;","description":"Finds customers who have ordered from both store locations."},{"title":"EXCEPT to Find Missing Records","useCase":"Unordered products.","code":"SELECT id, name FROM products\nEXCEPT\nSELECT p.id, p.name FROM products p\nJOIN order_items oi ON p.id = oi.product_id;","description":"Finds products that have never been ordered."},{"title":"Multiple Set Operations","useCase":"Complex data comparison.","code":"SELECT user_id FROM active_users\nINTERSECT\nSELECT user_id FROM premium_users\nEXCEPT\nSELECT user_id FROM cancelled_users;","description":"Active premium users who have not cancelled their subscription."}],"mcqQuestions":[{"question":"Which set operation keeps duplicates?","options":["UNION","UNION ALL","INTERSECT","EXCEPT"],"answer":1,"explanation":"UNION ALL keeps all rows including duplicates."},{"question":"Which returns rows common to both queries?","options":["UNION","UNION ALL","INTERSECT","EXCEPT"],"answer":2,"explanation":"INTERSECT returns rows present in both result sets."},{"question":"What is the column requirement for set operations?","options":["Same names","Same number and compatible types","Same data","Same indexes"],"answer":1,"explanation":"All queries must return the same number of columns with compatible data types."},{"question":"Where does ORDER BY go?","options":["After first query","At end of combined statement","After each query","Before UNION"],"answer":1,"explanation":"ORDER BY applies to the final result, placed after the last query."},{"question":"Which is faster?","options":["UNION","UNION ALL","Same","Depends on indexes"],"answer":1,"explanation":"UNION ALL is faster because it skips the deduplication sort step."},{"question":"Which operator is called MINUS in Oracle?","options":["UNION","INTERSECT","EXCEPT","EXCLUDE"],"answer":2,"explanation":"EXCEPT is called MINUS in Oracle databases."}]};
TOPICS_DATA["sql"]["sql-indexes"] = {"id":"sql-indexes","title":"Indexes","difficulty":"intermediate","estimatedMinutes":25,"tldr":["Indexes are special data structures that improve query performance by allowing faster data retrieval.","B-tree indexes are the default and work well for equality, range, sorting, and join operations.","Composite indexes cover multiple columns. The order of columns in a composite index matters significantly.","Indexes speed up SELECT but slow down INSERT, UPDATE, DELETE. They consume disk space and memory."],"laymanDefinition":"An index is like the index at the back of a textbook. Without it, you have to flip through every page (full table scan). With it, you jump directly to the relevant pages. But the index takes up space and needs updating when new pages are added.","deepDive":[{"heading":"B-Tree Indexes","text":"Default index type. Balanced tree structure for O(log n) lookups. Supports: =, >, <, >=, <=, BETWEEN, IN, LIKE (prefix), ORDER BY, JOINs. Best for columns with high cardinality (many distinct values)."},{"heading":"Composite (Multi-Column) Indexes","text":"Index on (col1, col2, col3). The order of columns is critical. Works for queries filtering on col1, (col1, col2), or (col1, col2, col3). Does NOT work for queries only filtering on col2 or col3 (leading column rule)."},{"heading":"Unique and Primary Key Indexes","text":"PRIMARY KEY automatically creates a unique index. UNIQUE constraint creates a unique index. These enforce data integrity and provide fast lookup by the key column(s)."},{"heading":"Partial and Expression Indexes","text":"Partial: CREATE INDEX ON employees(salary) WHERE status = \\'active\\' — indexes only active employees. Expression: CREATE INDEX ON employees(LOWER(email)) — indexes the expression result for case-insensitive lookups."},{"heading":"Index Types Comparison","text":"B-tree: general purpose (default). Hash: equality lookups only (PostgreSQL). GiST: full-text search, geometric data. GIN: array/JSONB containment. BRIN: huge tables with natural ordering. SP-GiST: clustering data."}],"interviewAnswer":"Indexes are the primary tool for query performance. Understanding B-tree structure, composite index column order, and index-only scans is essential for database optimization. Measure before adding indexes — monitor actual query plans.","interviewQuestions":[{"question":"What is an index?","answer":"A data structure that speeds up data retrieval at the cost of slower writes and additional storage."},{"question":"What is the default index type?","answer":"B-tree (balanced tree). Provides O(log n) search, insert, and delete operations."},{"question":"What is a composite index?","answer":"An index on multiple columns. Column order matters: (a, b) is different from (b, a)."},{"question":"What is the leading column rule?","answer":"A query must filter on the first (leading) column of a composite index to use it effectively."},{"question":"What are the trade-offs of indexes?","answer":"Faster SELECT, slower INSERT/UPDATE/DELETE, more disk space and memory usage."},{"question":"What is an index-only scan?","answer":"When all needed columns are in the index, the database reads only the index, avoiding table access. Extremely fast."},{"question":"What is a unique index?","answer":"Ensures all values in the indexed column(s) are unique. Automatically created for PRIMARY KEY and UNIQUE constraints."},{"question":"What is a partial index?","answer":"An index on a subset of rows: CREATE INDEX ON table(column) WHERE condition. Smaller, faster for filtered queries."},{"question":"What is an expression index?","answer":"Indexes the result of an expression: CREATE INDEX ON employees(LOWER(last_name)). Enables fast WHERE LOWER(last_name) = \\'smith\\'."},{"question":"How many indexes is too many?","answer":"There is no fixed number. Each index adds write overhead. Monitor: if an index is never used by query plans, drop it."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Indexes</text><rect x=\"10\" y=\"35\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"65\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">B-Tree</text><text x=\"65\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Default index</text><rect x=\"10\" y=\"65\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"65\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Composite</text><text x=\"65\" y=\"93\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Multi-column</text><rect x=\"10\" y=\"95\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"65\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Unique</text><text x=\"65\" y=\"123\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">No duplicates</text><rect x=\"10\" y=\"125\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"65\" y=\"141\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Partial</text><text x=\"65\" y=\"153\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Conditional</text><rect x=\"10\" y=\"155\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1\"/><text x=\"65\" y=\"171\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Expression</text><text x=\"65\" y=\"183\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Function-based</text><line x1=\"120\" y1=\"48\" x2=\"150\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"78\" x2=\"150\" y2=\"78\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"108\" x2=\"150\" y2=\"108\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"138\" x2=\"150\" y2=\"138\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"168\" x2=\"150\" y2=\"168\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"35\" width=\"220\" height=\"155\" rx=\"4\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1\"/><text x=\"270\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Indexes</text><text x=\"270\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Data structures for fast query performance at the cost of slower writes.</text><text x=\"240\" y=\"220\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Indexes: B-tree, composite, partial, expression indexes for query optimization.</text></svg>","codeExamples":[{"title":"Creating Indexes","useCase":"Different index types.","code":"-- B-tree (default)\nCREATE INDEX idx_emp_salary ON employees(salary);\n\n-- Unique index\nCREATE UNIQUE INDEX idx_emp_email ON employees(email);\n\n-- Composite index\nCREATE INDEX idx_emp_dept_salary ON employees(dept_id, salary);","description":"Creates different types of indexes for various query patterns."},{"title":"Partial Index","useCase":"Index only active employees.","code":"CREATE INDEX idx_active_emp_salary\nON employees(salary)\nWHERE status = 'active';\n\n-- Query that benefits:\nSELECT * FROM employees\nWHERE status = 'active' AND salary > 80000;","description":"Smaller, more efficient index for queries filtering by active employees."},{"title":"Expression Index","useCase":"Case-insensitive search.","code":"CREATE INDEX idx_emp_lower_name\nON employees(LOWER(last_name));\n\n-- Fast query using the index:\nSELECT * FROM employees\nWHERE LOWER(last_name) = 'smith';","description":"Enables fast case-insensitive text lookups."},{"title":"Index-Only Scan","useCase":"Covering index pattern.","code":"-- Index includes all needed columns\nCREATE INDEX idx_emp_dept_name\nON employees(dept_id, name, salary);\n\n-- This query needs only the index:\nSELECT name, salary FROM employees\nWHERE dept_id = 5\nORDER BY name;","description":"Covering index avoids table access entirely for maximum speed."},{"title":"Checking Index Usage","useCase":"Find unused indexes.","code":"-- PostgreSQL: check index usage\nSELECT\n  schemaname, tablename, indexname,\n  idx_scan AS times_used\nFROM pg_stat_user_indexes\nORDER BY idx_scan ASC;","description":"Identifying unused indexes that should be dropped to reduce write overhead."}],"mcqQuestions":[{"question":"What is the default index type?","options":["Hash","B-tree","GiST","GIN"],"answer":1,"explanation":"B-tree is the default general-purpose index type."},{"question":"What does a composite index require?","options":["All columns used","Leading column filtered","Exact column match","Equal number of columns"],"answer":1,"explanation":"The leading column of the index must be used in the query WHERE clause."},{"question":"What trade-off do indexes have?","options":["Faster reads, slower writes","Faster writes, slower reads","More disk, faster writes","No trade-offs"],"answer":0,"explanation":"Indexes speed up SELECT but slow down INSERT/UPDATE/DELETE."},{"question":"What is an index-only scan?","options":["No index used","All data from index","Partial index scan","Full table scan"],"answer":1,"explanation":"Index-only scan reads only the index without touching the table."},{"question":"Which index type supports array containment?","options":["B-tree","Hash","GIN","GiST"],"answer":2,"explanation":"GIN indexes are optimized for array and JSONB containment queries."},{"question":"What is a partial index?","options":["Incomplete index","Index with WHERE","Index on part of column","Broken index"],"answer":1,"explanation":"A partial index is created with a WHERE clause, indexing only a subset of rows."}]};
TOPICS_DATA["sql"]["sql-views"] = {"id":"sql-views","title":"Views & Materialized Views","difficulty":"intermediate","estimatedMinutes":25,"tldr":["A view is a saved SQL query that acts like a virtual table. It does not store data itself — it runs the query each time.","Views simplify complex queries, provide security (hide columns/rows), and create a logical data layer.","Materialized views (PostgreSQL) store the query result physically, enabling fast reads but requiring refresh.","Updatable views allow INSERT/UPDATE/DELETE through the view under certain conditions."],"laymanDefinition":"A view is like a saved search filter on your email. Instead of typing the search every time, you save it as a Smart Folder. Every time you open it, it shows current results. A materialized view is like taking a screenshot of the results — instant to view but outdated until refreshed.","deepDive":[{"heading":"Creating Views","text":"CREATE VIEW view_name AS SELECT ... — creates a virtual table. Simple views can be updated. WITH CHECK OPTION prevents inserting rows that would not be visible through the view. Views can reference other views (view chaining)."},{"heading":"Updatable Views","text":"Simple views on a single table without aggregates, DISTINCT, GROUP BY, or set operations are automatically updatable. WITH LOCAL/CASCADED CHECK OPTION controls whether inserts/updates must satisfy the view WHERE condition."},{"heading":"Materialized Views (PostgreSQL)","text":"CREATE MATERIALIZED VIEW mv AS SELECT ... WITH DATA — stores query results physically. Faster reads than regular views. Must be refreshed: REFRESH MATERIALIZED VIEW mv. CONCURRENTLY option allows reads during refresh."},{"heading":"View Use Cases","text":"Security: expose only specific columns (hide salary column). Simplification: complex JOINs become simple FROM view. Consistency: standardize query patterns. Migration: views maintain backward compatibility when schemas change."},{"heading":"Performance Considerations","text":"Regular views have no performance benefit — they inline the query. Nested views can be slow (multiple layers of inlining). Materialized views are fast but stale. Indexes can be created on materialized views for maximum speed."}],"interviewAnswer":"Views are a powerful tool for encapsulation, security, and simplicity. Use regular views as query shortcuts and security layers. Use materialized views for expensive queries that don't need real-time data.","interviewQuestions":[{"question":"What is a view?","answer":"A saved SQL query that behaves like a virtual table. Does not store data — executes the query each time it is accessed."},{"question":"What is the difference between a view and a materialized view?","answer":"Regular view runs the query each time (no storage). Materialized view stores results physically (faster reads, stale data possible)."},{"question":"Can you insert data through a view?","answer":"Yes, for simple views on a single table without aggregates, DISTINCT, GROUP BY, or set operations."},{"question":"What does WITH CHECK OPTION do?","answer":"Prevents INSERT or UPDATE operations that would create rows not visible in the view."},{"question":"How do you refresh a materialized view?","answer":"REFRESH MATERIALIZED VIEW view_name. In PostgreSQL, CONCURRENTLY option allows reads during refresh."},{"question":"What are the security benefits of views?","answer":"Grant access to views without granting access to underlying tables. Expose only necessary columns (hide sensitive data)."},{"question":"Can views improve performance?","answer":"Regular views do not improve performance — they just inline the query. Materialized views can significantly improve read performance."},{"question":"Can a view reference another view?","answer":"Yes. Views can be chained. Be careful — deep nesting becomes hard to debug and can perform poorly."},{"question":"What happens when you DROP a table referenced by a view?","answer":"The view becomes invalid. Any query using it will error until the table is recreated or the view is dropped."},{"question":"Can you create indexes on a view?","answer":"On regular views: no (they are virtual). On materialized views: yes, indexes can be created for faster queries."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Views & Materialized Views</text><rect x=\"10\" y=\"35\" width=\"130\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"75\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">CREATE VIEW</text><text x=\"75\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Saved query</text><line x1=\"140\" y1=\"48\" x2=\"170\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"180\" y=\"35\" width=\"130\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"245\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Query View</text><text x=\"245\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Virtual table</text><line x1=\"180\" y1=\"60\" x2=\"180\" y2=\"80\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"10\" y=\"70\" width=\"130\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"75\" y=\"86\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">MATERIALIZED</text><text x=\"75\" y=\"98\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Stored result</text><line x1=\"140\" y1=\"83\" x2=\"170\" y2=\"83\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"180\" y=\"75\" width=\"130\" height=\"25\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"245\" y=\"91\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">REFRESH</text><text x=\"245\" y=\"103\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Update data</text><rect x=\"320\" y=\"35\" width=\"160\" height=\"90\" rx=\"4\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1\"/><text x=\"400\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Views vs Materialized</text><text x=\"400\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Query shortcut vs cached result. Trade-off: freshness vs speed.</text><text x=\"240\" y=\"200\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Views: Virtual tables for query simplification, security, and data abstraction.</text></svg>","codeExamples":[{"title":"Creating a Simple View","useCase":"Encapsulate complex query.","code":"CREATE VIEW employee_details AS\nSELECT e.name, e.salary, d.department_name\nFROM employees e\nJOIN departments d ON e.dept_id = d.id\nWHERE e.status = 'active';\n\n-- Use the view like a table:\nSELECT * FROM employee_details ORDER BY salary DESC;","description":"Creates a simplified view of active employees with department names."},{"title":"Updatable View with CHECK OPTION","useCase":"Controlled data entry.","code":"CREATE VIEW engineering_employees AS\nSELECT id, name, salary, dept_id\nFROM employees\nWHERE dept_id = 3\nWITH CHECK OPTION;\n\n-- This INSERT is allowed:\nINSERT INTO engineering_employees (name, salary, dept_id)\nVALUES ('John', 75000, 3);\n\n-- This INSERT is rejected by CHECK OPTION:\nINSERT INTO engineering_employees (name, salary, dept_id)\nVALUES ('Jane', 80000, 5); -- dept_id 5 not visible","description":"WITH CHECK OPTION ensures data integrity through the view."},{"title":"Materialized View","useCase":"Expensive query caching.","code":"CREATE MATERIALIZED VIEW monthly_sales_summary AS\nSELECT\n  DATE_TRUNC('month', order_date) AS month,\n  product_id,\n  COUNT(*) AS orders,\n  SUM(amount) AS total_sales\nFROM orders\nGROUP BY month, product_id\nWITH DATA;\n\n-- Refresh periodically:\nREFRESH MATERIALIZED VIEW monthly_sales_summary;","description":"Stores pre-computed monthly sales for instant dashboard queries."},{"title":"Indexing a Materialized View","useCase":"Maximize materialized view speed.","code":"CREATE INDEX idx_mv_month_product\nON monthly_sales_summary(month, product_id);\n\n-- Now this query runs extremely fast:\nSELECT * FROM monthly_sales_summary\nWHERE month = '2024-01-01' AND product_id = 5;","description":"Materialized views support indexes like regular tables."},{"title":"View for Security","useCase":"Hide sensitive columns.","code":"CREATE VIEW public_employee_info AS\nSELECT id, name, department, email\nFROM employees;\n\n-- Grant access without exposing salary:\nGRANT SELECT ON public_employee_info TO hr_readers;","description":"Exposes only non-sensitive employee information to specific roles."}],"mcqQuestions":[{"question":"What is a view?","options":["A stored result set","A saved query","A temporary table","A copy of data"],"answer":1,"explanation":"A view is a saved SQL query that acts like a virtual table."},{"question":"How does a materialized view differ?","options":["Faster queries","Stores data physically","Is automatically updated","Cannot be indexed"],"answer":1,"explanation":"Materialized views store query results as a physical table."},{"question":"What command refreshes a materialized view?","options":["UPDATE MATERIALIZED VIEW","REFRESH MATERIALIZED VIEW","REBUILD VIEW","RECALC VIEW"],"answer":1,"explanation":"REFRESH MATERIALIZED VIEW updates the stored data."},{"question":"What does WITH CHECK OPTION prevent?","options":["SQL injection","Invalid data entry","Duplicate rows","Slow queries"],"answer":1,"explanation":"WITH CHECK OPTION prevents entering data invisible through the view."},{"question":"Can you index a regular view?","options":["Yes","No","Only in PostgreSQL","Only materialized views"],"answer":1,"explanation":"Regular views are virtual — they cannot be indexed."},{"question":"What happens when underlying table is dropped?","options":["View still works","View becomes invalid","View auto-drops","Data is preserved"],"answer":1,"explanation":"The view becomes invalid when its underlying table is dropped."}]};
TOPICS_DATA["sql"]["sql-transactions"] = {"id":"sql-transactions","title":"Transactions & ACID","difficulty":"intermediate","estimatedMinutes":30,"tldr":["A transaction is a unit of work that is executed as a whole — all steps succeed or all are rolled back.","ACID: Atomicity (all or nothing), Consistency (valid state to valid state), Isolation (concurrent transactions don't interfere), Durability (committed data persists).","BEGIN / START TRANSACTION starts a transaction. COMMIT saves changes. ROLLBACK undoes changes since BEGIN.","PostgreSQL uses auto-commit by default. MySQL uses auto-commit by default. Both support explicit transaction control."],"laymanDefinition":"A transaction is like a bank transfer: money leaves account A and arrives at account B. If the system crashes after step 1, the entire transaction rolls back — account A gets the money back. Both steps succeed together or fail together.","deepDive":[{"heading":"Transaction Control Statements","text":"BEGIN / START TRANSACTION — begin. COMMIT — save all changes since BEGIN. ROLLBACK — undo all changes since BEGIN. SAVEPOINT sp_name — set a savepoint within a transaction. ROLLBACK TO SAVEPOINT — roll back to savepoint. RELEASE SAVEPOINT — discard savepoint."},{"heading":"Isolation Levels (ANSI Standard)","text":"READ UNCOMMITTED: dirty reads allowed. READ COMMITTED: no dirty reads (PostgreSQL default). REPEATABLE READ: no dirty/non-repeatable reads. SERIALIZABLE: fully isolated (highest level, lowest concurrency)."},{"heading":"PostgreSQL Isolation Behavior","text":"Default: READ COMMITTED. REPEATABLE READ prevents non-repeatable reads but allows phantom reads. SERIALIZABLE uses SSI (Serializable Snapshot Isolation). PostgreSQL does not support READ UNCOMMITTED (upgrades to READ COMMITTED)."},{"heading":"Lost Updates and Race Conditions","text":"Lost update: two transactions read same value, both modify it, last commit overwrites first. Solution: SELECT ... FOR UPDATE (row-level locking). Optimistic locking: version column with increment on update."},{"heading":"Deadlocks","text":"Transaction A locks row 1, needs row 2. Transaction B locks row 2, needs row 1. Neither can proceed. Database detects deadlocks and kills one transaction. Prevention: consistent lock ordering in application code."}],"interviewAnswer":"Transaction management is critical for data integrity in multi-user systems. Understanding isolation levels helps balance consistency and performance. Always use transactions for multi-step operations that must be atomic.","interviewQuestions":[{"question":"What is a transaction?","answer":"A unit of work that is atomic — all changes succeed (COMMIT) or all are undone (ROLLBACK)."},{"question":"What does ACID stand for?","answer":"Atomicity, Consistency, Isolation, Durability. The four properties of reliable database transactions."},{"question":"What does COMMIT do?","answer":"Saves all changes made in the current transaction to the database permanently."},{"question":"What does ROLLBACK do?","answer":"Undoes all changes made since the transaction began (or since a savepoint)."},{"question":"What is a dirty read?","answer":"Reading uncommitted data from another transaction. Prevented by READ COMMITTED isolation level."},{"question":"What is the default isolation level in PostgreSQL?","answer":"READ COMMITTED. Prevents dirty reads but allows non-repeatable reads."},{"question":"What is the highest isolation level?","answer":"SERIALIZABLE. Ensures complete isolation but has the lowest concurrency."},{"question":"What is SELECT ... FOR UPDATE?","answer":"Locks the selected rows for update, preventing other transactions from modifying them until the transaction ends."},{"question":"What is a deadlock?","answer":"Two or more transactions waiting for each other\\'s locks. The database detects and resolves by aborting one transaction."},{"question":"How do you prevent deadlocks?","answer":"Access resources in a consistent order across all transactions. Keep transactions short. Use appropriate isolation levels."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Transactions & ACID</text><rect x=\"10\" y=\"35\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"60\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">BEGIN</text><text x=\"60\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Start TX</text><line x1=\"110\" y1=\"48\" x2=\"140\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"150\" y=\"35\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"200\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">COMMIT</text><text x=\"200\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Save</text><rect x=\"150\" y=\"65\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"200\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">ROLLBACK</text><text x=\"200\" y=\"93\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Undo</text><rect x=\"150\" y=\"95\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"200\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">SAVEPOINT</text><text x=\"200\" y=\"123\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Partial undo</text><line x1=\"250\" y1=\"48\" x2=\"280\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"250\" y1=\"78\" x2=\"280\" y2=\"78\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"250\" y1=\"108\" x2=\"280\" y2=\"108\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"290\" y=\"35\" width=\"190\" height=\"100\" rx=\"4\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1\"/><text x=\"385\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">ACID Properties</text><text x=\"385\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Atomicity, Consistency, Isolation, Durability — reliable transactions.</text><text x=\"240\" y=\"175\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Transactions: ACID-compliant units of work for reliable data operations.</text></svg>","codeExamples":[{"title":"Basic Transaction","useCase":"Money transfer between accounts.","code":"BEGIN;\n\nUPDATE accounts SET balance = balance - 100 WHERE id = 1;\nUPDATE accounts SET balance = balance + 100 WHERE id = 2;\n\n-- If both succeed:\nCOMMIT;\n\n-- If anything fails:\nROLLBACK;","description":"Atomic transfer — both updates commit or both roll back."},{"title":"Savepoints","useCase":"Partial rollback within transaction.","code":"BEGIN;\nINSERT INTO audit_log (action) VALUES ('step 1');\nSAVEPOINT sp1;\nINSERT INTO audit_log (action) VALUES ('step 2');\n\n-- Oops, step 2 was wrong:\nROLLBACK TO SAVEPOINT sp1;\nINSERT INTO audit_log (action) VALUES ('step 2 corrected');\nCOMMIT;","description":"Savepoints allow rolling back part of a transaction without aborting entirely."},{"title":"Row-Level Locking","useCase":"Prevent race conditions.","code":"BEGIN;\n\n-- Lock the inventory row:\nSELECT quantity FROM products WHERE id = 10\nFOR UPDATE;\n\n-- Check and update safely:\nUPDATE products SET quantity = quantity - 1\nWHERE id = 10 AND quantity > 0;\n\nCOMMIT;","description":"SELECT FOR UPDATE prevents lost updates in concurrent environments."},{"title":"Isolation Level Demonstration","useCase":"Setting isolation level.","code":"-- Set isolation for current transaction:\nBEGIN;\nSET TRANSACTION ISOLATION LEVEL SERIALIZABLE;\n\nSELECT SUM(balance) FROM accounts WHERE user_id = 5;\nUPDATE accounts SET balance = balance * 1.05 WHERE user_id = 5;\n\nCOMMIT;","description":"SERIALIZABLE isolation ensures the SELECT result is consistent with the UPDATE."},{"title":"Deadlock Detection","useCase":"PostgreSQL deadlock handling.","code":"-- Session 1:\nBEGIN; UPDATE accounts SET balance = 0 WHERE id = 1;\n\n-- Session 2:\nBEGIN; UPDATE accounts SET balance = 0 WHERE id = 2;\n\n-- Session 1:\nUPDATE accounts SET balance = 100 WHERE id = 2; -- waits\n\n-- Session 2:\nUPDATE accounts SET balance = 100 WHERE id = 1;\n-- One session gets: ERROR: deadlock detected\n-- The other session succeeds","description":"PostgreSQL automatically detects and resolves deadlocks."}],"mcqQuestions":[{"question":"What does COMMIT do?","options":["Undoes changes","Saves changes permanently","Starts a transaction","Locks tables"],"answer":1,"explanation":"COMMIT permanently saves all changes in the current transaction."},{"question":"What does ACID stand for?","options":["Auto-Commit Isolation Durability","Atomicity Consistency Isolation Durability","Atomic Consistency Isolation Data","All Committed Integrity Data"],"answer":1,"explanation":"ACID: Atomicity, Consistency, Isolation, Durability."},{"question":"What is the default isolation in PostgreSQL?","options":["READ UNCOMMITTED","READ COMMITTED","REPEATABLE READ","SERIALIZABLE"],"answer":1,"explanation":"READ COMMITTED is the PostgreSQL default."},{"question":"What prevents dirty reads?","options":["READ UNCOMMITTED","READ COMMITTED","REPEATABLE READ","Both B and C"],"answer":3,"explanation":"READ COMMITTED and higher prevent dirty reads."},{"question":"What does SELECT FOR UPDATE do?","options":["Locks selected rows","Creates a view","Updates selected rows","Deletes old data"],"answer":0,"explanation":"SELECT FOR UPDATE locks rows for update, preventing concurrent modifications."},{"question":"What is a deadlock?","options":["Slow query","Two TX waiting on each other","Locked table","Out of memory"],"answer":1,"explanation":"Deadlock occurs when transactions wait for locks held by each other."}]};
TOPICS_DATA["sql"]["sql-string-functions"] = {"id":"sql-string-functions","title":"String Functions","difficulty":"beginner","estimatedMinutes":20,"tldr":["String functions manipulate text data. Common operations: concatenation, case conversion, trimming, extraction, and pattern replacement.","PostgreSQL and MySQL have different function names. PostgreSQL uses || for concatenation; MySQL uses CONCAT().","SUBSTRING extracts parts of strings. POSITION/CHARINDEX finds substring location. REPLACE substitutes text.","TRIM, LTRIM, RTRIM remove whitespace. UPPER/LOWER convert case. LENGTH returns character count."],"laymanDefinition":"String functions are like editing tools for text. CONCAT is copy-paste, SUBSTRING is cutting out a piece, UPPER/LOWER is changing case, TRIM is trimming ragged edges, REPLACE is find-and-replace.","deepDive":[{"heading":"Concatenation","text":"PostgreSQL: \\'Hello\\' || \\' \\' || \\'World\\' or CONCAT(\\'Hello\\', \\' \\', \\'World\\'). MySQL: CONCAT(\\'Hello\\', \\' \\', \\'World\\'). SQL Server: \\'Hello\\' + \\' \\' + \\'World\\'. CONCAT ignores NULLs; || and + propagate NULLs."},{"heading":"Case Conversion","text":"UPPER(string) — all uppercase. LOWER(string) — all lowercase. INITCAP(string) / PostgreSQL: capitalize first letter of each word. Case-insensitive comparison: WHERE LOWER(name) = LOWER(\\'John\\')."},{"heading":"Substring Extraction","text":"SUBSTRING(string FROM start FOR length) or SUBSTRING(string, pattern). LEFT(string, n) — first n chars. RIGHT(string, n) — last n chars. SPLIT_PART(string, delimiter, position) — splits and returns specific part."},{"heading":"Search and Replace","text":"POSITION(\\'sub\\' IN string) — find position (PostgreSQL). STRPOS(string, \\'sub\\') in PostgreSQL. CHARINDEX(\\'sub\\', string) in SQL Server. REPLACE(string, \\'old\\', \\'new\\') — substitution."},{"heading":"Trimming and Padding","text":"TRIM(string) — remove leading/trailing whitespace. TRIM(LEADING \\'0\\' FROM string) — specific char trim. LTRIM, RTRIM. LPAD(string, length, \\'fill\\') — pad left. RPAD — pad right."}],"interviewAnswer":"String functions are essential for data cleaning, formatting, and transformation in SQL queries. Knowing the database-specific function names is important for cross-platform compatibility.","interviewQuestions":[{"question":"How do you concatenate strings in PostgreSQL?","answer":"Use || operator: \\'Hello\\' || \\' \\' || \\'World\\'. Or CONCAT(\\'Hello\\', \\'World\\')."},{"question":"How do you convert text to uppercase?","answer":"UPPER(column). For lowercase: LOWER(column)."},{"question":"How do you extract part of a string?","answer":"SUBSTRING(column FROM start FOR length). Or LEFT(column, n), RIGHT(column, n)."},{"question":"How do you find the position of a substring?","answer":"POSITION(\\'sub\\' IN column) in PostgreSQL. STRPOS(column, \\'sub\\') also works."},{"question":"How do you replace text in a string?","answer":"REPLACE(column, \\'old\\', \\'new\\') replaces all occurrences."},{"question":"How do you remove whitespace?","answer":"TRIM(column) removes leading and trailing whitespace. LTRIM for leading, RTRIM for trailing."},{"question":"How do you pad a string?","answer":"LPAD(column, length, \\'fill_char\\') pads left. RPAD pads right."},{"question":"What function splits a string by delimiter?","answer":"SPLIT_PART(string, delimiter, position) in PostgreSQL. Returns the nth part."},{"question":"How do you get string length?","answer":"LENGTH(column) returns number of characters. OCTET_LENGTH returns bytes."},{"question":"How does CONCAT handle NULLs?","answer":"CONCAT ignores NULLs. || propagates NULLs (PostgreSQL). Use COALESCE to handle NULLs."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">String Functions</text><rect x=\"10\" y=\"35\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"60\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">CONCAT</text><text x=\"60\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Join strings</text><rect x=\"10\" y=\"65\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"60\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">UPPER/LOWER</text><text x=\"60\" y=\"93\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Case</text><rect x=\"10\" y=\"95\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"60\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">SUBSTRING</text><text x=\"60\" y=\"123\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Extract</text><rect x=\"10\" y=\"125\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"60\" y=\"141\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">REPLACE</text><text x=\"60\" y=\"153\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Substitute</text><rect x=\"10\" y=\"155\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1\"/><text x=\"60\" y=\"171\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">TRIM</text><text x=\"60\" y=\"183\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Clean</text><line x1=\"110\" y1=\"48\" x2=\"140\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"110\" y1=\"78\" x2=\"140\" y2=\"78\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"110\" y1=\"108\" x2=\"140\" y2=\"108\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"110\" y1=\"138\" x2=\"140\" y2=\"138\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"110\" y1=\"168\" x2=\"140\" y2=\"168\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"150\" y=\"35\" width=\"230\" height=\"155\" rx=\"4\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1\"/><text x=\"265\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">String Functions</text><text x=\"265\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Text manipulation: concatenation, extraction, search, replace, and cleaning.</text><text x=\"240\" y=\"220\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">String Functions: Manipulate text with CONCAT, SUBSTRING, REPLACE, TRIM, and more.</text></svg>","codeExamples":[{"title":"Basic String Operations","useCase":"Common text transformations.","code":"SELECT\n  UPPER(name) AS uppercase,\n  LOWER(email) AS lowercase,\n  LENGTH(name) AS name_length,\n  TRIM(prefix || ' ' || name) AS full_name\nFROM employees;","description":"Demonstrates case conversion, length, concatenation, and trimming."},{"title":"Substring and Position","useCase":"Extracting parts of strings.","code":"SELECT\n  email,\n  SUBSTRING(email FROM 1 FOR POSITION('@' IN email) - 1) AS username,\n  SUBSTRING(email FROM POSITION('@' IN email) + 1) AS domain\nFROM employees;","description":"Extracts username and domain from email addresses."},{"title":"REPLACE and SPLIT_PART","useCase":"Text cleaning and parsing.","code":"SELECT\n  phone,\n  REPLACE(REPLACE(REPLACE(phone, '-', ''), '(', ''), ')', '') AS clean_phone,\n  SPLIT_PART(full_name, ' ', 1) AS first_name,\n  SPLIT_PART(full_name, ' ', 2) AS last_name\nFROM contacts;","description":"Cleans phone numbers and splits full names."},{"title":"Padding for Formatting","useCase":"Fixed-width text output.","code":"SELECT\n  LPAD(id::TEXT, 5, '0') AS formatted_id,\n  RPAD(name, 20, '.') AS padded_name,\n  LPAD(salary::TEXT, 10, ' ') AS formatted_salary\nFROM employees\nORDER BY id;","description":"Creates fixed-width formatted output using LPAD and RPAD."},{"title":"String Aggregation","useCase":"Combine values into one string.","code":"SELECT\n  department,\n  STRING_AGG(name, ', ' ORDER BY name) AS employee_list,\n  COUNT(*) AS count\nFROM employees\nGROUP BY department;","description":"Aggregates employee names per department into comma-separated lists."}],"mcqQuestions":[{"question":"What does UPPER() do?","options":["Lowers case","Capitalizes all letters","Capitalizes first letter","Removes uppercase"],"answer":1,"explanation":"UPPER() converts text to uppercase."},{"question":"How do you concatenate in PostgreSQL?","options":["+","||","&","CONCATENATE"],"answer":1,"explanation":"PostgreSQL uses || for concatenation."},{"question":"What does TRIM() remove?","options":["Numbers","Whitespace","Punctuation","Vowels"],"answer":1,"explanation":"TRIM removes leading and trailing whitespace."},{"question":"Which function replaces text?","options":["CHANGE","REPLACE","MODIFY","ALTER"],"answer":1,"explanation":"REPLACE() substitutes occurrences of a substring."},{"question":"What does SPLIT_PART return?","options":["Split string count","Specific part by position","First word","Delimiter position"],"answer":1,"explanation":"SPLIT_PART returns the nth part of a split string."},{"question":"How does CONCAT handle NULL?","options":["Returns NULL","Ignores NULL","Errors","Converts to empty string"],"answer":1,"explanation":"CONCAT ignores NULL arguments; || propagates NULLs."}]};
TOPICS_DATA["sql"]["sql-date-functions"] = {"id":"sql-date-functions","title":"Date/Time Functions","difficulty":"beginner","estimatedMinutes":20,"tldr":["SQL date/time functions handle date arithmetic, extraction, formatting, and conversion.","CURRENT_DATE returns today's date. CURRENT_TIMESTAMP / NOW() returns current date and time.","EXTRACT or DATE_PART retrieves specific parts (year, month, day, hour) from dates/timestamps.","Date arithmetic: date + INTERVAL '1 day', AGE() for difference between dates, DATEDIFF() in MySQL."],"laymanDefinition":"Date/time functions are like a calendar and clock built into the database. You can add days, find the difference between dates, extract the month, or format dates for display.","deepDive":[{"heading":"Current Date/Time","text":"CURRENT_DATE — today. CURRENT_TIME — current time. CURRENT_TIMESTAMP — date + time. NOW() — same as CURRENT_TIMESTAMP. LOCALTIME / LOCALTIMESTAMP — without timezone. PostgreSQL supports all of these."},{"heading":"EXTRACT and DATE_PART","text":"EXTRACT(YEAR FROM timestamp) — get year. EXTRACT(MONTH FROM date). EXTRACT(DOW FROM date) — day of week (0=Sunday). PostgreSQL also supports DATE_PART(\\'year\\', timestamp). MySQL: EXTRACT and YEAR(), MONTH(), DAY() functions."},{"heading":"Date Arithmetic","text":"PostgreSQL: date + INTERVAL \\'1 day\\', date - INTERVAL \\'3 months\\', date + integer (adds days). AGE(date1, date2) returns interval. MySQL: DATE_ADD(date, INTERVAL 1 DAY), DATEDIFF(date1, date2)."},{"heading":"Formatting Dates","text":"TO_CHAR(timestamp, \\'YYYY-MM-DD\\') — format date as string (PostgreSQL). TO_CHAR(timestamp, \\'Mon DD, YYYY\\') — \\'Jan 15, 2024\\'. MySQL: DATE_FORMAT(date, \\'%Y-%m-%d\\')."},{"heading":"Date Truncation","text":"DATE_TRUNC(\\'month\\', timestamp) — truncates to first of month (PostgreSQL). DATE_TRUNC(\\'year\\', timestamp) — truncates to Jan 1. Essential for grouping by month/year: GROUP BY DATE_TRUNC(\\'month\\', order_date)."}],"interviewAnswer":"Date/time functions are essential for reporting, aging analysis, and time-based grouping. PostgreSQL has the most comprehensive date/time support of any SQL database.","interviewQuestions":[{"question":"How do you get today\\'s date?","answer":"CURRENT_DATE returns the current date. CURRENT_TIMESTAMP and NOW() return date and time."},{"question":"How do you extract the year from a date?","answer":"EXTRACT(YEAR FROM date_column). PostgreSQL also supports DATE_PART(\\'year\\', date_column)."},{"question":"How do you add days to a date?","answer":"PostgreSQL: date + INTERVAL \\'7 days\\' or date + 7. MySQL: DATE_ADD(date, INTERVAL 7 DAY)."},{"question":"How do you find the difference between two dates?","answer":"PostgreSQL: AGE(end_date, start_date) returns interval. MySQL: DATEDIFF(end_date, start_date) returns days."},{"question":"How do you format a date as a string?","answer":"PostgreSQL: TO_CHAR(date, \\'YYYY-MM-DD\\'). MySQL: DATE_FORMAT(date, \\'%Y-%m-%d\\')."},{"question":"What does DATE_TRUNC do?","answer":"Truncates a timestamp to a specified precision. DATE_TRUNC(\\'month\\', date) returns first day of month at midnight."},{"question":"What is the difference between TIMESTAMP and TIMESTAMPTZ?","answer":"TIMESTAMP stores date/time without timezone. TIMESTAMPTZ (TIMESTAMP WITH TIME ZONE) stores with timezone and converts to UTC."},{"question":"How do you get the day of week?","answer":"EXTRACT(DOW FROM date) — 0=Sunday, 6=Saturday (PostgreSQL). MySQL: DAYOFWEEK(date) — 1=Sunday."},{"question":"How do you get the last day of the month?","answer":"PostgreSQL: (DATE_TRUNC(\\'month\\', date) + INTERVAL \\'1 month\\' - INTERVAL \\'1 day\\')::DATE."},{"question":"Can you index date columns?","answer":"Yes. B-tree indexes work well for date columns, especially for range queries and ORDER BY."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Date/Time Functions</text><rect x=\"10\" y=\"35\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"60\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">NOW()</text><text x=\"60\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Current time</text><rect x=\"10\" y=\"65\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"60\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">EXTRACT</text><text x=\"60\" y=\"93\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Get part</text><rect x=\"10\" y=\"95\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"60\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">+ INTERVAL</text><text x=\"60\" y=\"123\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Add time</text><rect x=\"10\" y=\"125\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"60\" y=\"141\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">AGE()</text><text x=\"60\" y=\"153\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Difference</text><rect x=\"10\" y=\"155\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1\"/><text x=\"60\" y=\"171\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">TO_CHAR</text><text x=\"60\" y=\"183\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Format</text><line x1=\"110\" y1=\"48\" x2=\"140\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"110\" y1=\"78\" x2=\"140\" y2=\"78\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"110\" y1=\"108\" x2=\"140\" y2=\"108\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"110\" y1=\"138\" x2=\"140\" y2=\"138\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"110\" y1=\"168\" x2=\"140\" y2=\"168\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"150\" y=\"35\" width=\"230\" height=\"155\" rx=\"4\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1\"/><text x=\"265\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Date/Time Functions</text><text x=\"265\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Manipulate, extract, format, and compute with dates and timestamps.</text><text x=\"240\" y=\"220\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Date/Time Functions: Date arithmetic, extraction, formatting, and timezone handling.</text></svg>","codeExamples":[{"title":"Current Timestamp Variations","useCase":"Getting current date/time.","code":"SELECT\n  CURRENT_DATE AS today,\n  CURRENT_TIME AS time_now,\n  CURRENT_TIMESTAMP AS ts_now,\n  NOW() AS now,\n  LOCALTIMESTAMP AS local_ts;","description":"Shows various ways to get current date and time in PostgreSQL."},{"title":"EXTRACT for Reporting","useCase":"Analyze orders by time parts.","code":"SELECT\n  EXTRACT(YEAR FROM order_date) AS year,\n  EXTRACT(MONTH FROM order_date) AS month,\n  EXTRACT(DOW FROM order_date) AS day_of_week,\n  COUNT(*) AS orders\nFROM orders\nGROUP BY year, month, day_of_week\nORDER BY year, month;","description":"Breaks down orders by year, month, and day of week."},{"title":"Date Arithmetic","useCase":"Find pending actions.","code":"SELECT\n  name, last_login,\n  AGE(CURRENT_DATE, last_login) AS time_since_login,\n  last_login + INTERVAL '90 days' AS expiry_date\nFROM users\nWHERE last_login < CURRENT_DATE - INTERVAL '30 days'\nORDER BY last_login;","description":"Finds inactive users and calculates their account expiry."},{"title":"DATE_TRUNC for Grouping","useCase":"Monthly sales aggregation.","code":"SELECT\n  DATE_TRUNC('month', order_date) AS month,\n  COUNT(*) AS orders,\n  SUM(amount) AS total_sales\nFROM orders\nWHERE order_date >= '2024-01-01'\nGROUP BY DATE_TRUNC('month', order_date)\nORDER BY month;","description":"Groups orders by month using date truncation."},{"title":"TO_CHAR Formatting","useCase":"User-friendly date display.","code":"SELECT\n  TO_CHAR(order_date, 'Mon DD, YYYY') AS formatted_date,\n  TO_CHAR(order_date, 'Day') AS weekday,\n  TO_CHAR(order_date, 'HH12:MI AM') AS time_of_day\nFROM orders\nLIMIT 5;","description":"Formats dates and times for display in reports."}],"mcqQuestions":[{"question":"Which function returns current date and time?","options":["CURRENT_DATE","CURRENT_TIMESTAMP","CURRENT_TIME","TODAY()"],"answer":1,"explanation":"CURRENT_TIMESTAMP returns current date and time."},{"question":"What does EXTRACT(YEAR FROM date) do?","options":["Adds a year","Gets the year part","Removes year","Converts to year"],"answer":1,"explanation":"EXTRACT retrieves a specific date part."},{"question":"How do you add 7 days to a date in PostgreSQL?","options":["date + 7","date + INTERVAL '7 days'","DATE_ADD(date, 7)","Both A and B"],"answer":3,"explanation":"PostgreSQL accepts date + integer (days) or date + INTERVAL."},{"question":"What does AGE() return?","options":["Years only","An interval","Days only","A timestamp"],"answer":1,"explanation":"AGE() returns the interval between two dates."},{"question":"What does DATE_TRUNC(\\'month\\', ts) do?","options":["Removes month","First day of month","Last day of month","Middle of month"],"answer":1,"explanation":"DATE_TRUNC truncates to the specified precision — first day of month."},{"question":"Which function formats dates?","options":["FORMAT_DATE","TO_CHAR","DATE_FORMAT","Both B and C"],"answer":3,"explanation":"TO_CHAR (PostgreSQL) and DATE_FORMAT (MySQL) format dates."}]};
TOPICS_DATA["sql"]["sql-conditional-expressions"] = {"id":"sql-conditional-expressions","title":"Conditional Expressions","difficulty":"intermediate","estimatedMinutes":20,"tldr":["Conditional expressions enable if-then-else logic within SQL queries without procedural code.","CASE is the most versatile conditional expression with two syntaxes: simple CASE (equality) and searched CASE (arbitrary conditions).","COALESCE returns the first non-NULL value from a list. NULLIF returns NULL if two values are equal.","GREATEST and LEAST return the maximum/minimum value from a list of expressions."],"laymanDefinition":"CASE is like a switch statement in programming — it lets you transform values based on conditions. COALESCE is a safety net that catches NULLs and replaces them with defaults. NULLIF is the opposite — it creates NULLs intentionally.","deepDive":[{"heading":"CASE Syntax Variants","text":"Simple CASE: CASE column WHEN value1 THEN result1 WHEN value2 THEN result2 ELSE default END. Searched CASE: CASE WHEN condition1 THEN result1 WHEN condition2 THEN result2 ELSE default END. Searched allows any boolean expression, ranges, and subqueries."},{"heading":"COALESCE and IFNULL","text":"COALESCE(val1, val2, val3, ...) — returns first non-NULL. Takes multiple arguments, any data type. IFNULL(val1, val2) — two-argument version (MySQL). COALESCE is standard SQL."},{"heading":"NULLIF","text":"NULLIF(val1, val2) — returns NULL if val1 = val2, otherwise returns val1. Useful for preventing division by zero: NULLIF(denominator, 0). Also used to convert specific values to NULL for aggregate functions."},{"heading":"GREATEST and LEAST","text":"GREATEST(val1, val2, val3) — returns the largest value. LEAST returns the smallest. Works with numbers, strings, dates. NULLs cause NULL return (use COALESCE within)."},{"heading":"CASE in Different Clauses","text":"CASE in SELECT transforms output. CASE in WHERE creates conditional filters. CASE in ORDER BY customizes sort order. CASE in GROUP BY creates conditional groupings. CASE in UPDATE provides conditional values."}],"interviewAnswer":"Conditional expressions bring programming logic to SQL. CASE is the workhorse, COALESCE handles NULLs elegantly, and NULLIF prevents division errors. Master these to write more flexible and robust queries.","interviewQuestions":[{"question":"What is the searched CASE expression?","answer":"CASE WHEN condition THEN result ... END. Allows any boolean conditions, not just equality."},{"question":"What is the difference between simple and searched CASE?","answer":"Simple CASE checks equality against a single expression. Searched CASE evaluates independent boolean conditions."},{"question":"What does COALESCE do?","answer":"Returns the first non-NULL argument. Takes 2+ arguments of compatible types."},{"question":"What does NULLIF do?","answer":"Returns NULL if both arguments are equal. Otherwise returns the first argument."},{"question":"How do you prevent division by zero?","answer":"Use: value / NULLIF(denominator, 0). Returns NULL instead of error when denominator is 0."},{"question":"What does GREATEST do?","answer":"Returns the maximum value from a list of expressions. Opposite of LEAST."},{"question":"Can CASE be used in WHERE?","answer":"Yes. WHERE CASE WHEN condition THEN true ELSE false END. But often a simpler boolean expression works better."},{"question":"Can CASE be used in ORDER BY?","answer":"Yes. ORDER BY CASE WHEN department = \\'Engineering\\' THEN 1 ELSE 2 END — custom sort order."},{"question":"Can CASE be used in GROUP BY?","answer":"Yes. GROUP BY CASE WHEN salary > 100000 THEN \\'High\\' WHEN salary > 50000 THEN \\'Medium\\' ELSE \\'Low\\' END."},{"question":"What happens if no ELSE in CASE?","answer":"The CASE expression returns NULL when no condition matches. Always include ELSE for safety."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Conditional Expressions</text><rect x=\"10\" y=\"35\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"60\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">CASE</text><text x=\"60\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">If-then-else</text><rect x=\"10\" y=\"65\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"60\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">COALESCE</text><text x=\"60\" y=\"93\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">First non-NULL</text><rect x=\"10\" y=\"95\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"60\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">NULLIF</text><text x=\"60\" y=\"123\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Create NULL</text><rect x=\"10\" y=\"125\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"60\" y=\"141\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">GREATEST</text><text x=\"60\" y=\"153\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Max value</text><rect x=\"10\" y=\"155\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1\"/><text x=\"60\" y=\"171\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">LEAST</text><text x=\"60\" y=\"183\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Min value</text><line x1=\"110\" y1=\"48\" x2=\"140\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"110\" y1=\"78\" x2=\"140\" y2=\"78\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"110\" y1=\"108\" x2=\"140\" y2=\"108\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"110\" y1=\"138\" x2=\"140\" y2=\"138\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"110\" y1=\"168\" x2=\"140\" y2=\"168\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"150\" y=\"35\" width=\"230\" height=\"155\" rx=\"4\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1\"/><text x=\"265\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Conditional Expressions</text><text x=\"265\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">CASE, COALESCE, NULLIF — programming logic and NULL handling in SQL.</text><text x=\"240\" y=\"220\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Conditional Expressions: CASE, COALESCE, NULLIF for flexible SQL logic.</text></svg>","codeExamples":[{"title":"Searched CASE for Bucketing","useCase":"Salary categories.","code":"SELECT\n  name, salary,\n  CASE\n    WHEN salary > 100000 THEN 'High'\n    WHEN salary > 60000 THEN 'Medium'\n    WHEN salary > 0 THEN 'Low'\n    ELSE 'Unknown'\n  END AS salary_bracket\nFROM employees\nORDER BY salary DESC;","description":"Categorizes salaries into brackets using searched CASE."},{"title":"COALESCE for Default Values","useCase":"Replace NULL with defaults.","code":"SELECT\n  name,\n  COALESCE(phone, 'No phone on file') AS phone,\n  COALESCE(bonus, 0) AS bonus,\n  COALESCE(manager_id, 0) AS manager_id\nFROM employees;","description":"COALESCE provides fallback values for NULL columns."},{"title":"NULLIF to Prevent Division by Zero","useCase":"Safe percentage calculation.","code":"SELECT\n  department,\n  COUNT(*) AS total,\n  SUM(CASE WHEN gender = 'F' THEN 1 ELSE 0 END) AS female,\n  ROUND(SUM(CASE WHEN gender = 'F' THEN 1 ELSE 0 END)\n    / NULLIF(COUNT(*), 0)::DECIMAL * 100, 2) AS female_pct\nFROM employees\nGROUP BY department;","description":"NULLIF prevents division by zero, returning NULL instead of an error."},{"title":"CASE in ORDER BY","useCase":"Custom sort order for status.","code":"SELECT name, status, created_at\nFROM tasks\nORDER BY\n  CASE status\n    WHEN 'critical' THEN 1\n    WHEN 'high' THEN 2\n    WHEN 'medium' THEN 3\n    WHEN 'low' THEN 4\n    ELSE 5\n  END,\n  created_at DESC;","description":"Custom sorting logic using CASE in ORDER BY clause."},{"title":"GREATEST and LEAST","useCase":"Find extremes across columns.","code":"SELECT\n  student_name,\n  GREATEST(math, science, english) AS best_score,\n  LEAST(math, science, english) AS worst_score\nFROM exam_scores;","description":"GREATEST and LEAST find max/min across multiple columns per row."}],"mcqQuestions":[{"question":"Which expression returns first non-NULL?","options":["IFNULL","COALESCE","NULLIF","CASE"],"answer":1,"explanation":"COALESCE returns the first non-NULL argument."},{"question":"When does NULLIF return NULL?","options":["Always","When arguments are equal","When first is NULL","When second is NULL"],"answer":1,"explanation":"NULLIF returns NULL when both arguments are equal."},{"question":"What is the ELSE value if omitted in CASE?","options":["0","NULL","False","Empty string"],"answer":1,"explanation":"CASE without ELSE returns NULL when no condition matches."},{"question":"Can CASE be used in ORDER BY?","options":["Yes","No","Only in SELECT","Only in WHERE"],"answer":0,"explanation":"CASE can be used in SELECT, WHERE, ORDER BY, GROUP BY, and HAVING."},{"question":"What does GREATEST(1, 5, 3) return?","options":["1","3","5","9"],"answer":2,"explanation":"GREATEST returns the maximum value from the list (5)."},{"question":"How do you safely divide in SQL?","options":["value / 0","value / COALESCE(denom, 1)","value / NULLIF(denom, 0)","DIVIDE(value, denom)"],"answer":2,"explanation":"NULLIF(denom, 0) returns NULL when denom is 0, preventing division by zero errors."}]};
TOPICS_DATA["sql"]["sql-stored-procedures"] = {"id":"sql-stored-procedures","title":"Stored Procedures & Functions","difficulty":"advanced","estimatedMinutes":30,"tldr":["Stored procedures and functions are database-side programs written in SQL or procedural languages (PL/pgSQL).","Stored procedures can perform transactions and do not return values. Functions must return a value and are used in SQL expressions.","PostgreSQL uses CREATE FUNCTION for both functions and procedures (CREATE PROCEDURE added in PG 11).","Benefits: performance (reduced network), security (encapsulation), reusability (write once, use everywhere)."],"laymanDefinition":"A stored procedure is like a macro or script saved in the database. Instead of sending five separate SQL statements, you send one CALL and the database does all five steps internally. It reduces network traffic and centralizes logic.","deepDive":[{"heading":"Functions vs Procedures","text":"Functions: CREATE FUNCTION, must return a value, used in SELECT/WHERE/expressions, cannot use transactions. Procedures: CREATE PROCEDURE, may return multiple result sets, called with CALL, can use transactions (PostgreSQL 11+)."},{"heading":"PL/pgSQL Language","text":"PostgreSQL\\'s procedural language. Syntax: $$ DECLARE ... BEGIN ... END; $$ LANGUAGE plpgsql. Supports variables, IF/ELSE, LOOP, WHILE, FOR, EXCEPTION handling, cursors, and dynamic SQL."},{"heading":"Parameters","text":"IN — input only (default). OUT — output only, like a return value. INOUT — both input and output. Parameters can have DEFAULT values. Named parameter syntax: func_name(param => value)."},{"heading":"Exception Handling","text":"BEGIN ... EXCEPTION WHEN condition THEN ... END; — catch errors within a block. RAISE statement for custom error messages. GET DIAGNOSTICS for error details. Prevents transaction abortion from non-critical errors."},{"heading":"Security: SQL Injection","text":"Use parameterized queries (EXECUTE ... USING) instead of string concatenation in dynamic SQL. Set SECURITY DEFINER or SECURITY INVOKER to control execution privileges. Always validate input."}],"interviewAnswer":"Stored procedures and functions are powerful for encapsulating business logic in the database. Use them for complex multi-step operations, data validation, and scheduled tasks. PostgreSQL's PL/pgSQL is the most mature procedural extension.","interviewQuestions":[{"question":"What is the difference between a function and a procedure?","answer":"Functions return a value and can be used in SQL expressions. Procedures can use transactions and are called with CALL."},{"question":"What is PL/pgSQL?","answer":"PostgreSQL\\'s procedural language for writing functions and procedures. Supports variables, control structures, and error handling."},{"question":"How do you return a value from a function?","answer":"Use RETURN value; The function declares RETURNS type in its signature."},{"question":"Can stored procedures use transactions?","answer":"Yes, in PostgreSQL 11+ with CREATE PROCEDURE. Procedures can use COMMIT and ROLLBACK. Functions cannot."},{"question":"What are OUT parameters?","answer":"Output parameters that act like additional return values. Defined in the parameter list with OUT keyword."},{"question":"How do you handle errors in PL/pgSQL?","answer":"Using BEGIN ... EXCEPTION WHEN ... THEN ... END blocks within the function body."},{"question":"What is SECURITY DEFINER?","answer":"The function runs with the privileges of its owner, not the caller. Used for privilege escalation."},{"question":"What is dynamic SQL in PostgreSQL?","answer":"EXECUTE \\'SELECT * FROM \\' || table_name — constructing and running SQL strings. Use EXECUTE ... USING for parameterized dynamic SQL."},{"question":"How do you prevent SQL injection in dynamic SQL?","answer":"Always use EXECUTE ... USING for parameters. Never concatenate user input into SQL strings."},{"question":"Can you call a function from a SELECT?","answer":"Yes. SELECT function_name(args); Functions are first-class SQL expressions."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Stored Procedures & Functions</text><rect x=\"10\" y=\"35\" width=\"120\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"70\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">CREATE FUNCTION</text><text x=\"70\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Returns value</text><rect x=\"10\" y=\"65\" width=\"120\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"70\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">CREATE PROCEDURE</text><text x=\"70\" y=\"93\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">CALL only</text><rect x=\"10\" y=\"95\" width=\"120\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"70\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">PL/pgSQL</text><text x=\"70\" y=\"123\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Procedural lang</text><rect x=\"10\" y=\"125\" width=\"120\" height=\"25\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"70\" y=\"141\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">EXCEPTION</text><text x=\"70\" y=\"153\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Error handling</text><line x1=\"130\" y1=\"48\" x2=\"160\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"130\" y1=\"78\" x2=\"160\" y2=\"78\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"130\" y1=\"108\" x2=\"160\" y2=\"108\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"130\" y1=\"138\" x2=\"160\" y2=\"138\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"170\" y=\"35\" width=\"210\" height=\"130\" rx=\"4\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1\"/><text x=\"275\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Stored Programs</text><text x=\"275\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Database-side logic: functions, procedures, and PL/pgSQL programming.</text><text x=\"240\" y=\"195\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Stored Procedures: Server-side logic for encapsulation, performance, and reusability.</text></svg>","codeExamples":[{"title":"Creating a Function","useCase":"Calculate annual salary.","code":"CREATE FUNCTION get_annual_salary(emp_id INT)\nRETURNS DECIMAL AS $$\nDECLARE\n  sal DECIMAL;\nBEGIN\n  SELECT salary * 12 INTO sal FROM employees WHERE id = emp_id;\n  RETURN sal;\nEND;\n$$ LANGUAGE plpgsql;\n\n-- Usage:\nSELECT get_annual_salary(5);","description":"Creates a function that calculates and returns annual salary."},{"title":"Stored Procedure with Transaction","useCase":"Transfer between accounts.","code":"CREATE PROCEDURE transfer_funds(\n  from_id INT, to_id INT, amount DECIMAL\n) LANGUAGE plpgsql AS $$\nBEGIN\n  COMMIT; -- end any existing transaction\n  BEGIN; -- start new transaction\n  UPDATE accounts SET balance = balance - amount WHERE id = from_id;\n  UPDATE accounts SET balance = balance + amount WHERE id = to_id;\n  COMMIT;\nEXCEPTION\n  WHEN OTHERS THEN\n    ROLLBACK;\n    RAISE NOTICE 'Transfer failed: %', SQLERRM;\nEND;\n$$;\n\nCALL transfer_funds(1, 2, 100.00);","description":"Procedure with transaction management and error handling."},{"title":"Function with OUT Parameters","useCase":"Return multiple values.","code":"CREATE FUNCTION get_emp_stats(dept_id INT,\n  OUT avg_sal DECIMAL,\n  OUT max_sal DECIMAL,\n  OUT emp_count INT\n) LANGUAGE plpgsql AS $$\nBEGIN\n  SELECT AVG(salary), MAX(salary), COUNT(*)\n  INTO avg_sal, max_sal, emp_count\n  FROM employees WHERE dept_id = dept_id;\nEND;\n$$;\n\nSELECT * FROM get_emp_stats(3);","description":"OUT parameters return multiple values from a single function call."},{"title":"Trigger Function Example","useCase":"Audit log on update.","code":"CREATE FUNCTION log_employee_changes()\nRETURNS TRIGGER AS $$\nBEGIN\n  INSERT INTO audit_log(table_name, record_id, old_data, new_data)\n  VALUES ('employees', OLD.id,\n    ROW(OLD.name, OLD.salary)::TEXT,\n    ROW(NEW.name, NEW.salary)::TEXT);\n  RETURN NEW;\nEND;\n$$ LANGUAGE plpgsql;","description":"Trigger function that logs changes to an audit table."},{"title":"Dynamic SQL with EXECUTE","useCase":"Safe dynamic table access.","code":"CREATE FUNCTION get_count(tbl TEXT, col TEXT, val TEXT)\nRETURNS INT LANGUAGE plpgsql AS $$\nDECLARE\n  cnt INT;\nBEGIN\n  EXECUTE format(\n    'SELECT COUNT(*) FROM %I WHERE %I = %L',\n    tbl, col, val\n  ) INTO cnt;\n  RETURN cnt;\nEND;\n$$;\n\nSELECT get_count('employees', 'department', 'Engineering');","description":"Dynamic SQL using EXECUTE with format() for safe identifier quoting."}],"mcqQuestions":[{"question":"Which can use transactions?","options":["Functions","Procedures","Both","Neither"],"answer":1,"explanation":"Procedures (PostgreSQL 11+) can use transactions. Functions cannot."},{"question":"What language is native to PostgreSQL for procedures?","options":["PL/SQL","PL/pgSQL","T-SQL","PL/SQL Plus"],"answer":1,"explanation":"PL/pgSQL is PostgreSQL\\'s procedural language."},{"question":"What keyword returns a value from a function?","options":["RESULT","RETURN","OUTPUT","SEND"],"answer":1,"explanation":"RETURN sends the value back from a function."},{"question":"What does SECURITY DEFINER do?","options":["Runs as caller","Runs as owner","Runs as DBA","Runs as PUBLIC"],"answer":1,"explanation":"SECURITY DEFINER runs the function with the owner\\'s privileges."},{"question":"How do you call a procedure?","options":["SELECT","CALL","EXEC","RUN"],"answer":1,"explanation":"CALL invokes a stored procedure."},{"question":"What prevents SQL injection in dynamic SQL?","options":["EXECUTE","EXECUTE ... USING","format()","Both B and C"],"answer":3,"explanation":"EXECUTE ... USING and format() with %I prevent SQL injection."}]};
TOPICS_DATA["sql"]["sql-triggers"] = {"id":"sql-triggers","title":"Triggers","difficulty":"advanced","estimatedMinutes":25,"tldr":["A trigger is a database function that automatically executes when a specified event occurs on a table.","Trigger events: INSERT, UPDATE, DELETE, or TRUNCATE. Timing: BEFORE, AFTER, or INSTEAD OF.","Statement-level triggers fire once per SQL statement. Row-level triggers fire once per affected row.","Triggers enforce business rules, maintain audit logs, update summary tables, and cascade changes."],"laymanDefinition":"A trigger is like an automatic action that happens whenever something changes. Like setting up an automatic email notification when a new user signs up. You define the trigger once, and it runs every time the event occurs without manual intervention.","deepDive":[{"heading":"Trigger Timing","text":"BEFORE trigger — runs before the operation. Can modify the new row or prevent the operation. AFTER trigger — runs after the operation. Cannot modify the row but can access OLD and NEW data. INSTEAD OF — replaces the operation (views)."},{"heading":"Row vs Statement Level","text":"FOR EACH ROW — fires once per affected row. Has access to OLD and NEW row data. FOR EACH STATEMENT — fires once per SQL statement regardless of rows affected. No per-row data access. Row-level is more common."},{"heading":"OLD and NEW References","text":"OLD — the row before the operation (UPDATE/DELETE). NEW — the row after the operation (INSERT/UPDATE). OLD and NEW are RECORD types. Access fields: OLD.salary, NEW.name."},{"heading":"Trigger Functions","text":"Must return TRIGGER type. RETURN NEW — proceed with operation. RETURN NULL — skip operation (for BEFORE triggers). RETURN OLD — for DELETE. Created with CREATE FUNCTION ... RETURNS TRIGGER, then attached with CREATE TRIGGER."},{"heading":"Triggers and Performance","text":"Row-level triggers on large operations can be slow. Each row execution adds overhead. Minimize trigger logic. Use statement-level triggers when per-row data is not needed. Avoid triggers that query the same table (recursion risk)."}],"interviewAnswer":"Triggers are powerful for maintaining data integrity automatically. However, they can make debugging difficult since the execution is implicit. Use triggers sparingly and document them thoroughly. Prefer application-level logic when possible.","interviewQuestions":[{"question":"What is a trigger?","answer":"A database function that automatically executes on INSERT, UPDATE, DELETE, or TRUNCATE events."},{"question":"What are the trigger timing options?","answer":"BEFORE (before operation), AFTER (after operation), INSTEAD OF (replaces operation for views)."},{"question":"What is the difference between row and statement triggers?","answer":"Row-level (FOR EACH ROW) fires per row, has OLD/NEW access. Statement-level fires once per statement."},{"question":"What does OLD represent in a trigger?","answer":"The row data before the operation. Available in UPDATE and DELETE triggers."},{"question":"What does NEW represent?","answer":"The row data after the operation. Available in INSERT and UPDATE triggers."},{"question":"Can a trigger prevent an operation?","answer":"Yes. In a BEFORE trigger, RETURN NULL aborts the operation. Raise an exception to produce an error."},{"question":"Can triggers be recursive?","answer":"Yes. A trigger that modifies the same table can fire itself again. PostgreSQL limits recursion depth (max_stack_depth)."},{"question":"What is an INSTEAD OF trigger?","answer":"Replaces the triggering operation entirely. Mainly used on views to make them updatable."},{"question":"How do you view triggers?","answer":"PostgreSQL: SELECT * FROM pg_triggers; or \\dy in psql."},{"question":"Can you disable a trigger temporarily?","answer":"Yes. ALTER TABLE table_name DISABLE TRIGGER trigger_name; For all: ALTER TABLE table_name DISABLE TRIGGER ALL;"}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Triggers</text><rect x=\"10\" y=\"35\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"60\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">BEFORE</text><text x=\"60\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Pre-check</text><rect x=\"10\" y=\"65\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"60\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">AFTER</text><text x=\"60\" y=\"93\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Post-action</text><rect x=\"10\" y=\"95\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"60\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">INSTEAD OF</text><text x=\"60\" y=\"123\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">View modify</text><rect x=\"170\" y=\"35\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"220\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">FOR EACH ROW</text><text x=\"220\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Per row</text><rect x=\"170\" y=\"65\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1\"/><text x=\"220\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">FOR EACH STMT</text><text x=\"220\" y=\"93\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Per stmt</text><rect x=\"170\" y=\"95\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#6610f2\" stroke=\"#6610f2\" stroke-width=\"1\"/><text x=\"220\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">OLD / NEW</text><text x=\"220\" y=\"123\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Row data</text><line x1=\"100\" y1=\"48\" x2=\"130\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"100\" y1=\"78\" x2=\"130\" y2=\"78\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"100\" y1=\"108\" x2=\"130\" y2=\"108\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"280\" y=\"35\" width=\"200\" height=\"95\" rx=\"4\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1\"/><text x=\"380\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Triggers</text><text x=\"380\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Automatic execution on table events. Use for validation, audit, and cascading.</text><text x=\"240\" y=\"170\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Triggers: Automatic functions executed on INSERT, UPDATE, DELETE events.</text></svg>","codeExamples":[{"title":"Before Insert Validation","useCase":"Ensure data quality.","code":"CREATE FUNCTION validate_employee()\nRETURNS TRIGGER AS $$\nBEGIN\n  IF NEW.salary < 0 THEN\n    RAISE EXCEPTION 'Salary cannot be negative: %', NEW.salary;\n  END IF;\n  IF NEW.email IS NULL THEN\n    NEW.email = LOWER(NEW.name) || '@company.com';\n  END IF;\n  RETURN NEW;\nEND;\n$$ LANGUAGE plpgsql;\n\nCREATE TRIGGER trg_validate_employee\nBEFORE INSERT ON employees\nFOR EACH ROW EXECUTE FUNCTION validate_employee();","description":"Validates and auto-fills data before insert."},{"title":"Audit Log Trigger","useCase":"Track all changes.","code":"CREATE FUNCTION audit_employee_changes()\nRETURNS TRIGGER AS $$\nBEGIN\n  INSERT INTO employee_audit(employee_id, changed_by, changed_at, old_data, new_data)\n  VALUES (OLD.id, current_user, NOW(),\n    ROW(OLD.*)::TEXT, ROW(NEW.*)::TEXT);\n  RETURN NEW;\nEND;\n$$ LANGUAGE plpgsql;\n\nCREATE TRIGGER trg_audit_employees\nAFTER UPDATE ON employees\nFOR EACH ROW EXECUTE FUNCTION audit_employee_changes();","description":"Logs all employee updates to an audit table for compliance."},{"title":"Update Summary Table Trigger","useCase":"Maintain aggregated data.","code":"CREATE FUNCTION update_dept_summary()\nRETURNS TRIGGER AS $$\nBEGIN\n  IF TG_OP = 'INSERT' OR TG_OP = 'UPDATE' THEN\n    INSERT INTO dept_summary(dept_id, emp_count, total_salary)\n    VALUES (NEW.dept_id, 1, NEW.salary)\n    ON CONFLICT (dept_id) DO UPDATE SET\n      emp_count = dept_summary.emp_count + 1,\n      total_salary = dept_summary.total_salary + NEW.salary;\n  END IF;\n  RETURN NEW;\nEND;\n$$ LANGUAGE plpgsql;","description":"Keeps department summary table in sync with employee changes."},{"title":"INSTEAD OF Trigger on View","useCase":"Make views updatable.","code":"CREATE FUNCTION update_employee_view()\nRETURNS TRIGGER AS $$\nBEGIN\n  UPDATE employees SET\n    name = NEW.name, salary = NEW.salary\n  WHERE id = OLD.id;\n  RETURN NEW;\nEND;\n$$ LANGUAGE plpgsql;\n\nCREATE TRIGGER trg_update_emp_view\nINSTEAD OF UPDATE ON employee_details_view\nFOR EACH ROW EXECUTE FUNCTION update_employee_view();","description":"INSTEAD OF trigger makes a complex view support UPDATE operations."},{"title":"Delete Cascade Trigger","useCase":"Custom cascade logic.","code":"CREATE FUNCTION cascade_delete_department()\nRETURNS TRIGGER AS $$\nBEGIN\n  -- Archive employees before delete\n  INSERT INTO employee_archive SELECT * FROM employees WHERE dept_id = OLD.id;\n  DELETE FROM employees WHERE dept_id = OLD.id;\n  RETURN OLD;\nEND;\n$$ LANGUAGE plpgsql;\n\nCREATE TRIGGER trg_cascade_dept\nBEFORE DELETE ON departments\nFOR EACH ROW EXECUTE FUNCTION cascade_delete_department();","description":"Custom cascade: archives employees before deleting a department."}],"mcqQuestions":[{"question":"When does a BEFORE trigger fire?","options":["Before the operation","After the operation","Instead of operation","On commit"],"answer":0,"explanation":"BEFORE triggers fire before the data modification."},{"question":"What does FOR EACH ROW mean?","options":["Once per statement","Once per row","Once per table","Once per transaction"],"answer":1,"explanation":"FOR EACH ROW fires the trigger once per affected row."},{"question":"What does OLD contain?","options":["New row data","Old row data","Table metadata","Trigger data"],"answer":1,"explanation":"OLD contains the row data before modification."},{"question":"How do you abort an operation in a trigger?","options":["RETURN NULL","RAISE EXCEPTION","ROLLBACK","Both A and B"],"answer":3,"explanation":"RETURN NULL or RAISE EXCEPTION both abort the operation."},{"question":"What trigger type makes views updatable?","options":["BEFORE","AFTER","INSTEAD OF","FOR EACH ROW"],"answer":2,"explanation":"INSTEAD OF triggers replace the operation, making views writable."},{"question":"How do you disable a trigger?","options":["DROP TRIGGER","DISABLE TRIGGER","ALTER TABLE ... DISABLE TRIGGER","DEACTIVATE TRIGGER"],"answer":2,"explanation":"ALTER TABLE table_name DISABLE TRIGGER trigger_name disables it."}]};
TOPICS_DATA["sql"]["sql-normalization"] = {"id":"sql-normalization","title":"Database Normalization","difficulty":"intermediate","estimatedMinutes":30,"tldr":["Normalization organizes database schema to reduce data redundancy and improve data integrity.","1NF: each cell contains a single value, each column has a unique name, rows are unique.","2NF: 1NF + every non-key column is fully functionally dependent on the entire primary key.","3NF: 2NF + no transitive dependencies (non-key column depends on another non-key column)."],"laymanDefinition":"Normalization is like organizing a messy desk. 1NF is making sure each drawer has one type of item. 2NF is making sure items in a drawer actually belong there (not just because of the desk). 3NF is making sure nothing depends on something that could move.","deepDive":[{"heading":"First Normal Form (1NF)","text":"Each column has a single atomic value (no arrays or comma-separated lists). Each column has a unique name. All entries in a column are the same type. Each row is unique (has a primary key). Table: Student | Courses (CS101,CS102) → split to Student | Course."},{"heading":"Second Normal Form (2NF)","text":"Must be 1NF. Every non-key column must depend on the entire primary key (for composite keys). If a table has PK (StudentID, CourseID) and column Instructor depends only on CourseID, it violates 2NF. Solution: split into separate tables."},{"heading":"Third Normal Form (3NF)","text":"Must be 2NF. No transitive dependencies: a non-key column depends on another non-key column. Example: Order → CustomerID → CustomerName violates 3NF because CustomerName depends on CustomerID, not directly on Order. Solution: separate Customers table."},{"heading":"Boyce-Codd Normal Form (BCNF)","text":"Stricter version of 3NF. Every determinant must be a candidate key. Every functional dependency X → Y, X must be a superkey. Resolves anomalies that 3NF misses when there are overlapping candidate keys."},{"heading":"Denormalization","text":"Intentionally adding redundancy for performance. Common in data warehouses (star schema). Benefits: fewer JOINs, faster reads. Costs: data inconsistency risk, more storage, more complex writes. Trade-off decision based on read/write patterns."}],"interviewAnswer":"Normalization up to 3NF is standard practice for transactional databases. BCNF handles edge cases. Denormalization is a deliberate optimization for read-heavy workloads like data warehouses.","interviewQuestions":[{"question":"What is database normalization?","answer":"The process of organizing schema to reduce redundancy and dependency by dividing tables and defining relationships."},{"question":"What is 1NF?","answer":"First Normal Form: atomic values, unique column names, same type per column, unique rows with primary key."},{"question":"What is 2NF?","answer":"Second Normal Form: 1NF + every non-key column fully depends on the entire primary key (no partial dependency)."},{"question":"What is 3NF?","answer":"Third Normal Form: 2NF + no transitive dependencies (non-key column depends only on the primary key)."},{"question":"What is a transitive dependency?","answer":"When column A determines column B, and B determines column C. C depends on B, not directly on the primary key."},{"question":"What is BCNF?","answer":"Boyce-Codd Normal Form: every determinant is a candidate key. Stricter than 3NF."},{"question":"What is denormalization?","answer":"Intentionally adding redundancy for read performance. Common in data warehouses and reporting systems."},{"question":"What are the benefits of normalization?","answer":"Reduces data redundancy, improves data integrity, simplifies maintenance, prevents update/insert/delete anomalies."},{"question":"What are the costs of normalization?","answer":"More tables, more JOINs, potentially slower reads. Complex queries with many JOINs can impact performance."},{"question":"Is it always good to normalize to 3NF?","answer":"For OLTP (transactional) systems, yes generally. For OLAP (analytical/reporting) systems, denormalization is often beneficial."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Database Normalization</text><rect x=\"10\" y=\"35\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"65\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">1NF</text><text x=\"65\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Atomic values</text><rect x=\"10\" y=\"65\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"65\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">2NF</text><text x=\"65\" y=\"93\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Full key dep</text><rect x=\"10\" y=\"95\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"65\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">3NF</text><text x=\"65\" y=\"123\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">No transitive</text><rect x=\"10\" y=\"125\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"65\" y=\"141\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">BCNF</text><text x=\"65\" y=\"153\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Every det = key</text><rect x=\"10\" y=\"155\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1\"/><text x=\"65\" y=\"171\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Denormal</text><text x=\"65\" y=\"183\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Perf tradeoff</text><line x1=\"120\" y1=\"48\" x2=\"150\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"78\" x2=\"150\" y2=\"78\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"108\" x2=\"150\" y2=\"108\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"138\" x2=\"150\" y2=\"138\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"168\" x2=\"150\" y2=\"168\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"35\" width=\"220\" height=\"155\" rx=\"4\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1\"/><text x=\"270\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Normalization</text><text x=\"270\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Organize schema to reduce redundancy and improve integrity step by step.</text><text x=\"240\" y=\"220\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Normalization: 1NF → 2NF → 3NF — reducing redundancy at each level.</text></svg>","codeExamples":[{"title":"Unnormalized to 1NF","useCase":"Remove repeating groups.","code":"-- Unnormalized:\nCREATE TABLE student_courses (\n  student_name VARCHAR(100),\n  courses TEXT -- comma separated: \"CS101,CS102\"\n);\n\n-- 1NF: atomic values\nCREATE TABLE student_courses_1nf (\n  student_name VARCHAR(100),\n  course_code VARCHAR(10),\n  PRIMARY KEY (student_name, course_code)\n);","description":"Split comma-separated courses into individual rows for 1NF."},{"title":"1NF to 2NF Example","useCase":"Remove partial dependency.","code":"-- 1NF (violates 2NF):\n-- PK: (student_id, course_id)\n-- course_name depends only on course_id (partial)\n\n-- 2NF: split into two tables\nCREATE TABLE enrollments (\n  student_id INT, course_id INT,\n  grade CHAR(1),\n  PRIMARY KEY (student_id, course_id)\n);\n\nCREATE TABLE courses (\n  id INT PRIMARY KEY,\n  name VARCHAR(100),\n  instructor VARCHAR(100)\n);","description":"Partial dependency (course_name on course_id only) is resolved by extracting a courses table."},{"title":"2NF to 3NF","useCase":"Remove transitive dependency.","code":"-- 2NF (violates 3NF):\n-- order_id PK, customer_id, customer_name, order_total\n-- customer_name depends on customer_id, not order_id (transitive)\n\n-- 3NF:\nCREATE TABLE orders (\n  id INT PRIMARY KEY,\n  customer_id INT REFERENCES customers(id),\n  order_total DECIMAL(10,2)\n);\n\nCREATE TABLE customers (\n  id INT PRIMARY KEY,\n  name VARCHAR(100),\n  email VARCHAR(100)\n);","description":"Transitive dependency (customer_name → customer_id) resolved by separate customers table."},{"title":"Normalization in Practice","useCase":"Complete example.","code":"-- Start: one big table with redundancy\nCREATE TABLE raw_orders (\n  order_id INT, customer_name VARCHAR(100),\n  customer_email VARCHAR(100),\n  product_name VARCHAR(100),\n  product_price DECIMAL,\n  quantity INT, order_date DATE\n);\n\n-- Normalized (3NF) schema:\n-- customers(id, name, email)\n-- products(id, name, price)\n-- orders(id, customer_id, order_date)\n-- order_items(order_id, product_id, quantity)","description":"Transforming a denormalized table into a normalized 3NF schema with four tables."},{"title":"Denormalization for Reporting","useCase":"Star schema example.","code":"-- Data warehouse star schema (denormalized)\nCREATE TABLE fact_sales (\n  sale_id INT,\n  date_id INT REFERENCES dim_date(id),\n  product_id INT REFERENCES dim_product(id),\n  customer_id INT REFERENCES dim_customer(id),\n  quantity INT,\n  amount DECIMAL(10,2)\n);\n\n-- Dimension tables are denormalized for fast queries\nCREATE TABLE dim_product (\n  id INT PRIMARY KEY,\n  name VARCHAR(100), category, brand, supplier\n);","description":"Star schema uses controlled denormalization for analytical query performance."}],"mcqQuestions":[{"question":"Which normal form requires atomic values?","options":["1NF","2NF","3NF","BCNF"],"answer":0,"explanation":"1NF requires atomic (single) values in each cell."},{"question":"What does 2NF remove?","options":["Duplicate rows","Partial dependencies","Transitive dependencies","NULL values"],"answer":1,"explanation":"2NF removes partial dependencies on composite keys."},{"question":"What does 3NF remove?","options":["Partial dependencies","Transitive dependencies","Atomic values","Foreign keys"],"answer":1,"explanation":"3NF removes transitive dependencies (non-key → non-key)."},{"question":"What is a typical use for denormalization?","options":["OLTP systems","Data warehouses","Every application","Mobile apps"],"answer":1,"explanation":"Denormalization is common in data warehouses and reporting databases."},{"question":"Which normal form is stricter than 3NF?","options":["4NF","BCNF","DKNF","5NF"],"answer":1,"explanation":"Boyce-Codd Normal Form (BCNF) is stricter than 3NF."},{"question":"What is a transitive dependency?","options":["A depends on B, B depends on PK","C depends on B, B depends on A","A depends on PK through B","Both B and C"],"answer":3,"explanation":"Transitive: non-key column depends on another non-key column."}]};
TOPICS_DATA["sql"]["sql-json"] = {"id":"sql-json","title":"JSON & JSONB","difficulty":"advanced","estimatedMinutes":25,"tldr":["PostgreSQL offers two JSON types: JSON (stores exact text copy, re-parsed each query) and JSONB (stores binary/decomposed, supports indexing).","JSONB is generally preferred: faster to query (indexes, no re-parsing), supports GIN indexing for containment/existence queries, and removes duplicate keys.","Operators: -> (JSON field as JSON), ->> (JSON field as text), @> (contains), ? (key exists), || (concatenate).","Functions: jsonb_build_object, jsonb_agg, jsonb_array_elements, jsonb_set, jsonb_pretty."],"laymanDefinition":"JSONB is like filing a document in a filing cabinet with a detailed index of every word. JSON is like filing the document as-is — every time you want to read it, you pull out the whole thing. JSONB is faster to search through but takes slightly more space.","deepDive":[{"heading":"JSON vs JSONB","text":"JSON: stores exact input (preserves whitespace, key order, duplicate keys). Slower operations (re-parsed each time). No indexes. JSONB: stores parsed binary format. Supports indexing (GIN, B-tree). More operators. Preferred for most use cases."},{"heading":"JSONB Operators","text":"-> \\'key\\' — get value as JSON. ->> \\'key\\' — get value as TEXT. @> \\'{\"key\": \"val\"}\\' — top-level contains. ? \\'key\\' — key exists. ?| ARRAY[\\'a\\',\\'b\\'] — any key exists. ?& — all keys exist. || — merge/concatenate JSONB objects."},{"heading":"GIN Indexes on JSONB","text":"CREATE INDEX ON table USING GIN (jsonb_col); — indexes all keys/values. Supports @>, ?, ?|, ?& operators. JSON path ops (@? and @*) also use GIN. Much faster than sequential scan for JSON queries."},{"heading":"JSONB Functions","text":"jsonb_build_object(\\'key\\', val) — build JSONB from key-value pairs. jsonb_agg(expr) — aggregate rows into JSONB array. jsonb_array_elements(jsonb) — expand array to rows. jsonb_set(target, path, newval) — update nested value."},{"heading":"JSON Path Queries (PG 12+)","text":"jsonb_path_exists(data, \\'$.phone[*].type ? (@ == \"mobile\")\\') — SQL/JSON path language. Path access: \\'$.store.book[0].title\\'. Powerful for complex JSON document queries with filters and conditions."}],"interviewAnswer":"PostgreSQL's JSONB support is best-in-class, offering NoSQL-like document storage within a relational database. Use JSONB for flexible schemas, event sourcing, and when combining structured and semi-structured data.","interviewQuestions":[{"question":"What is the difference between JSON and JSONB?","answer":"JSON stores text (re-parsed each query). JSONB stores binary (faster, supports indexing, preferred)."},{"question":"What does the @> operator do?","answer":"Checks if a JSONB document contains another JSONB value at the top level."},{"question":"What does the ? operator do?","answer":"Checks if a key exists in a JSONB object."},{"question":"What index type supports JSONB containment queries?","answer":"GIN (Generalized Inverted Index). CREATE INDEX ON table USING GIN (jsonb_col);"},{"question":"How do you extract a JSON field as text?","answer":"column ->> \\'key\\' returns the value as TEXT. column -> \\'key\\' returns as JSON."},{"question":"How do you aggregate rows into a JSON array?","answer":"jsonb_agg(column) or jsonb_agg(column ORDER BY ...) aggregates values into a JSONB array."},{"question":"What does jsonb_set do?","answer":"Updates a nested value in a JSONB document: jsonb_set(data, \\'{path,to,field}\\', \\'new_value\\'::jsonb)."},{"question":"How do you expand a JSON array to rows?","answer":"jsonb_array_elements(jsonb_col) — one row per array element."},{"question":"What is jsonb_pretty?","answer":"Formats JSONB with indentation for readability."},{"question":"Can JSONB have indexes on specific paths?","answer":"Yes. CREATE INDEX ON table USING GIN ((jsonb_col -> \\'email\\')); — index on specific key."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">JSON & JSONB</text><rect x=\"10\" y=\"35\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"65\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">JSON</text><text x=\"65\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Text storage</text><rect x=\"10\" y=\"65\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"65\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">JSONB</text><text x=\"65\" y=\"93\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Binary storage</text><rect x=\"10\" y=\"95\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"65\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">@></text><text x=\"65\" y=\"123\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Contains</text><rect x=\"10\" y=\"125\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"65\" y=\"141\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">->></text><text x=\"65\" y=\"153\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Extract</text><rect x=\"10\" y=\"155\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1\"/><text x=\"65\" y=\"171\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">GIN Index</text><text x=\"65\" y=\"183\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Fast search</text><line x1=\"120\" y1=\"48\" x2=\"150\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"78\" x2=\"150\" y2=\"78\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"108\" x2=\"150\" y2=\"108\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"138\" x2=\"150\" y2=\"138\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"168\" x2=\"150\" y2=\"168\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"35\" width=\"220\" height=\"155\" rx=\"4\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1\"/><text x=\"270\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">JSON & JSONB</text><text x=\"270\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">PostgreSQL's NoSQL-style document storage with indexing and powerful operators.</text><text x=\"240\" y=\"220\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">JSON & JSONB: Flexible document storage with relational integrity in PostgreSQL.</text></svg>","codeExamples":[{"title":"Creating and Querying JSONB","useCase":"Store and retrieve nested data.","code":"CREATE TABLE products (\n  id SERIAL PRIMARY KEY,\n  name VARCHAR(100),\n  attributes JSONB\n);\n\nINSERT INTO products (name, attributes) VALUES (\n  'Laptop',\n  '{\"brand\": \"Dell\", \"specs\": {\"ram\": \"16GB\", \"cpu\": \"i7\"}, \"tags\": [\"electronics\", \"computers\"]}'\n);\n\nSELECT name, attributes->'brand' AS brand,\n  attributes->'specs'->>'ram' AS ram\nFROM products\nWHERE attributes @> '{\"brand\": \"Dell\"}';","description":"JSONB with nested objects, extraction, and containment query."},{"title":"JSONB GIN Index","useCase":"Fast JSON searches.","code":"CREATE INDEX idx_products_attrs\nON products USING GIN (attributes);\n\n-- These queries use the index:\nSELECT * FROM products WHERE attributes ? 'brand';\nSELECT * FROM products WHERE attributes @> '{\"tags\": [\"electronics\"]}';\nSELECT * FROM products WHERE attributes ?| ARRAY['color', 'size'];","description":"GIN index enables fast containment, existence, and key lookups in JSONB."},{"title":"Aggregate to JSON","useCase":"Build JSON from relational data.","code":"SELECT\n  department,\n  jsonb_agg(jsonb_build_object(\n    'name', name,\n    'salary', salary\n  ) ORDER BY name) AS employees\nFROM employees\nGROUP BY department;","description":"Creates nested JSON documents from relational GROUP BY results."},{"title":"jsonb_set to Update","useCase":"Modify nested JSON values.","code":"-- Update laptop specs\nUPDATE products SET attributes = jsonb_set(\n  attributes,\n  '{specs, ram}',\n  '\"32GB\"'\n) WHERE name = 'Laptop';\n\n-- Result: specs.ram changes from \"16GB\" to \"32GB\"","description":"jsonb_set updates deeply nested JSONB fields without rewriting the entire document."},{"title":"JSON Path Queries","useCase":"SQL/JSON path expressions.","code":"-- Find products with mobile phone in tags\nSELECT name FROM products\nWHERE jsonb_path_exists(attributes, '$.tags[*] ? (@ == \"mobile\")');\n\n-- Extract all tag values\nSELECT jsonb_path_query(attributes, '$.tags[*]')\nFROM products;","description":"JSON path expressions (PG 12+) for complex document queries."}],"mcqQuestions":[{"question":"Which JSON type supports indexing?","options":["JSON","JSONB","Both","Neither"],"answer":1,"explanation":"JSONB supports GIN and B-tree indexing. JSON does not."},{"question":"What operator checks if a key exists?","options":["@>","?","->","||"],"answer":1,"explanation":"The ? operator checks if a key exists in a JSONB object."},{"question":"What does @> check?","options":["Key existence","Containment","Equality","Type match"],"answer":1,"explanation":"@> checks if the left JSONB contains the right JSONB."},{"question":"How do you extract a JSON field as text?","options":["->","->>","#>","@>"],"answer":1,"explanation":"->> extracts a JSON field as TEXT."},{"question":"What index is best for JSONB?","options":["B-tree","Hash","GIN","GiST"],"answer":2,"explanation":"GIN (Generalized Inverted Index) is best for JSONB containment queries."},{"question":"What function aggregates rows to JSON?","options":["jsonb_agg","jsonb_build","jsonb_row","jsonb_collect"],"answer":0,"explanation":"jsonb_agg aggregates values into a JSONB array."}]};
TOPICS_DATA["sql"]["sql-full-text-search"] = {"id":"sql-full-text-search","title":"Full-Text Search","difficulty":"advanced","estimatedMinutes":25,"tldr":["Full-text search enables natural language search across text columns, going beyond simple LIKE patterns.","PostgreSQL uses tsvector (document) and tsquery (query) types with stemming, ranking, and stop word removal.","LIKE is fine for small datasets. Full-text search is essential for large text collections, articles, and product descriptions.","GIN indexes on tsvector columns enable fast full-text search queries."],"laymanDefinition":"Full-text search is like having a smart index in the back of a book. LIKE '%running%' only finds \"running\". Full-text search finds \"run\", \"runs\", \"running\", \"ran\" — it understands word variations (stemming). It also ignores common words like \"the\" and \"and\" (stop words).","deepDive":[{"heading":"tsvector and tsquery","text":"tsvector: text search document — list of lexemes (stemmed words) with positions. to_tsvector(\\'english\\', text) — converts text to tsvector. tsquery: search query — lexemes combined with & (AND), | (OR), ! (NOT). to_tsquery(\\'english\\', \\'cat & dog\\') — creates query."},{"heading":"Match Operator @@","text":"tsvector @@ tsquery — returns true if document matches query. SELECT * FROM articles WHERE to_tsvector(\\'english\\', body) @@ to_tsquery(\\'english\\', \\'database & performance\\'). Indexable operator."},{"heading":"Ranking Results","text":"ts_rank(tsvector, tsquery) — computes relevance score based on term frequency, proximity, and document structure. ts_rank_cd — cover density ranking. ORDER BY ts_rank DESC for relevance-ordered results."},{"heading":"GIN Indexes for FTS","text":"CREATE INDEX ON articles USING GIN (to_tsvector(\\'english\\', body)); — pre-computes and indexes tsvector. Makes @@ queries fast. GiST indexes work too but are slower for updates and larger."},{"heading":"Configuration and Customization","text":"Language configuration: \\'english\\', \\'simple\\', \\'french\\', etc. Controls stemming rules and stop words. Custom dictionaries: add custom stop words, synonyms, thesaurus. Use ALTER TEXT SEARCH CONFIGURATION."}],"interviewAnswer":"Full-text search is a game-changer for text-heavy applications. It handles word variations, ignores noise words, ranks by relevance, and performs well at scale with proper indexing. PostgreSQL's built-in FTS rivals dedicated search tools for many applications.","interviewQuestions":[{"question":"What is full-text search?","answer":"Natural language search with stemming, stop words, ranking, and phrase matching — beyond simple LIKE patterns."},{"question":"What is a tsvector?","answer":"A text search document type containing lexemes (stemmed words) with positional information. Created with to_tsvector()."},{"question":"What is a tsquery?","answer":"A text search query type with boolean operators. Created with to_tsquery() or plainto_tsquery()."},{"question":"What does the @@ operator do?","answer":"Matches a tsvector against a tsquery. Returns true if the document satisfies the query."},{"question":"How do you rank full-text search results?","answer":"ts_rank(tsvector, tsquery) returns a relevance score. Use ORDER BY ts_rank DESC for best matches first."},{"question":"What index supports fast full-text search?","answer":"GIN index on the tsvector column. CREATE INDEX ON table USING GIN (to_tsvector(\\'english\\', column))."},{"question":"What is stemming?","answer":"Reducing words to their root form: \"running\", \"runs\", \"ran\" all stem to \"run\". Handled automatically by the text search configuration."},{"question":"What are stop words?","answer":"Common words like \"the\", \"and\", \"in\" that are ignored in full-text search. Controlled by the language configuration."},{"question":"What is the difference between to_tsquery and plainto_tsquery?","answer":"to_tsquery uses operators (&, |, !). plainto_tsquery treats all words as AND and adds & between them."},{"question":"Can full-text search handle phrases?","answer":"Yes. Use phraseto_tsquery() for exact phrase matching. Also use <-> (followed by) operator in tsquery for word proximity."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Full-Text Search</text><rect x=\"10\" y=\"35\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"65\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">LIKE</text><text x=\"65\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Simple match</text><rect x=\"10\" y=\"65\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"65\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">tsvector</text><text x=\"65\" y=\"93\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Document</text><rect x=\"10\" y=\"95\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"65\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">tsquery</text><text x=\"65\" y=\"123\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Query</text><rect x=\"10\" y=\"125\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"65\" y=\"141\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">@@</text><text x=\"65\" y=\"153\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Match op</text><rect x=\"10\" y=\"155\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1\"/><text x=\"65\" y=\"171\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">GIN</text><text x=\"65\" y=\"183\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Index</text><line x1=\"120\" y1=\"48\" x2=\"150\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"78\" x2=\"150\" y2=\"78\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"108\" x2=\"150\" y2=\"108\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"138\" x2=\"150\" y2=\"138\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"168\" x2=\"150\" y2=\"168\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"35\" width=\"220\" height=\"155\" rx=\"4\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1\"/><text x=\"270\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Full-Text Search</text><text x=\"270\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Natural language search with stemming, ranking, and indexes — beyond LIKE.</text><text x=\"240\" y=\"220\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Full-Text Search: Language-aware text search with stemming, weighting, and ranking.</text></svg>","codeExamples":[{"title":"Basic Full-Text Search","useCase":"Search articles by content.","code":"SELECT id, title,\n  ts_rank(to_tsvector('english', body), to_tsquery('english', 'performance & tuning')) AS rank\nFROM articles\nWHERE to_tsvector('english', body) @@ to_tsquery('english', 'performance & tuning')\nORDER BY rank DESC\nLIMIT 10;","description":"Searches for articles containing both \"performance\" and \"tuning\" with relevance ranking."},{"title":"Creating FTS Index","useCase":"GiST index for speed.","code":"-- Add a tsvector column\nALTER TABLE articles ADD COLUMN fts tsvector;\n\n-- Populate with trigger\nCREATE FUNCTION update_fts() RETURNS TRIGGER AS $$\nBEGIN\n  NEW.fts := to_tsvector('english', COALESCE(NEW.title, '') || ' ' || COALESCE(NEW.body, ''));\n  RETURN NEW;\nEND;\n$$ LANGUAGE plpgsql;\n\nCREATE TRIGGER trg_article_fts\nBEFORE INSERT OR UPDATE ON articles\nFOR EACH ROW EXECUTE FUNCTION update_fts();\n\n-- Create GIN index\nCREATE INDEX idx_articles_fts ON articles USING GIN (fts);","description":"Sets up automatic tsvector maintenance with trigger and GIN index."},{"title":"Phrase Search","useCase":"Exact phrase matching.","code":"SELECT id, title\nFROM articles\nWHERE to_tsvector('english', body) @@ phraseto_tsquery('english', 'database performance tuning')\nORDER BY ts_rank(to_tsvector('english', body), phraseto_tsquery('english', 'database performance tuning')) DESC;","description":"phraseto_tsquery matches the exact phrase with word order."},{"title":"Weighted Search","useCase":"Title vs body weighting.","code":"-- Assign weights: A=title (highest), B=body\nSELECT id, ts_rank(\n  setweight(to_tsvector('english', title), 'A') ||\n  setweight(to_tsvector('english', body), 'B'),\n  to_tsquery('english', 'database')\n) AS rank\nFROM articles\nWHERE setweight(to_tsvector('english', title), 'A') ||\n  setweight(to_tsvector('english', body), 'B')\n  @@ to_tsquery('english', 'database')\nORDER BY rank DESC;","description":"Title matches get higher weight than body matches for better relevance ranking."},{"title":"Highlighting Results","useCase":"Show matching snippets.","code":"SELECT\n  id, title,\n  ts_headline('english', body, to_tsquery('english', 'performance'),\n    'StartSel = <mark>, StopSel = </mark>, MaxWords=30, MinWords=10') AS snippet\nFROM articles\nWHERE to_tsvector('english', body) @@ to_tsquery('english', 'performance')\nLIMIT 5;","description":"ts_headline generates HTML snippets with search terms highlighted."}],"mcqQuestions":[{"question":"What type stores search documents?","options":["tsquery","tsvector","text","jsonb"],"answer":1,"explanation":"tsvector stores parsed search documents with lexemes."},{"question":"What operator matches document to query?","options":["@@","@>","&&","##"],"answer":0,"explanation":"@@ is the full-text search match operator."},{"question":"What is the default FTS configuration language?","options":["english","simple","default","standard"],"answer":0,"explanation":"english is the default with stemming and stop words."},{"question":"What index is best for full-text search?","options":["B-tree","Hash","GIN","BRIN"],"answer":2,"explanation":"GIN indexes are optimal for full-text search."},{"question":"What function ranks search results?","options":["ts_rank","ts_headline","tsvector","to_tsquery"],"answer":0,"explanation":"ts_rank computes relevance scores for ordering results."},{"question":"What is stemming?","options":["Finding word roots","Removing stop words","Indexing phrases","Ranking results"],"answer":0,"explanation":"Stemming reduces words to their root form for broader matching."}]};
TOPICS_DATA["sql"]["sql-explain"] = {"id":"sql-explain","title":"Query Optimization & EXPLAIN","difficulty":"advanced","estimatedMinutes":30,"tldr":["EXPLAIN shows the query execution plan — how the database will execute a query, including index usage, join methods, and cost estimates.","EXPLAIN ANALYZE actually executes the query and shows actual vs estimated times. Use with caution on write queries.","Key plan nodes: Seq Scan (full table scan), Index Scan (index lookup), Index Only Scan (all data in index), Bitmap Heap Scan.","Optimization: index creation, query rewriting, avoiding full scans, proper join order, and analyzing table statistics."],"laymanDefinition":"EXPLAIN is like looking at a GPS route before driving. It shows the roads (scans), the turns (joins), and the estimated time (cost). EXPLAIN ANALYZE is like actually driving the route and recording the real time — it tells you where you got stuck in traffic.","deepDive":[{"heading":"EXPLAIN Output","text":"Seq Scan: scans entire table (slowest, but sometimes fastest for small tables). Index Scan: uses index to find rows (fast for selective queries). Index Only Scan: reads only index, no table access (fastest). Bitmap Heap Scan: combines multiple index results."},{"heading":"Cost Values","text":"Format: cost=0.00..42.35 rows=10 width=4. First number: startup cost before first row. Second: total cost to return all rows. rows: estimated row count. width: estimated average row width in bytes. Compare costs between different query plans."},{"heading":"Join Methods","text":"Nested Loop: for each row in outer, scan inner (good for small outer + indexed inner). Hash Join: build hash table on one input, probe with other (good for large, unsorted data). Merge Join: sort both inputs then merge (good for large, pre-sorted data)."},{"heading":"ANALYZE and Statistics","text":"ANALYZE table_name; — updates table statistics (row count, value distribution). The query planner relies on accurate statistics. autovacuum runs ANALYZE automatically. pg_stat_user_tables shows last analyze time."},{"heading":"Common Optimization Patterns","text":"Add missing indexes on WHERE/JOIN/ORDER BY columns. Rewrite OR conditions as UNION ALL. Use EXISTS instead of DISTINCT for existence checks. Avoid functions on indexed columns in WHERE (e.g., WHERE LOWER(name) = — use expression index)."}],"interviewAnswer":"EXPLAIN is the most important tool for query optimization. Understanding execution plans tells you exactly why a query is slow and what to fix. Always check EXPLAIN ANALYZE before and after making optimization changes.","interviewQuestions":[{"question":"What does EXPLAIN do?","answer":"Shows the query execution plan: how the database will access tables, which indexes it uses, and cost estimates."},{"question":"What is the difference between EXPLAIN and EXPLAIN ANALYZE?","answer":"EXPLAIN shows only the estimated plan. EXPLAIN ANALYZE executes the query and shows actual timing and row counts."},{"question":"What is a Sequential Scan?","answer":"Reading every row of a table one by one. Fast for small tables, slow for large tables. Indicates missing indexes."},{"question":"What is an Index Scan?","answer":"Using an index to find rows. Fast for selective queries (returning a small percentage of rows)."},{"question":"What is an Index Only Scan?","answer":"Reading only the index without accessing the table. Fastest scan type — requires a covering index."},{"question":"What is a Nested Loop Join?","answer":"For each row in the outer table, scan the inner table for matches. Best for small outer + indexed inner."},{"question":"What is a Hash Join?","answer":"Build a hash table on one input, probe it with the other. Best for large, unsorted data with equality conditions."},{"question":"What is a Merge Join?","answer":"Sort both inputs then merge. Best for large, pre-sorted datasets or when ORDER BY is already needed."},{"question":"What do cost numbers in EXPLAIN mean?","answer":"cost=X..Y: X is startup cost, Y is total cost. Higher cost = slower plan. Compare different plans."},{"question":"How do you update statistics?","answer":"ANALYZE table_name; Updates table statistics for the query planner. PostgreSQL runs autovacuum/autoanalyze automatically."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Query Optimization & EXPLAIN</text><rect x=\"10\" y=\"35\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"65\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">EXPLAIN</text><text x=\"65\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Estimated plan</text><rect x=\"10\" y=\"65\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"65\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">EXPLAIN ANALYZE</text><text x=\"65\" y=\"93\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Actual timing</text><rect x=\"10\" y=\"95\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"65\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Seq Scan</text><text x=\"65\" y=\"123\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Full table</text><rect x=\"10\" y=\"125\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"65\" y=\"141\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Index Scan</text><text x=\"65\" y=\"153\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Fast lookup</text><rect x=\"10\" y=\"155\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1\"/><text x=\"65\" y=\"171\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Hash Join</text><text x=\"65\" y=\"183\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Merge large</text><line x1=\"120\" y1=\"48\" x2=\"150\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"78\" x2=\"150\" y2=\"78\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"108\" x2=\"150\" y2=\"108\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"138\" x2=\"150\" y2=\"138\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"168\" x2=\"150\" y2=\"168\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"35\" width=\"220\" height=\"155\" rx=\"4\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1\"/><text x=\"270\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Query Optimization</text><text x=\"270\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Understand execution plans, indexes, join methods, and statistics.</text><text x=\"240\" y=\"220\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">EXPLAIN & Optimization: Understand execution plans to write faster SQL queries.</text></svg>","codeExamples":[{"title":"Reading EXPLAIN Output","useCase":"Understanding a basic plan.","code":"EXPLAIN SELECT * FROM employees WHERE salary > 80000;\n\n-- Output:\n-- Seq Scan on employees  (cost=0.00..324.50 rows=15 width=72)\n--   Filter: (salary > 80000)\n\n-- After adding an index:\nCREATE INDEX ON employees(salary);\n\n-- Output:\n-- Index Scan using employees_salary_idx on employees  (cost=0.28..8.29 rows=15 width=72)\n--   Index Cond: (salary > 80000)","description":"Shows how adding an index changes Seq Scan to Index Scan with lower cost."},{"title":"EXPLAIN ANALYZE","useCase":"Actual vs estimated.","code":"EXPLAIN ANALYZE\nSELECT e.name, d.department_name\nFROM employees e\nJOIN departments d ON e.dept_id = d.id\nWHERE d.department_name = 'Engineering';\n\n-- Shows actual time, rows, loops\n-- Look for: actual time vs estimated time mismatch\n-- Look for: \"rows\" vs \"rows\" mismatch (stale statistics)","description":"EXPLAIN ANALYZE shows actual execution metrics to compare with estimates."},{"title":"Optimizing a Slow Query","useCase":"Step-by-step optimization.","code":"-- Slow query:\nEXPLAIN ANALYZE SELECT * FROM orders\nWHERE status = 'pending' AND amount > 1000\nORDER BY created_at DESC;\n\n-- Add composite index:\nCREATE INDEX idx_orders_status_amount_date\nON orders(status, amount, created_at DESC);\n\n-- Now: Index Scan with index condition, no separate sort\n-- Much faster for this query pattern","description":"A covering composite index can turn a slow query into an instant one."},{"title":"Detecting Missing Indexes","useCase":"Using pg_stat_user_tables.","code":"-- Find tables with most sequential scans\nSELECT\n  schemaname, relname,\n  seq_scan, seq_tup_read,\n  idx_scan, idx_tup_fetch\nFROM pg_stat_user_tables\nORDER BY seq_scan DESC\nLIMIT 10;","description":"Identifies tables where sequential scans dominate — candidates for indexing."},{"title":"Optimizing JOINs","useCase":"Rewrite for better performance.","code":"-- Instead of:\nSELECT DISTINCT c.name\nFROM customers c\nJOIN orders o ON c.id = o.customer_id\nWHERE o.status = 'shipped';\n\n-- Better:\nSELECT c.name\nFROM customers c\nWHERE EXISTS (\n  SELECT 1 FROM orders o\n  WHERE o.customer_id = c.id AND o.status = 'shipped'\n);\n\n-- EXISTS can early-exit on first match","description":"EXISTS is often faster than DISTINCT for existence checks."}],"mcqQuestions":[{"question":"What does EXPLAIN show?","options":["Query results","Execution plan","Table data","Index contents"],"answer":1,"explanation":"EXPLAIN shows the query execution plan."},{"question":"What scan type is fastest?","options":["Seq Scan","Index Scan","Index Only Scan","Bitmap Scan"],"answer":2,"explanation":"Index Only Scan reads only the index, no table access."},{"question":"What does EXPLAIN ANALYZE do?","options":["Shows estimated plan only","Executes query and shows actuals","Shows indexes only","Shows table statistics"],"answer":1,"explanation":"EXPLAIN ANALYZE executes the query and shows actual timing."},{"question":"Which join is best for large unsorted data?","options":["Nested Loop","Hash Join","Merge Join","Cross Join"],"answer":1,"explanation":"Hash Join is best for large, unsorted datasets with equality joins."},{"question":"What does cost=X..Y mean?","options":["X=total, Y=startup","X=startup, Y=total","X=index, Y=scan","X=rows, Y=width"],"answer":1,"explanation":"X is startup cost before first row, Y is total cost."},{"question":"How do you update planner statistics?","options":["UPDATE STATS","ANALYZE","VACUUM","REINDEX"],"answer":1,"explanation":"ANALYZE updates table statistics for the query planner."}]};
TOPICS_DATA["sql"]["sql-injection"] = {"id":"sql-injection","title":"SQL Injection & Prevention","difficulty":"intermediate","estimatedMinutes":25,"tldr":["SQL injection is a code injection technique where attackers insert malicious SQL into application queries.","Common payloads: ' OR 1=1 --, ' UNION SELECT ... --, ' DROP TABLE users --","Prevention: parameterized queries (prepared statements), input validation, least privilege, escaping.","SQL injection is the #1 vulnerability in web applications according to OWASP Top 10."],"laymanDefinition":"SQL injection is like a thief tricking your digital doorman. Instead of saying \"I'm John from apartment 3B\", they say \"I'm John from apartment 3B OR I'm a resident anyway\". The OR condition makes the check always pass. Parameterized queries are like requiring a key card — no tricks allowed.","deepDive":[{"heading":"How SQL Injection Works","text":"Input: \\' OR 1=1; -- becomes: SELECT * FROM users WHERE email = \\'\\' OR 1=1; --\\' . The -- comments out the rest. Returns all users. UNION injection: \\' UNION SELECT username, password FROM admins -- extracts data from other tables."},{"heading":"Parameterized Queries (Prepared Statements)","text":"Separates SQL code from data. Placeholders: $1, $2 (PostgreSQL), ? (MySQL). Driver safely escapes values. Example (Node.js/pg): client.query(\\'SELECT * FROM users WHERE email = $1\\', [userInput]). Data can never be interpreted as SQL."},{"heading":"ORM Protection","text":"Sequelize, TypeORM, Prisma, Knex use parameterized queries by default. But raw queries and $raw in WHERE filters can bypass protection. Never concatenate user input into raw query strings even within ORMs."},{"heading":"Additional Defenses","text":"Input validation: whitelist allowed characters, reject suspicious patterns. Least privilege: application DB user should only have needed permissions (no DROP TABLE). WAF (Web Application Firewall) can detect and block injection attempts."},{"heading":"Stored Procedure Safety","text":"Stored procedures can help if they use parameterized internal queries. But procedures with EXECUTE (dynamic SQL) are vulnerable if they concatenate input. Always use EXECUTE ... USING for parameterized dynamic SQL."}],"interviewAnswer":"SQL injection is entirely preventable. Never concatenate user input into SQL strings. Use parameterized queries for all database operations. This single practice eliminates the vast majority of SQL injection vulnerabilities.","interviewQuestions":[{"question":"What is SQL injection?","answer":"An attack where malicious SQL code is inserted into application queries through user input, potentially exposing or destroying data."},{"question":"How does parameterized query prevent injection?","answer":"Separates SQL code from data. User input is treated as data values, never executable SQL."},{"question":"What is the most common SQL injection payload?","answer":"\\' OR 1=1 -- bypasses authentication by making the WHERE clause always true."},{"question":"Are ORMs safe from SQL injection?","answer":"ORMs use parameterized queries by default. But raw queries and bypass methods can still be vulnerable."},{"question":"What is least privilege?","answer":"Database users should have only the minimum permissions needed. The app user should not have DROP TABLE or administrative access."},{"question":"What does the -- do in SQL injection?","answer":"Comments out the rest of the SQL query, preventing syntax errors from the injected payload."},{"question":"Can stored procedures prevent SQL injection?","answer":"Only if they use parameterized queries internally. Dynamic SQL within procedures (EXECUTE with concatenation) is still vulnerable."},{"question":"What is blind SQL injection?","answer":"Injection where the attacker does not see error messages. They infer information through true/false responses (boolean-based) or timing delays (time-based)."},{"question":"What is second-order SQL injection?","answer":"Malicious input is stored in the database, then executed later when retrieved and used in another query without proper escaping."},{"question":"How do you test for SQL injection?","answer":"Input special characters (\\', \", ;, --). Error messages revealing SQL syntax suggest vulnerability. Automated tools: SQLMap, OWASP ZAP."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">SQL Injection & Prevention</text><rect x=\"10\" y=\"35\" width=\"120\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"70\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Input: ' OR 1=1--</text><text x=\"70\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Malicious payload</text><line x1=\"130\" y1=\"48\" x2=\"160\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"170\" y=\"35\" width=\"120\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"230\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Parameterized</text><text x=\"230\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Safe query</text><line x1=\"170\" y1=\"60\" x2=\"170\" y2=\"80\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"10\" y=\"70\" width=\"120\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"70\" y=\"86\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Validation</text><text x=\"70\" y=\"98\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Input check</text><rect x=\"10\" y=\"105\" width=\"120\" height=\"25\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"70\" y=\"121\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Least Priv</text><text x=\"70\" y=\"133\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Min perms</text><line x1=\"130\" y1=\"83\" x2=\"160\" y2=\"83\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"130\" y1=\"118\" x2=\"160\" y2=\"118\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"170\" y=\"75\" width=\"120\" height=\"50\" rx=\"4\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1\"/><text x=\"230\" y=\"91\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Escaping</text><text x=\"230\" y=\"103\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Data > Code</text><rect x=\"300\" y=\"35\" width=\"180\" height=\"160\" rx=\"4\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1\"/><text x=\"390\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">SQL Injection Prevention</text><text x=\"390\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Parameterized queries + input validation + least privilege = defense in depth.</text><text x=\"240\" y=\"225\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">SQL Injection: Code injection attack. Prevention via parameterized queries and defense in depth.</text></svg>","codeExamples":[{"title":"Vulnerable vs Safe (Node.js/pg)","useCase":"Compare bad vs good.","code":"// VULNERABLE — NEVER DO THIS:\nconst sql = `SELECT * FROM users WHERE email = '${userInput}'`;\nconst result = await client.query(sql);\n\n// SAFE — parameterized query:\nconst sql = 'SELECT * FROM users WHERE email = $1';\nconst result = await client.query(sql, [userInput]);","description":"String interpolation vs parameterized query — the difference between vulnerable and safe."},{"title":"Python/psycopg2 Example","useCase":"Parameterized in Python.","code":"import psycopg2\n\n# VULNERABLE:\ncur.execute(f\"SELECT * FROM users WHERE email = '{user_input}'\")\n\n# SAFE — parameterized:\ncur.execute(\"SELECT * FROM users WHERE email = %s\", (user_input,))","description":"Python psycopg2 parameterized query with %s placeholder."},{"title":"SQL Injection in Action","useCase":"How authentication is bypassed.","code":"-- Normal query:\nSELECT * FROM users WHERE email = 'alice@x.com' AND password = 'secret123';\n\n-- Injection: Login with email:\n  ' OR 1=1 --\n\n-- Query becomes:\nSELECT * FROM users WHERE email = '' OR 1=1 --' AND password = 'anything';\n\n-- 1=1 is always true, -- comments out password check\n-- Returns first user — logged in as that user!","description":"Classic authentication bypass using OR 1=1 injection."},{"title":"Union-Based Injection","useCase":"Extracting data from other tables.","code":"-- Vulnerable query:\nSELECT name, price FROM products WHERE id = ' + userInput\n\n-- Injection: id = 1 UNION SELECT username, password FROM admins\n\n-- Query becomes:\nSELECT name, price FROM products WHERE id = 1\nUNION\nSELECT username, password FROM admins;\n\n-- Returns product data + admin credentials!","description":"UNION injection extracts data from unrelated tables."},{"title":"Input Validation Defense","useCase":"Whitelist approach.","code":"// Whitelist validation (Node.js):\nfunction validateUserId(input) {\n  const num = parseInt(input, 10);\n  if (isNaN(num) || num < 1) {\n    throw new Error(\"Invalid user ID\");\n  }\n  return num;\n}\n\n// Safe query with validated input:\nconst id = validateUserId(req.params.id);\nconst result = await client.query(\"SELECT * FROM users WHERE id = $1\", [id]);","description":"Input validation as an additional defense layer beyond parameterization."}],"mcqQuestions":[{"question":"What is SQL injection?","options":["A performance issue","A code injection attack","A data type error","A connection problem"],"answer":1,"explanation":"SQL injection is a code injection attack through malicious input."},{"question":"What is the primary prevention?","options":["Input validation","Parameterized queries","Encryption","Firewalls"],"answer":1,"explanation":"Parameterized queries (prepared statements) are the primary defense."},{"question":"What does \\' OR 1=1 -- do?","options":["Returns no rows","Makes WHERE always true","Deletes the table","Shows an error"],"answer":1,"explanation":"OR 1=1 makes the condition always true; -- comments out the rest."},{"question":"Can ORMs be vulnerable?","options":["Never","Only raw queries can be","Always safe","Depends on database"],"answer":1,"explanation":"ORMs are safe by default but raw queries and some bypasses can be vulnerable."},{"question":"What is least privilege?","options":["Minimum permissions needed","Maximum permissions","No permissions","Admin access"],"answer":0,"explanation":"Least privilege means the minimum permissions necessary for the application."},{"question":"What does -- do in SQL?","options":["Comments out rest of query","Ends the query","Adds condition","Drops table"],"answer":0,"explanation":"-- is a SQL comment that removes the rest of the query."}]};
TOPICS_DATA["sql"]["sql-backup-restore"] = {"id":"sql-backup-restore","title":"Backup & Restore","difficulty":"intermediate","estimatedMinutes":25,"tldr":["PostgreSQL backup tools: pg_dump (single database, custom/plain/tar format), pg_dumpall (all databases, globals).","pg_dump creates consistent snapshots without blocking reads. For zero-downtime backups, use pg_basebackup or replication.","pg_restore restores from custom/directory/tar format. psql runs plain SQL dumps. Point-in-time recovery (PITR) uses WAL archives.","Backup strategies: full weekly + daily incremental + continuous WAL archiving for PITR."],"laymanDefinition":"Database backups are like insurance for your data. pg_dump is like taking a photo of your database at a specific moment. WAL archiving is like keeping a detailed diary of every single change — allowing you to \"rewind\" to any point in time.","deepDive":[{"heading":"pg_dump (Logical Backup)","text":"pg_dump -d dbname > backup.sql — plain SQL. pg_dump -Fc -d dbname > backup.dump — custom format (compressed, restorable selectively). pg_dump -Fd -d dbname backup_dir — directory format (parallel)."},{"heading":"pg_dumpall","text":"pg_dumpall > all.sql — dumps all databases plus global objects (roles, tablespaces). pg_dumpall --globals-only > globals.sql — roles and tablespaces only. Restore with psql -f all.sql postgres."},{"heading":"pg_restore","text":"pg_restore -d dbname backup.dump — restore custom format. --clean — drop existing objects before restore. --jobs=n — parallel restore. -t table — restore single table. -l — list contents."},{"heading":"Physical Backup and PITR","text":"pg_basebackup — takes physical copy of entire cluster. Enable WAL archiving: archive_mode=on, archive_command. Restore: configure restore_command, create recovery.signal. Replay WAL to desired point in time (PITR)."},{"heading":"Backup Automation","text":"cron job for pg_dump. pgBackRest or barman for enterprise backup management. Test restores regularly. 3-2-1 rule: 3 copies, 2 media types, 1 offsite."}],"interviewAnswer":"Regular backups and tested restore procedures are non-negotiable for production databases. Logical backups (pg_dump) are portable and human-readable. Physical backups (pg_basebackup + WAL) enable PITR and faster restores for large databases.","interviewQuestions":[{"question":"What does pg_dump do?","answer":"Creates a logical backup of a single PostgreSQL database. Can output plain SQL, custom, directory, or tar format."},{"question":"What is the difference between pg_dump and pg_dumpall?","answer":"pg_dump backs up a single database. pg_dumpall backs up all databases and global objects (roles, tablespaces)."},{"question":"What is the -Fc format in pg_dump?","answer":"Custom format — compressed, supports selective restore, parallel restore. Recommended for most backups."},{"question":"How do you restore a custom format dump?","answer":"pg_restore -d dbname backup.dump. With --clean to drop existing objects first."},{"question":"What is PITR?","answer":"Point-in-Time Recovery — the ability to restore a database to any moment in time using base backup + WAL archives."},{"question":"What is WAL archiving?","answer":"Continuous archiving of Write-Ahead Log (WAL) files that record every database change. Required for PITR."},{"question":"How do you restore a plain SQL dump?","answer":"psql -d dbname -f backup.sql. Plain SQL dumps are universal but can only restore the entire database."},{"question":"What is pg_basebackup?","answer":"Creates a physical base backup of the entire PostgreSQL cluster. Used for replication and PITR setup."},{"question":"How often should you backup?","answer":"Full backup weekly, incremental daily, continuous WAL archiving. Regular restore testing is more important than backup frequency."},{"question":"What is the 3-2-1 backup rule?","answer":"3 copies of data, 2 different media types, 1 copy offsite."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Backup & Restore</text><rect x=\"10\" y=\"35\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"65\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">pg_dump</text><text x=\"65\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Logical backup</text><rect x=\"10\" y=\"65\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"65\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">pg_dumpall</text><text x=\"65\" y=\"93\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">All databases</text><rect x=\"10\" y=\"95\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"65\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">pg_restore</text><text x=\"65\" y=\"123\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Restore dump</text><rect x=\"10\" y=\"125\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"65\" y=\"141\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">WAL Archive</text><text x=\"65\" y=\"153\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Continuous</text><rect x=\"10\" y=\"155\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1\"/><text x=\"65\" y=\"171\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">PITR</text><text x=\"65\" y=\"183\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Point-in-time</text><line x1=\"120\" y1=\"48\" x2=\"150\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"78\" x2=\"150\" y2=\"78\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"108\" x2=\"150\" y2=\"108\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"138\" x2=\"150\" y2=\"138\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"168\" x2=\"150\" y2=\"168\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"35\" width=\"220\" height=\"155\" rx=\"4\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1\"/><text x=\"270\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Backup & Restore</text><text x=\"270\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Logical and physical backups, WAL archiving, and PITR strategies.</text><text x=\"240\" y=\"220\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Backup & Restore: pg_dump, pg_restore, WAL archiving, and Point-in-Time Recovery.</text></svg>","codeExamples":[{"title":"pg_dump Examples","useCase":"Common backup commands.","code":"# Plain SQL format (portable)\npg_dump -h localhost -U postgres mydb > mydb_backup.sql\n\n# Custom format (compressed, selective restore)\npg_dump -Fc -h localhost -U postgres mydb > mydb_backup.dump\n\n# Directory format (parallel dump)\npg_dump -Fd -j 4 -h localhost -U postgres mydb -f mydb_backup_dir/","description":"Different pg_dump formats for different needs."},{"title":"pg_restore Examples","useCase":"Restoring backups.","code":"# Restore entire custom dump\npg_restore -d mydb --clean mydb_backup.dump\n\n# Restore single table\npg_restore -d mydb -t employees mydb_backup.dump\n\n# List contents of a dump\npg_restore -l mydb_backup.dump\n\n# Parallel restore\npg_restore -d mydb -j 4 mydb_backup.dump","description":"Selective restore and parallel restore with pg_restore."},{"title":"WAL Archiving Setup","useCase":"Configure for PITR.","code":"# postgresql.conf\nwal_level = replica\narchive_mode = on\narchive_command = 'cp %p /archive/%f'\n\n# Take base backup\npg_basebackup -D /backup/base -Ft -z\n\n# Recovery: create recovery.signal in data directory\n# and set restore_command = 'cp /archive/%f %p'\n# in postgresql.conf","description":"WAL archiving setup for continuous backup and point-in-time recovery."},{"title":"Automated Backup Script","useCase":"Simple cron backup routine.","code":"#!/bin/bash\nBACKUP_DIR=\"/backups/$(date +%Y-%m-%d)\"\nmkdir -p $BACKUP_DIR\n\n# Full backup\npg_dump -Fc mydb > $BACKUP_DIR/mydb.dump\n\n# Globals only\npg_dumpall --globals-only > $BACKUP_DIR/globals.sql\n\n# Remove backups older than 30 days\nfind /backups/* -mtime +30 -exec rm -rf {} \\;","description":"Automated daily backup script with rotation."},{"title":"Testing Restores","useCase":"Verify backup integrity.","code":"# Create a test database\ncreatedb test_restore\n\n# Restore into test database\npg_restore -d test_restore mydb_backup.dump\n\n# Verify data integrity\npsql -d test_restore -c \"SELECT COUNT(*) FROM employees;\"\npsql -d test_restore -c \"SELECT * FROM employees ORDER BY id DESC LIMIT 5;\"\n\n# Drop test database\ndropdb test_restore","description":"Regular restore testing is essential — a backup is only as good as its last successful restore."}],"mcqQuestions":[{"question":"What does pg_dump do?","options":["Backs up a single database","Backs up all databases","Restores a backup","Creates a new database"],"answer":0,"explanation":"pg_dump creates a logical backup of one database."},{"question":"What format supports selective restore?","options":["Plain SQL","Custom (-Fc)","Tar","All formats"],"answer":1,"explanation":"Custom format supports restoring individual tables selectively."},{"question":"What enables point-in-time recovery?","options":["pg_dump","WAL archiving","pg_dumpall","Regular backups"],"answer":1,"explanation":"WAL archiving enables PITR by recording every change."},{"question":"What command creates custom format backup?","options":["pg_dump -Fc","pg_dump -Fp","pg_dumpall","pg_basebackup"],"answer":0,"explanation":"pg_dump -Fc creates custom format backup."},{"question":"What does pg_restore --clean do?","options":["Removes old backups","Drops existing objects before restore","Cleans temporary files","Optimizes database"],"answer":1,"explanation":"--clean drops existing database objects before restoring."},{"question":"How do you restore a plain SQL dump?","options":["pg_restore","psql -f","pg_dump -r","psql -r"],"answer":1,"explanation":"Use psql -f backup.sql to restore a plain SQL dump."}]};
TOPICS_DATA["sql"]["sql-users-permissions"] = {"id":"sql-users-permissions","title":"Users, Roles & Permissions","difficulty":"intermediate","estimatedMinutes":25,"tldr":["PostgreSQL manages access through roles (which can act as users or groups). Permissions are granted at database, schema, table, and column levels.","CREATE ROLE creates a role. LOGIN attribute allows login. CREATE USER is equivalent to CREATE ROLE WITH LOGIN.","GRANT assigns privileges. REVOKE removes privileges. Privileges: SELECT, INSERT, UPDATE, DELETE, ALL, and more.","Row-Level Security (RLS) enables fine-grained per-row access control based on policy expressions."],"laymanDefinition":"Roles and permissions are like building security. CREATE ROLE is getting a master key. GRANT is deciding which doors each person can open. RLS is like a security guard who checks if a person is allowed to see specific files, not just enter the room.","deepDive":[{"heading":"Roles as Users and Groups","text":"CREATE ROLE alice LOGIN PASSWORD \\'secure\\'; — user-level role. CREATE ROLE developers; GRANT developers TO alice; — group-level role. Roles can be nested (role groups containing other roles). Roles own database objects."},{"heading":"Database-Level Privileges","text":"GRANT CONNECT, CREATE ON DATABASE dbname TO role; — connect and create schema permissions. GRANT ALL ON DATABASE — all permissions. Default: public schema grants CREATE to PUBLIC (usually revoked in production)."},{"heading":"Schema and Table Permissions","text":"GRANT USAGE ON SCHEMA public TO role; — schema access. GRANT SELECT, INSERT, UPDATE ON table TO role; — table operations. GRANT ALL ON ALL TABLES IN SCHEMA public TO role; — all tables in schema."},{"heading":"Column-Level Permissions","text":"GRANT SELECT (name, email) ON users TO role; — only specific columns visible. GRANT UPDATE (status) ON orders TO role; — can only update specific columns. Useful for hiding sensitive data (salary columns)."},{"heading":"Row-Level Security (RLS)","text":"ALTER TABLE employees ENABLE ROW LEVEL SECURITY; CREATE POLICY emp_policy ON employees USING (department = current_setting(\\'app.dept\\')); — users only see rows matching their department. Requires superuser or table owner."}],"interviewAnswer":"Proper permission management is essential for security and compliance. Use roles for access groups, grant minimal privileges, and consider RLS for multi-tenant applications. Regularly audit permissions with \\dp or information_schema.","interviewQuestions":[{"question":"What is a role in PostgreSQL?","answer":"An entity that can own objects and hold privileges. Can act as a user (with LOGIN) or a group (membership)."},{"question":"What is the difference between CREATE ROLE and CREATE USER?","answer":"CREATE USER is equivalent to CREATE ROLE WITH LOGIN. CREATE ROLE does not include LOGIN by default."},{"question":"How do you grant privileges?","answer":"GRANT privilege ON object TO role; Example: GRANT SELECT ON employees TO app_user;"},{"question":"How do you remove privileges?","answer":"REVOKE privilege ON object FROM role; Example: REVOKE DELETE ON employees FROM app_user;"},{"question":"What are the main privilege types?","answer":"SELECT, INSERT, UPDATE, DELETE, TRUNCATE, REFERENCES, TRIGGER, CREATE, CONNECT, TEMPORARY, EXECUTE, USAGE, ALL."},{"question":"What is Row-Level Security?","answer":"RLS limits which rows a user can see or modify based on a policy expression. Enables per-row access control."},{"question":"How do you enable RLS?","answer":"ALTER TABLE table_name ENABLE ROW LEVEL SECURITY; Then CREATE POLICY ... USING (condition)."},{"question":"What is the PUBLIC role?","answer":"A special role that represents all database users. Default privileges often grant access to PUBLIC."},{"question":"What does GRANT USAGE ON SCHEMA do?","answer":"Allows accessing objects within the schema. Required before granting table-level permissions."},{"question":"How do you view privileges?","answer":"\\dp table_name (psql), \\du for roles, information_schema.table_privileges for programmatic access."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Users, Roles & Permissions</text><rect x=\"10\" y=\"35\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"60\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">CREATE ROLE</text><text x=\"60\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">User/group</text><rect x=\"10\" y=\"65\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"60\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">GRANT</text><text x=\"60\" y=\"93\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Add perms</text><rect x=\"10\" y=\"95\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"60\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">REVOKE</text><text x=\"60\" y=\"123\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Remove perms</text><rect x=\"10\" y=\"125\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"60\" y=\"141\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">RLS</text><text x=\"60\" y=\"153\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Row security</text><line x1=\"110\" y1=\"48\" x2=\"140\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"110\" y1=\"78\" x2=\"140\" y2=\"78\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"110\" y1=\"108\" x2=\"140\" y2=\"108\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"110\" y1=\"138\" x2=\"140\" y2=\"138\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"150\" y=\"35\" width=\"230\" height=\"130\" rx=\"4\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1\"/><text x=\"265\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Users & Permissions</text><text x=\"265\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Roles, privileges, schemas, columns, and row-level security for access control.</text><text x=\"240\" y=\"195\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Users & Permissions: Role-based access control from database level to row level.</text></svg>","codeExamples":[{"title":"Creating Roles and Groups","useCase":"User and group management.","code":"-- Create group role\nCREATE ROLE engineers NOLOGIN;\n\n-- Create user roles\nCREATE ROLE alice LOGIN PASSWORD 'secure123' IN ROLE engineers;\nCREATE ROLE bob LOGIN PASSWORD 'pass456' IN ROLE engineers;\n\n-- Grant permissions to group\nGRANT SELECT, INSERT ON employees TO engineers;","description":"Group roles simplify permission management — add users to groups rather than granting individually."},{"title":"Schema and Table Grants","useCase":"Controlled access patterns.","code":"-- Application user needs minimal access\nCREATE ROLE app_user LOGIN PASSWORD 'app_pass';\n\n-- Schema access\nGRANT USAGE ON SCHEMA public TO app_user;\n\n-- Table permissions (not all tables)\nGRANT SELECT, INSERT, UPDATE ON orders TO app_user;\nGRANT SELECT ON products TO app_user;\n-- No access to salaries, audit logs, etc.\n\n-- Default privileges for future tables\nALTER DEFAULT PRIVILEGES IN SCHEMA public\nGRANT SELECT ON TABLES TO app_user;","description":"Minimal permissions for application user — only what is needed."},{"title":"Column-Level Security","useCase":"Hide sensitive columns.","code":"-- Managers can see salaries:\nCREATE ROLE managers LOGIN PASSWORD 'mgmt_pass';\nGRANT SELECT ON employees TO managers;\n\n-- HR staff see only non-sensitive columns:\nCREATE ROLE hr_staff LOGIN PASSWORD 'hr_pass';\nGRANT SELECT (id, name, email, department, hire_date)\n  ON employees TO hr_staff;\n\n-- hr_staff query:\nSELECT id, name, email FROM employees; -- works\nSELECT salary FROM employees; -- ERROR: permission denied","description":"Column-level GRANT restricts access to specific columns."},{"title":"Row-Level Security Setup","useCase":"Multi-tenant isolation.","code":"-- Enable RLS on orders table\nALTER TABLE orders ENABLE ROW LEVEL SECURITY;\n\n-- Policy: users only see their own orders\nCREATE POLICY user_orders ON orders\nUSING (customer_id = current_setting('app.user_id')::INT);\n\n-- Bypass RLS for admins\nCREATE POLICY admin_all ON orders\nFOR ALL USING (current_setting('app.role') = 'admin');","description":"RLS ensures users can only access rows belonging to their organization or themselves."},{"title":"Revoking Dangerous Privileges","useCase":"Secure production setup.","code":"-- Remove public create privilege\nREVOKE CREATE ON SCHEMA public FROM PUBLIC;\n\n-- App user should not modify schema\nREVOKE CREATE ON SCHEMA public FROM app_user;\n\n-- App user should not delete\nREVOKE DELETE, TRUNCATE ON ALL TABLES IN SCHEMA public FROM app_user;\n\n-- Review privileges\nSELECT grantee, privilege_type\nFROM information_schema.table_privileges\nWHERE table_name = 'employees';","description":"Production hardening — remove dangerous privileges from application users."}],"mcqQuestions":[{"question":"What creates a login-capable role?","options":["CREATE ROLE name LOGIN","CREATE USER name","CREATE GROUP name","Both A and B"],"answer":3,"explanation":"CREATE USER and CREATE ROLE WITH LOGIN both create login-capable roles."},{"question":"What does GRANT do?","options":["Removes permissions","Adds permissions","Creates users","Drops roles"],"answer":1,"explanation":"GRANT assigns privileges to roles."},{"question":"What does RLS stand for?","options":["Row-Level Security","Role-Level Security","Remote Login Service","Relational Lock System"],"answer":0,"explanation":"RLS is Row-Level Security — per-row access control."},{"question":"What privilege allows schema access?","options":["SELECT","USAGE","CREATE","ALL"],"answer":1,"explanation":"USAGE ON SCHEMA allows accessing objects within the schema."},{"question":"What is the special PUBLIC role?","options":["A superuser","All database users","Application users","Database owner"],"answer":1,"explanation":"PUBLIC represents all current and future database users."},{"question":"How do you bypass RLS?","options":["WITH ADMIN OPTION","BYPASSRLS attribute","SUPERUSER","Both B and C"],"answer":3,"explanation":"BYPASSRLS role attribute or superuser status bypasses RLS."}]};
TOPICS_DATA["sql"]["sql-upsert"] = {"id":"sql-upsert","title":"UPSERT & MERGE","difficulty":"intermediate","estimatedMinutes":20,"tldr":["UPSERT = INSERT + UPDATE (insert or update if already exists). PostgreSQL uses INSERT ... ON CONFLICT DO UPDATE.","ON CONFLICT specifies the conflict target (unique constraint/index) and the action: DO NOTHING or DO UPDATE.","MERGE (SQL standard, PostgreSQL 15+) combines INSERT, UPDATE, DELETE in a single statement based on a source/target match.","UPSERT is atomic and concurrent-safe — no race conditions between check and insert/update."],"laymanDefinition":"UPSERT is like \"save or update\" in a to-do app. When you save a task, if it already exists (same ID), update it instead. ON CONFLICT is saying \"if this unique value already exists, here is what to do instead of erroring\".","deepDive":[{"heading":"INSERT ... ON CONFLICT DO NOTHING","text":"INSERT INTO products (id, name) VALUES (1, \\'Laptop\\') ON CONFLICT (id) DO NOTHING; — inserts if no conflict, silently skips if conflict. Useful for idempotent inserts."},{"heading":"INSERT ... ON CONFLICT DO UPDATE","text":"INSERT INTO ... VALUES (...) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, updated_at = NOW(). EXCLUDED refers to the values that would have been inserted. Can reference both original table columns and EXCLUDED pseudo-table."},{"heading":"Conflict Target","text":"ON CONFLICT (column) — specify the unique column/index. ON CONFLICT ON CONSTRAINT constraint_name — specify constraint name. ON CONFLICT WHERE condition — partial unique indexes. Without target, DO UPDATE is not allowed."},{"heading":"MERGE (PG 15+)","text":"MERGE INTO target USING source ON condition WHEN MATCHED THEN UPDATE SET ... WHEN NOT MATCHED THEN INSERT .... Also supports WHEN MATCHED THEN DELETE. More flexible than ON CONFLICT but more verbose."},{"heading":"Use Cases","text":"Importing data with upserts (CSV imports, ETL). Session management (insert or update last seen). Inventory updates (insert new product or update stock). Counter tables (insert or increment)."}],"interviewAnswer":"UPSERT is essential for any application that imports data or handles concurrent inserts/updates. ON CONFLICT DO UPDATE is the standard PostgreSQL approach — it is atomic, fast, and handles race conditions automatically.","interviewQuestions":[{"question":"What is UPSERT?","answer":"INSERT + UPDATE — insert a row, or if a conflict occurs (unique violation), update the existing row."},{"question":"What is the PostgreSQL UPSERT syntax?","answer":"INSERT INTO table VALUES (...) ON CONFLICT (column) DO UPDATE SET column = EXCLUDED.column;"},{"question":"What does EXCLUDED refer to?","answer":"A pseudo-table containing the values that would have been inserted. EXCLUDED.column refers to the proposed new value."},{"question":"What does ON CONFLICT DO NOTHING do?","answer":"Inserts if no conflict occurs. If a conflict occurs, silently does nothing (no error)."},{"question":"What is the conflict target?","answer":"The unique column, constraint, or index that defines what constitutes a conflict."},{"question":"What is MERGE?","answer":"A SQL standard statement (PG 15+) that conditionally inserts, updates, or deletes based on source/target matching."},{"question":"What is the difference between MERGE and ON CONFLICT?","answer":"ON CONFLICT is simpler and PostgreSQL-specific. MERGE is more flexible (supports DELETE) but more verbose."},{"question":"Is UPSERT atomic?","answer":"Yes. ON CONFLICT is atomic — no race condition between the check and the insert/update."},{"question":"Can you use WHERE in DO UPDATE?","answer":"Yes: ON CONFLICT DO UPDATE SET column = value WHERE condition. Only updates if the condition is met."},{"question":"When would you use DO NOTHING vs DO UPDATE?","answer":"DO NOTHING: bulk imports where you want to skip duplicates. DO UPDATE: syncing data where you want latest values."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">UPSERT & MERGE</text><rect x=\"10\" y=\"35\" width=\"130\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"75\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">INSERT</text><text x=\"75\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">First attempt</text><line x1=\"140\" y1=\"48\" x2=\"170\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"180\" y=\"35\" width=\"130\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"245\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">ON CONFLICT</text><text x=\"245\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Conflict?</text><line x1=\"180\" y1=\"60\" x2=\"180\" y2=\"80\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"310\" y1=\"48\" x2=\"340\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"10\" y=\"70\" width=\"130\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"75\" y=\"86\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">DO NOTHING</text><text x=\"75\" y=\"98\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Skip</text><rect x=\"180\" y=\"75\" width=\"130\" height=\"25\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"245\" y=\"91\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">DO UPDATE</text><text x=\"245\" y=\"103\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Update</text><rect x=\"350\" y=\"35\" width=\"130\" height=\"80\" rx=\"4\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1\"/><text x=\"415\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">UPSERT</text><text x=\"415\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Insert or Update. Atomic and race-condition-free.</text><text x=\"240\" y=\"160\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">UPSERT & MERGE: Insert or update in one atomic statement without race conditions.</text></svg>","codeExamples":[{"title":"Basic UPSERT","useCase":"Insert or update product.","code":"INSERT INTO products (id, name, price, stock)\nVALUES (101, 'Wireless Mouse', 29.99, 50)\nON CONFLICT (id) DO UPDATE SET\n  name = EXCLUDED.name,\n  price = EXCLUDED.price,\n  stock = products.stock + EXCLUDED.stock,\n  updated_at = NOW();","description":"Inserts new product or adds stock and updates details for existing product."},{"title":"ON CONFLICT DO NOTHING","useCase":"Idempotent inserts.","code":"-- Insert if not exists, skip if exists\nINSERT INTO user_sessions (user_id, session_token, created_at)\nVALUES (42, 'abc123', NOW())\nON CONFLICT (user_id) DO NOTHING;\n\n-- Returns INSERT 0 0 if skipped,\n-- INSERT 0 1 if inserted","description":"Prevents duplicate session creation without raising errors."},{"title":"Using EXCLUDED","useCase":"Reference proposed values.","code":"INSERT INTO counters (page, views, last_viewed)\nVALUES ('/home', 1, NOW())\nON CONFLICT (page) DO UPDATE SET\n  views = counters.views + EXCLUDED.views,\n  last_viewed = EXCLUDED.last_viewed;","description":"EXCLUDED references the proposed values; table name references existing values."},{"title":"MERGE Statement (PG 15+)","useCase":"Full-featured merge.","code":"MERGE INTO products p\nUSING (VALUES (101, 'Mouse', 25.00)) AS s(id, name, price)\nON p.id = s.id\nWHEN MATCHED THEN UPDATE SET\n  name = s.name, price = s.price, updated_at = NOW()\nWHEN NOT MATCHED THEN INSERT (id, name, price)\n  VALUES (s.id, s.name, s.price);","description":"MERGE provides standard SQL syntax with WHEN MATCHED / NOT MATCHED clauses."},{"title":"Conditional UPSERT","useCase":"Update only certain conditions.","code":"INSERT INTO orders (id, status, amount, updated_at)\nVALUES (5001, 'shipped', 150.00, NOW())\nON CONFLICT (id) DO UPDATE SET\n  status = EXCLUDED.status,\n  updated_at = NOW()\nWHERE orders.status != 'cancelled';\n\n-- Only updates if the existing order is not cancelled","description":"Conditional DO UPDATE prevents overwriting certain states (e.g., cancelled orders)."}],"mcqQuestions":[{"question":"What does UPSERT stand for?","options":["Update + Select","Insert + Update","Union + Select","Unique + Insert"],"answer":1,"explanation":"UPSERT = INSERT + UPDATE (insert or update)."},{"question":"What PostgreSQL feature enables UPSERT?","options":["MERGE","ON CONFLICT","UPSERT keyword","REPLACE"],"answer":1,"explanation":"INSERT ... ON CONFLICT is the PostgreSQL UPSERT mechanism."},{"question":"What does EXCLUDED represent?","options":["Existing row data","Proposed new values","Excluded columns","Error data"],"answer":1,"explanation":"EXCLUDED refers to the values that would have been inserted."},{"question":"What does ON CONFLICT DO NOTHING do?","options":["Errors on conflict","Skips silently on conflict","Updates on conflict","Deletes on conflict"],"answer":1,"explanation":"DO NOTHING skips the insert silently on conflict without error."},{"question":"When was MERGE added to PostgreSQL?","options":["PG 10","PG 12","PG 14","PG 15"],"answer":3,"explanation":"MERGE was added in PostgreSQL 15."},{"question":"Is UPSERT atomic?","options":["Yes","No","Depends on index","Only with DO NOTHING"],"answer":0,"explanation":"ON CONFLICT is atomic — no race conditions."}]};
TOPICS_DATA["sql"]["sql-sequences"] = {"id":"sql-sequences","title":"Sequences & Identity","difficulty":"beginner","estimatedMinutes":15,"tldr":["Sequences are database objects that generate unique numeric values, typically used for auto-incrementing primary keys.","PostgreSQL: CREATE SEQUENCE, SERIAL (old), GENERATED AS IDENTITY (new, standard).","SERIAL is a shorthand for creating a sequence and setting a DEFAULT. GENERATED AS IDENTITY is the SQL standard and more robust.","Sequences can be shared across tables, have min/max values, cycle, cache, and be customized."],"laymanDefinition":"A sequence is like a ticket dispenser at a deli counter. Every time you pull a ticket, you get the next number. One person gets #42, the next gets #43. Sequences guarantee unique numbers even when multiple people (users) are taking tickets simultaneously.","deepDive":[{"heading":"SERIAL Pseudo-Type","text":"id SERIAL PRIMARY KEY — creates integer column with auto-incrementing sequence. SERIAL = INT + DEFAULT nextval(\\'table_id_seq\\'). BIGSERIAL for bigint. SMALLSERIAL for smallint. Cannot alter the sequence behavior."},{"heading":"GENERATED AS IDENTITY (PG 10+)","text":"id INT GENERATED ALWAYS AS IDENTITY — SQL standard. GENERATED BY DEFAULT — allows manual inserts. ALWAYS prevents manual override (cannot INSERT explicit value). BY DEFAULT allows manual values. Preferred over SERIAL."},{"heading":"Sequence Operations","text":"nextval(\\'seq\\') — get next value. currval(\\'seq\\') — current value in session. setval(\\'seq\\', n) — set current value. ALTER SEQUENCE — change min/max/cache/cycle. Sequence values are transaction-independent (cannot be rolled back)."},{"heading":"Shared Sequences","text":"Multiple tables can share one sequence: CREATE SEQUENCE global_id; DEFAULT nextval(\\'global_id\\') in multiple tables. Useful for global unique IDs across tables. Cannot be used with SERIAL (auto-creates per-table sequence)."},{"heading":"Sequence Gaps","text":"Sequences generate unique numbers but not gapless. Gaps occur from: ROLLBACK (values consumed but not rolled back), cache losses (server crash), concurrent transactions. For gapless sequences, use a counter table with transactions."}],"interviewAnswer":"Sequences are the standard way to generate unique identifiers in PostgreSQL. GENERATED AS IDENTITY is the modern, standard-conforming approach. SERIAL is legacy but widely used. Neither guarantees gapless numbers — only uniqueness.","interviewQuestions":[{"question":"What is a sequence?","answer":"A database object that generates a unique numeric value each time nextval() is called."},{"question":"What is the difference between SERIAL and GENERATED AS IDENTITY?","answer":"SERIAL creates a sequence + DEFAULT. GENERATED AS IDENTITY (PG 10+) is SQL standard, more robust, supports ALWAYS/BY DEFAULT."},{"question":"What does nextval() do?","answer":"Advances the sequence to the next value and returns it. Cannot be rolled back."},{"question":"What does currval() do?","answer":"Returns the current value of the sequence for this session. Returns the last nextval() called."},{"question":"What does setval() do?","answer":"Sets the sequence\\'s current value (or next value depending on third parameter)."},{"question":"Can sequences roll back?","answer":"No. Once nextval() is called, the value is consumed even if the transaction rolls back. This prevents blocking concurrent inserts."},{"question":"What is the default increment for a sequence?","answer":"1. Can be changed with ALTER SEQUENCE ... INCREMENT BY n."},{"question":"Can multiple tables share a sequence?","answer":"Yes. Create a standalone sequence and reference it in DEFAULT clauses of multiple tables."},{"question":"What is a sequence cache?","answer":"Pre-allocates sequence values in memory for performance. Default cache is 1. Higher cache improves speed but loses more values on crash."},{"question":"How do you reset a sequence?","answer":"ALTER SEQUENCE seq_name RESTART WITH n; or setval(\\'seq_name\\', n, false);"}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Sequences & Identity</text><rect x=\"10\" y=\"35\" width=\"120\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"70\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">CREATE SEQUENCE</text><text x=\"70\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Standalone</text><rect x=\"10\" y=\"65\" width=\"120\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"70\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">SERIAL</text><text x=\"70\" y=\"93\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Auto ID</text><rect x=\"10\" y=\"95\" width=\"120\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"70\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">IDENTITY</text><text x=\"70\" y=\"123\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Standard</text><rect x=\"10\" y=\"125\" width=\"120\" height=\"25\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"70\" y=\"141\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">nextval</text><text x=\"70\" y=\"153\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Get next</text><rect x=\"10\" y=\"155\" width=\"120\" height=\"25\" rx=\"4\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1\"/><text x=\"70\" y=\"171\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Cache</text><text x=\"70\" y=\"183\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Performance</text><line x1=\"130\" y1=\"48\" x2=\"160\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"130\" y1=\"78\" x2=\"160\" y2=\"78\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"130\" y1=\"108\" x2=\"160\" y2=\"108\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"130\" y1=\"138\" x2=\"160\" y2=\"138\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"130\" y1=\"168\" x2=\"160\" y2=\"168\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"170\" y=\"35\" width=\"210\" height=\"155\" rx=\"4\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1\"/><text x=\"275\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Sequences & Identity</text><text x=\"275\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Auto-incrementing unique values for primary keys and identifiers.</text><text x=\"240\" y=\"220\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Sequences & Identity: Auto-incrementing unique ID generation for primary keys.</text></svg>","codeExamples":[{"title":"SERIAL vs IDENTITY Comparison","useCase":"Different syntax approaches.","code":"-- SERIAL (legacy approach)\nCREATE TABLE products_serial (\n  id SERIAL PRIMARY KEY,\n  name VARCHAR(100)\n);\n\n-- GENERATED ALWAYS (modern approach)\nCREATE TABLE products_identity (\n  id INT GENERATED ALWAYS AS IDENTITY PRIMARY KEY,\n  name VARCHAR(100)\n);\n\n-- GENERATED BY DEFAULT (allow manual IDs)\nCREATE TABLE products_default (\n  id INT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,\n  name VARCHAR(100)\n);","description":"SERIAL vs GENERATED AS IDENTITY — the modern approach is preferred."},{"title":"Custom Sequence","useCase":"Standalone sequence usage.","code":"CREATE SEQUENCE order_number_seq\n  START WITH 10000\n  INCREMENT BY 1\n  MINVALUE 10000\n  MAXVALUE 99999\n  CYCLE;  -- wrap around when max reached\n\nCREATE TABLE orders (\n  order_number INT DEFAULT nextval('order_number_seq') PRIMARY KEY,\n  customer_id INT,\n  total DECIMAL(10,2)\n);\n\nINSERT INTO orders (customer_id, total) VALUES (42, 150.00);\n-- order_number is auto-populated: 10000","description":"Custom sequence with specific range and CYCLE behavior."},{"title":"Shared Sequence Across Tables","useCase":"Global unique IDs.","code":"CREATE SEQUENCE global_id_seq;\n\nCREATE TABLE users (\n  id INT DEFAULT nextval('global_id_seq') PRIMARY KEY,\n  name VARCHAR(100)\n);\n\nCREATE TABLE products (\n  id INT DEFAULT nextval('global_id_seq') PRIMARY KEY,\n  name VARCHAR(100)\n);\n\n-- All IDs are unique across both tables\n-- Useful for audit logs referencing any entity","description":"Shared sequence ensures globally unique IDs across multiple tables."},{"title":"Sequence Operations","useCase":"Managing sequences.","code":"-- View current value\nSELECT currval('products_id_seq');\n\n-- Get next value without inserting\nSELECT nextval('products_id_seq');\n\n-- Reset sequence\nSELECT setval('products_id_seq', 1000);\n\n-- Alter sequence properties\nALTER SEQUENCE products_id_seq INCREMENT BY 10 CACHE 20;","description":"Sequence management functions for inspection and modification."},{"title":"Handling Gaps","useCase":"Understanding why gaps happen.","code":"-- Gap example:\nBEGIN;\nINSERT INTO products (name) VALUES ('Laptop'); -- gets id=1\nROLLBACK; -- id=1 is consumed\n\nBEGIN;\nINSERT INTO products (name) VALUES ('Phone'); -- gets id=2\nCOMMIT;\n\n-- Table has: id=2 (no id=1)\n-- Gap occurred because id=1 was consumed and rolled back","description":"Understanding sequence gaps — rollback, cache, and concurrent transactions cause gaps."}],"mcqQuestions":[{"question":"What does SERIAL do?","options":["Creates a unique index","Creates auto-increment column","Creates a sequence only","Creates a primary key"],"answer":1,"explanation":"SERIAL creates an auto-incrementing integer column with a backing sequence."},{"question":"What is GENERATED ALWAYS?","options":["Allows manual values","Prevents manual values","Creates a sequence","Drops a table"],"answer":1,"explanation":"GENERATED ALWAYS prevents inserting explicit values — only the system generates IDs."},{"question":"What function gets the next sequence value?","options":["currval","nextval","setval","lastval"],"answer":1,"explanation":"nextval() advances and returns the next sequence value."},{"question":"Can sequence values be rolled back?","options":["Yes","No","Only with savepoints","Depends on configuration"],"answer":1,"explanation":"Sequence values persist even if the transaction rolls back."},{"question":"What is the purpose of sequence cache?","options":["Increases uniqueness","Improves performance","Reduces gaps","Enables rollback"],"answer":1,"explanation":"Cache pre-allocates sequence values for better concurrent performance."},{"question":"Which is the modern PostgreSQL approach?","options":["SERIAL","GENERATED AS IDENTITY","AUTO_INCREMENT","SEQUENCE DEFAULT"],"answer":1,"explanation":"GENERATED AS IDENTITY (PG 10+) is the modern SQL standard approach."}]};
TOPICS_DATA["sql"]["sql-data-types"] = {"id":"sql-data-types","title":"Data Types Deep Dive","difficulty":"intermediate","estimatedMinutes":25,"tldr":["PostgreSQL has the richest set of data types including numeric, character, date/time, boolean, enumerated, geometric, network, bit string, text search, UUID, XML, JSON, array, range, and composite types.","Numeric types: SMALLINT, INTEGER, BIGINT, DECIMAL/NUMERIC (exact), REAL, DOUBLE PRECISION (floating).","Character types: CHAR(n), VARCHAR(n), TEXT (unlimited). TEXT and VARCHAR have same performance in PostgreSQL.","Special types: UUID, INET/CIDR (network), TSVECTOR/TSQUERY (text search), INT4RANGE/NUMRANGE (range)."],"laymanDefinition":"Data types are like different containers in a kitchen. SMALLINT is a shot glass (small), INT is a regular glass, BIGINT is a pitcher. VARCHAR(50) is a labeled container that can hold up to 50 items, TEXT is a giant bin. Using the right container prevents spills and wasted space.","deepDive":[{"heading":"Numeric Types","text":"SMALLINT (2 bytes, -32k to 32k). INTEGER/INT (4 bytes, -2B to 2B). BIGINT (8 bytes). DECIMAL(p,s)/NUMERIC(p,s) — exact precision, perfect for money. REAL (4 bytes float). DOUBLE (8 bytes float). SERIAL/BIGSERIAL — auto-increment integers."},{"heading":"Character Types","text":"CHAR(n) — fixed-length, padded with spaces (wastes space). VARCHAR(n) — variable up to n. TEXT — unlimited. All have same performance in PostgreSQL (unlike other databases). No performance penalty for using TEXT over VARCHAR."},{"heading":"Date/Time Types","text":"DATE — calendar date (no time). TIME — time of day. TIMESTAMP — date + time (no timezone). TIMESTAMPTZ — with timezone (stored as UTC). INTERVAL — duration. Always use TIMESTAMPTZ for application timestamps."},{"heading":"Boolean and Enumerated","text":"BOOLEAN — true/false. Accepts TRUE, \\'t\\', \\'true\\', \\'1\\', \\'yes\\'. FALSE: FALSE, \\'f\\', \\'false\\', \\'0\\', \\'no\\'. CREATE TYPE mood AS ENUM (\\'sad\\', \\'ok\\', \\'happy\\') — enumerated type with ordered values. Cannot add/remove values without ALTER TYPE."},{"heading":"Array, Range, and Composite","text":"INT[] — array type. INT4RANGE — range type with inclusive/exclusive bounds. CREATE TYPE composite AS (a INT, b TEXT) — composite type for table definitions and functions. Custom types extend PostgreSQL\\'s type system."}],"interviewAnswer":"Mastering PostgreSQL data types is crucial for schema design. Choosing the right type impacts storage, performance, and data integrity. PostgreSQL's extensible type system supports custom types, domains, and enumerations.","interviewQuestions":[{"question":"What are the numeric types in PostgreSQL?","answer":"SMALLINT, INTEGER, BIGINT, DECIMAL/NUMERIC, REAL, DOUBLE PRECISION. Plus serial variants."},{"question":"What is the difference between VARCHAR and TEXT?","answer":"No performance difference in PostgreSQL. VARCHAR(n) has a length limit. TEXT is unlimited. Use VARCHAR when length constraint is needed."},{"question":"What is the difference between TIMESTAMP and TIMESTAMPTZ?","answer":"TIMESTAMP stores date/time without timezone. TIMESTAMPTZ stores with timezone, normalized to UTC for storage, displayed in session timezone."},{"question":"What is NUMERIC/DECIMAL used for?","answer":"Exact precision fixed-point numbers. Perfect for monetary values where floating-point rounding is unacceptable."},{"question":"What is an enumerated type?","answer":"A custom type with a fixed set of values: CREATE TYPE status AS ENUM (\\'active\\', \\'inactive\\', \\'pending\\')."},{"question":"What is a range type?","answer":"A type that represents a range of values: INT4RANGE (integer range), DATERANGE (date range), NUMRANGE."},{"question":"What is a composite type?","answer":"A custom type with multiple fields: CREATE TYPE address AS (street TEXT, city TEXT, zip TEXT)."},{"question":"What is UUID type?","answer":"Stores Universally Unique Identifiers. Good for distributed systems. Use gen_random_uuid() to generate."},{"question":"What is INET type?","answer":"Stores IPv4 or IPv6 addresses. Supports subnet operations and sorting. Built-in validation."},{"question":"What is BYTEA?","answer":"Binary data storage. Up to 1GB per value. Two formats: BYTEA (escape) and BYTEA (hex)."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Data Types Deep Dive</text><rect x=\"10\" y=\"35\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"60\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Numeric</text><text x=\"60\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">INT, DECIMAL</text><rect x=\"10\" y=\"65\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"60\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Text</text><text x=\"60\" y=\"93\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">VARCHAR, TEXT</text><rect x=\"10\" y=\"95\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"60\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Date/Time</text><text x=\"60\" y=\"123\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">TIMESTAMP</text><rect x=\"10\" y=\"125\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"60\" y=\"141\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Special</text><text x=\"60\" y=\"153\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">UUID, INET</text><rect x=\"10\" y=\"155\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1\"/><text x=\"60\" y=\"171\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Custom</text><text x=\"60\" y=\"183\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">ENUM, COMPOSITE</text><line x1=\"110\" y1=\"48\" x2=\"140\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"110\" y1=\"78\" x2=\"140\" y2=\"78\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"110\" y1=\"108\" x2=\"140\" y2=\"108\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"110\" y1=\"138\" x2=\"140\" y2=\"138\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"110\" y1=\"168\" x2=\"140\" y2=\"168\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"150\" y=\"35\" width=\"230\" height=\"155\" rx=\"4\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1\"/><text x=\"265\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Data Types Deep Dive</text><text x=\"265\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">PostgreSQL's rich type system: numeric, text, temporal, network, custom types.</text><text x=\"240\" y=\"220\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Data Types: PostgreSQL's extensive type system for precise and efficient data storage.</text></svg>","codeExamples":[{"title":"Choosing the Right Numeric Type","useCase":"Match type to data.","code":"-- Age: SMALLINT (range: -32768 to 32767)\nCREATE TABLE people (age SMALLINT);\n\n-- Population: INTEGER (fits 2 billion)\nCREATE TABLE cities (population INT);\n\n-- Large counter: BIGINT\nCREATE TABLE page_views (count BIGINT);\n\n-- Monetary: DECIMAL (exact precision)\nCREATE TABLE accounts (balance DECIMAL(12,2));\n\n-- Scientific: DOUBLE PRECISION\nCREATE TABLE measurements (value DOUBLE PRECISION);","description":"Choosing the appropriate numeric type for different data ranges and precision needs."},{"title":"UUID as Primary Key","useCase":"Distributed-friendly IDs.","code":"CREATE EXTENSION IF NOT EXISTS pgcrypto;\n\nCREATE TABLE users (\n  id UUID DEFAULT gen_random_uuid() PRIMARY KEY,\n  name VARCHAR(100),\n  email VARCHAR(255)\n);\n\nINSERT INTO users (name, email) VALUES ('Alice', 'alice@x.com');\n-- id = 'a0eebc99-9c0b-4ef8-bb6d-6bb9bd380a11' (random)","description":"UUID primary keys are ideal for distributed systems and avoiding sequential ID guessing."},{"title":"Range Types Usage","useCase":"Date range for bookings.","code":"CREATE TABLE room_bookings (\n  room_id INT,\n  booking_period DATERANGE,\n  EXCLUDE USING gist (room_id WITH =, booking_period WITH &&)\n);\n\nINSERT INTO room_bookings VALUES\n  (101, '[2024-01-01, 2024-01-05)');\n\n-- This will be rejected (overlap):\nINSERT INTO room_bookings VALUES\n  (101, '[2024-01-03, 2024-01-07)');\n-- ERROR: conflicting key","description":"Range types with exclusion constraints prevent overlapping bookings."},{"title":"Enumerated Types","useCase":"Fixed status values.","code":"CREATE TYPE order_status AS ENUM (\n  'pending', 'confirmed', 'shipped', 'delivered', 'cancelled'\n);\n\nCREATE TABLE orders (\n  id INT PRIMARY KEY,\n  status order_status DEFAULT 'pending'\n);\n\nINSERT INTO orders (id, status) VALUES (1, 'pending');\n-- Order respects enum order: pending < confirmed < shipped < delivered","description":"ENUM types enforce valid values and maintain sort order."},{"title":"Network Types","useCase":"Store IP addresses.","code":"CREATE TABLE access_log (\n  ip INET,\n  mac MACADDR,\n  accessed_at TIMESTAMPTZ\n);\n\nINSERT INTO access_log VALUES\n  ('192.168.1.100', '08:00:2b:01:02:03', NOW());\n\n-- Network queries:\nSELECT * FROM access_log\nWHERE ip <<= '192.168.1.0/24'; -- subnet containment","description":"INET and MACADDR types provide built-in validation and network operations."}],"mcqQuestions":[{"question":"Which type is best for monetary values?","options":["FLOAT","DOUBLE","DECIMAL","INTEGER"],"answer":2,"explanation":"DECIMAL/NUMERIC provides exact precision for monetary values."},{"question":"What is the difference between VARCHAR and TEXT in PostgreSQL?","options":["Performance","TEXT is unlimited","VARCHAR is faster","No real difference"],"answer":3,"explanation":"VARCHAR and TEXT have identical performance in PostgreSQL."},{"question":"Which timestamp type stores timezone?","options":["TIMESTAMP","TIMESTAMPTZ","TIMESTAMP WITH LOCAL TZ","All of them"],"answer":1,"explanation":"TIMESTAMPTZ stores timezone-aware timestamps."},{"question":"What is UUID ideal for?","options":["Sequential IDs","Distributed systems","Small tables","Foreign keys"],"answer":1,"explanation":"UUID is ideal for distributed systems where unique IDs must be generated independently."},{"question":"What does ENUM provide?","options":["Unlimited values","Fixed valid values","Faster queries","Smaller storage"],"answer":1,"explanation":"ENUM restricts values to a predefined set."},{"question":"What type stores IP addresses?","options":["TEXT","VARCHAR","INET","IP"],"answer":2,"explanation":"INET provides built-in IP address validation and operations."}]};
TOPICS_DATA["sql"]["sql-partitioning"] = {"id":"sql-partitioning","title":"Table Partitioning","difficulty":"advanced","estimatedMinutes":30,"tldr":["Table partitioning divides a large table into smaller, more manageable pieces called partitions, improving query performance and data management.","Partition methods: RANGE (by date range), LIST (by discrete values), HASH (by hash of a column).","Partition pruning: the query planner skips irrelevant partitions based on the WHERE clause, dramatically reducing I/O.","PostgreSQL supports declarative partitioning (PG 10+) with sub-partitioning and partition maintenance operations."],"laymanDefinition":"Table partitioning is like organizing a giant filing cabinet by year. Instead of searching through 10 years of documents, you open the 2024 drawer. Partition pruning means the database only looks in relevant partitions, making queries much faster.","deepDive":[{"heading":"RANGE Partitioning","text":"PARTITION BY RANGE (created_at). Partitions: FOR VALUES FROM (\\'2024-01-01\\') TO (\\'2024-04-01\\'). Best for time-series data: logs, transactions, historical data. Supports automatic partition creation with pg_partman extension."},{"heading":"LIST Partitioning","text":"PARTITION BY LIST (region). Partitions: FOR VALUES IN (\\'US\\'), FOR VALUES IN (\\'EU\\'). Best for data with discrete categories: regions, departments, status values. Each partition holds matching values."},{"heading":"HASH Partitioning","text":"PARTITION BY HASH (id). Partitions: FOR VALUES WITH (MODULUS 4, REMAINDER 0). Distributes data evenly across N partitions. Best for load balancing and when no natural partition key exists."},{"heading":"Partition Pruning","text":"Automatic: query planner examines WHERE clause and accesses only matching partitions. EXPLAIN shows \"Partitions: excluded=3\" for a 4-partition table when 3 are skipped. Critical for performance on large partitioned tables."},{"heading":"Partition Maintenance","text":"CREATE TABLE ... PARTITION OF — attach new partition. DROP TABLE partition_name — drop old partition (fast, no vacuum). ALTER TABLE ... DETACH PARTITION — detach then drop. REINDEX each partition separately."}],"interviewAnswer":"Table partitioning is essential for managing large tables (100M+ rows). It improves query performance via partition pruning, enables fast data deletion (DROP PARTITION), and simplifies data lifecycle management.","interviewQuestions":[{"question":"What is table partitioning?","answer":"Dividing a large table into smaller physical pieces (partitions) while maintaining a single logical table interface."},{"question":"What are the three partitioning methods?","answer":"RANGE (date ranges), LIST (value lists), HASH (hash distribution)."},{"question":"What is partition pruning?","answer":"The query planner automatically skips partitions that do not match the WHERE conditions, reducing I/O."},{"question":"What is RANGE partitioning best for?","answer":"Time-series data: logs, transactions, sensor data, audit tables. Common: monthly or yearly partitions."},{"question":"What is LIST partitioning best for?","answer":"Discrete categories: regions (\\'US\\', \\'EU\\', \\'APAC\\'), status values, departments."},{"question":"What is HASH partitioning best for?","answer":"Even data distribution when no natural partition key exists. Good for load balancing."},{"question":"How do you add a new partition?","answer":"CREATE TABLE partition_name PARTITION OF main_table FOR VALUES FROM (x) TO (y);"},{"question":"How do you remove old data?","answer":"DROP TABLE partition_name; — much faster than DELETE from a non-partitioned table."},{"question":"Can partitions be indexed?","answer":"Yes. Indexes are created per partition. In PG 11+, indexes on parent are automatically created on new partitions."},{"question":"What are the limitations of partitioning?","answer":"No cross-partition foreign keys. Unique indexes must include the partition key. No global indexes (each partition indexed separately)."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Table Partitioning</text><rect x=\"10\" y=\"35\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"65\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">RANGE</text><text x=\"65\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Date ranges</text><rect x=\"10\" y=\"65\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"65\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">LIST</text><text x=\"65\" y=\"93\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Categories</text><rect x=\"10\" y=\"95\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"65\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">HASH</text><text x=\"65\" y=\"123\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Distribution</text><rect x=\"10\" y=\"125\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"65\" y=\"141\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Pruning</text><text x=\"65\" y=\"153\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Skip parts</text><rect x=\"10\" y=\"155\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1\"/><text x=\"65\" y=\"171\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Maintenance</text><text x=\"65\" y=\"183\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Add/drop</text><line x1=\"120\" y1=\"48\" x2=\"150\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"78\" x2=\"150\" y2=\"78\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"108\" x2=\"150\" y2=\"108\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"138\" x2=\"150\" y2=\"138\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"168\" x2=\"150\" y2=\"168\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"35\" width=\"220\" height=\"155\" rx=\"4\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1\"/><text x=\"270\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Table Partitioning</text><text x=\"270\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Split large tables into smaller pieces for performance and manageability.</text><text x=\"240\" y=\"220\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Table Partitioning: RANGE, LIST, HASH — partition pruning for faster queries on large tables.</text></svg>","codeExamples":[{"title":"RANGE Partitioning by Month","useCase":"Time-series data management.","code":"CREATE TABLE orders (\n  id INT, order_date DATE, amount DECIMAL, customer_id INT\n) PARTITION BY RANGE (order_date);\n\nCREATE TABLE orders_2024_q1 PARTITION OF orders\n  FOR VALUES FROM ('2024-01-01') TO ('2024-04-01');\n\nCREATE TABLE orders_2024_q2 PARTITION OF orders\n  FOR VALUES FROM ('2024-04-01') TO ('2024-07-01');\n\nCREATE TABLE orders_2024_q3 PARTITION OF orders\n  FOR VALUES FROM ('2024-07-01') TO ('2024-10-01');\n\nCREATE TABLE orders_2024_q4 PARTITION OF orders\n  FOR VALUES FROM ('2024-10-01') TO ('2025-01-01');","description":"Creates quarterly partitions for orders table. Queries by date range only scan relevant partitions."},{"title":"LIST Partitioning by Region","useCase":"Categorical data.","code":"CREATE TABLE customers (\n  id INT, name TEXT, region TEXT, signup_date DATE\n) PARTITION BY LIST (region);\n\nCREATE TABLE customers_us PARTITION OF customers\n  FOR VALUES IN ('US', 'CA', 'MX');\n\nCREATE TABLE customers_eu PARTITION OF customers\n  FOR VALUES IN ('UK', 'DE', 'FR', 'IT');\n\nCREATE TABLE customers_apac PARTITION OF customers\n  FOR VALUES IN ('JP', 'CN', 'IN', 'AU');\n\n-- Query: WHERE region = 'DE' only scans eu partition","description":"LIST partitioning separates data by geographic region for regional data isolation."},{"title":"HASH Partitioning","useCase":"Even data distribution.","code":"CREATE TABLE events (\n  id INT, event_data TEXT, created_at TIMESTAMPTZ\n) PARTITION BY HASH (id);\n\nCREATE TABLE events_0 PARTITION OF events\n  FOR VALUES WITH (MODULUS 4, REMAINDER 0);\nCREATE TABLE events_1 PARTITION OF events\n  FOR VALUES WITH (MODULUS 4, REMAINDER 1);\nCREATE TABLE events_2 PARTITION OF events\n  FOR VALUES WITH (MODULUS 4, REMAINDER 2);\nCREATE TABLE events_3 PARTITION OF events\n  FOR VALUES WITH (MODULUS 4, REMAINDER 3);","description":"HASH partitioning distributes data evenly across 4 partitions for load balancing."},{"title":"Partition Pruning in Action","useCase":"Verify with EXPLAIN.","code":"EXPLAIN SELECT * FROM orders\nWHERE order_date >= '2024-06-01' AND order_date < '2024-07-01';\n\n-- Output shows only q2 partition scanned:\n-- Seq Scan on orders_2024_q2 ...\n--   Filter: (order_date >= '2024-06-01'::date)\n-- Other partitions: excluded (pruned)","description":"EXPLAIN shows partition pruning in action — only relevant partitions are scanned."},{"title":"Managing Partitions","useCase":"Adding and dropping partitions.","code":"-- Add a new partition for next quarter\nCREATE TABLE orders_2025_q1 PARTITION OF orders\n  FOR VALUES FROM ('2025-01-01') TO ('2025-04-01');\n\n-- Drop old data (fast, no vacuum)\nDROP TABLE orders_2023_q1;\n\n-- Detach partition for archival\nALTER TABLE orders DETACH PARTITION orders_2023_q2;\n-- Can now move the detached table to archive storage","description":"Efficient data lifecycle management with partition add, drop, and detach operations."}],"mcqQuestions":[{"question":"What is table partitioning?","options":["Indexing strategy","Splitting tables into smaller pieces","Joining tables","Caching strategy"],"answer":1,"explanation":"Partitioning divides a large table into smaller physical partitions."},{"question":"Which method is best for time-series?","options":["LIST","RANGE","HASH","KEY"],"answer":1,"explanation":"RANGE partitioning is ideal for time-series data by date ranges."},{"question":"What is partition pruning?","options":["Deleting partitions","Skipping irrelevant partitions","Creating partitions","Merging partitions"],"answer":1,"explanation":"Partition pruning skips partitions that do not match the query WHERE clause."},{"question":"Which method distributes data evenly?","options":["RANGE","LIST","HASH","KEY"],"answer":2,"explanation":"HASH partitioning distributes data evenly across a fixed number of partitions."},{"question":"How do you remove old data efficiently?","options":["DELETE FROM","DROP PARTITION","TRUNCATE","VACUUM"],"answer":1,"explanation":"DROP TABLE on a partition is much faster than DELETE from a large table."},{"question":"What is a limitation of partitioning?","options":["No indexes allowed","No cross-partition FKs","Slow queries","No INSERT allowed"],"answer":1,"explanation":"Foreign keys cannot reference a partitioned table (no cross-partition FKs)."}]};
TOPICS_DATA["sql"]["sql-pivot"] = {"id":"sql-pivot","title":"PIVOT & Crosstab Queries","difficulty":"advanced","estimatedMinutes":25,"tldr":["Pivot queries transform rows into columns, creating crosstab or matrix-style reports from normalized data.","Crosstab queries are necessary for: sales by month (rows=products, columns=months), attendance by department, survey results by category.","PostgreSQL does not have a built-in PIVOT operator. Use tablefunc extension (crosstab function) or conditional aggregation with CASE.","Conditional aggregation (CASE inside aggregate) is the most portable approach, working in all SQL databases."],"laymanDefinition":"A pivot is like turning a vertical list into a spreadsheet. Instead of a list like \"Product A - Jan - 100, Product A - Feb - 200\", you get a table with months as columns: \"Product A | Jan: 100 | Feb: 200 | Mar: 150\". Rows become columns.","deepDive":[{"heading":"Conditional Aggregation (CASE Pivot)","text":"SELECT category, SUM(CASE WHEN month = \\'Jan\\' THEN amount END) AS jan, ... FROM sales GROUP BY category. Most portable — works in all databases. Easy to understand. Column count is fixed at query time."},{"heading":"tablefunc Extension (crosstab)","text":"CREATE EXTENSION tablefunc; SELECT * FROM crosstab(\\'source_sql\\', \\'category_sql\\') AS ct(row_name TYPE, col1 TYPE, col2 TYPE, ...). Source query must return (row_name, category, value) ordered correctly. Dynamic columns are not supported."},{"heading":"FILTER Clause (PostgreSQL 9.4+)","text":"SELECT category, COUNT(*) FILTER (WHERE month = \\'Jan\\') AS jan, ... FROM sales GROUP BY category. Cleaner syntax than CASE. PostgreSQL-specific. Same performance as CASE."},{"heading":"Dynamic Pivot with crosstab + hstore","text":"For unknown columns at query time: use crosstab with hstore or jsonb_agg. SELECT jsonb_object_agg(month, total) FROM ... Returns a JSON object instead of separate columns. Flexible for dynamic reporting."},{"heading":"Use Cases","text":"Sales reports: products x months. Employee headcount by department and status. Survey responses by question and rating. Any grid/matrix report where rows and columns come from data."}],"interviewAnswer":"Pivoting is essential for reporting and dashboards. Conditional aggregation with CASE is the most portable approach. The crosstab function is faster for large datasets but requires fixed column definitions. For truly dynamic columns, use JSON aggregation.","interviewQuestions":[{"question":"What is a pivot query?","answer":"Transforms row values into column headers, creating a crosstab/matrix from normalized data."},{"question":"What is the most portable pivot technique?","answer":"Conditional aggregation: SUM(CASE WHEN condition THEN value END). Works in all SQL databases."},{"question":"What does the tablefunc extension provide?","answer":"The crosstab() function for pivot queries in PostgreSQL."},{"question":"What is the FILTER clause for pivots?","answer":"PostgreSQL syntax: COUNT(*) FILTER (WHERE month = \\'Jan\\'). Cleaner than CASE."},{"question":"What are the requirements for crosstab()?","answer":"Source query must return (row_name, category, value) sorted by row_name then category. Column definition must match the output."},{"question":"How do you create dynamic pivot columns?","answer":"Use jsonb_object_agg() to aggregate into a JSON object instead of separate columns."},{"question":"What is a common pivot use case?","answer":"Monthly sales report: rows = products, columns = months, values = sales amounts."},{"question":"Can you pivot with multiple value columns?","answer":"Yes. Use multiple CASE expressions or crosstab() with multiple value columns."},{"question":"What is the difference between CASE and FILTER for pivots?","answer":"CASE is portable. FILTER is cleaner syntax but PostgreSQL-only. Performance is similar."},{"question":"How do you handle NULLs in pivot results?","answer":"Use COALESCE(SUM(CASE ...), 0) to show 0 instead of NULL for missing combinations."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">PIVOT & Crosstab Queries</text><rect x=\"10\" y=\"35\" width=\"130\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"75\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">CASE</text><text x=\"75\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Portable pivot</text><rect x=\"10\" y=\"65\" width=\"130\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"75\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">FILTER</text><text x=\"75\" y=\"93\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Clean syntax</text><rect x=\"10\" y=\"95\" width=\"130\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"75\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">crosstab()</text><text x=\"75\" y=\"123\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Fast pivot</text><rect x=\"10\" y=\"125\" width=\"130\" height=\"25\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"75\" y=\"141\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">jsonb_agg</text><text x=\"75\" y=\"153\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Dynamic cols</text><line x1=\"140\" y1=\"48\" x2=\"170\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"140\" y1=\"78\" x2=\"170\" y2=\"78\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"140\" y1=\"108\" x2=\"170\" y2=\"108\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"140\" y1=\"138\" x2=\"170\" y2=\"138\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"180\" y=\"35\" width=\"200\" height=\"130\" rx=\"4\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1\"/><text x=\"280\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Pivot & Crosstab</text><text x=\"280\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Transform rows to columns for matrix-style reports and dashboards.</text><text x=\"240\" y=\"195\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Pivot Queries: Convert rows to columns for crosstab reports using CASE, FILTER, or crosstab().</text></svg>","codeExamples":[{"title":"CASE-Based Pivot","useCase":"Monthly sales by product.","code":"SELECT\n  product_name,\n  SUM(CASE WHEN month = 1 THEN amount ELSE 0 END) AS jan,\n  SUM(CASE WHEN month = 2 THEN amount ELSE 0 END) AS feb,\n  SUM(CASE WHEN month = 3 THEN amount ELSE 0 END) AS mar,\n  SUM(amount) AS total\nFROM monthly_sales\nWHERE year = 2024\nGROUP BY product_name\nORDER BY product_name;","description":"CASE-based pivoting: months become columns, products are rows."},{"title":"FILTER Clause Pivot","useCase":"Cleaner PostgreSQL syntax.","code":"SELECT\n  department,\n  COUNT(*) FILTER (WHERE status = 'active') AS active,\n  COUNT(*) FILTER (WHERE status = 'inactive') AS inactive,\n  COUNT(*) FILTER (WHERE status = 'on_leave') AS on_leave,\n  COUNT(*) AS total\nFROM employees\nGROUP BY department\nORDER BY department;","description":"FILTER clause provides cleaner syntax than CASE for aggregate pivots."},{"title":"crosstab() Function","useCase":"Using tablefunc extension.","code":"CREATE EXTENSION IF NOT EXISTS tablefunc;\n\nSELECT * FROM crosstab(\n  'SELECT product_name, month, amount'\n   FROM monthly_sales\n   WHERE year = 2024\n   ORDER BY 1, 2',\n  'SELECT generate_series(1, 12) AS month'\n) AS ct(\n  product_name TEXT,\n  jan NUMERIC, feb NUMERIC, mar NUMERIC,\n  apr NUMERIC, may NUMERIC, jun NUMERIC,\n  jul NUMERIC, aug NUMERIC, sep NUMERIC,\n  oct NUMERIC, nov NUMERIC, dec NUMERIC\n);","description":"crosstab() function creates the pivot with fixed column definitions."},{"title":"Dynamic JSON Pivot","useCase":"Unknown columns at query time.","code":"SELECT\n  department,\n  jsonb_object_agg(status, count ORDER BY status) AS status_breakdown\nFROM (\n  SELECT department, status, COUNT(*) AS count\n  FROM employees\n  GROUP BY department, status\n) sub\nGROUP BY department\nORDER BY department;\n\n-- Result: department | {\"active\": 15, \"inactive\": 3}","description":"jsonb_object_agg creates flexible pivots when column names are not known in advance."},{"title":"Multiple Value Columns","useCase":"Pivot with multiple measures.","code":"SELECT\n  department,\n  SUM(CASE WHEN status = 'active' THEN 1 ELSE 0 END) AS active_count,\n  ROUND(AVG(CASE WHEN status = 'active' THEN salary END), 0) AS active_avg_sal,\n  SUM(CASE WHEN status = 'inactive' THEN 1 ELSE 0 END) AS inactive_count\nFROM employees\nGROUP BY department\nORDER BY department;","description":"Pivoting multiple measures (count and average) across categories."}],"mcqQuestions":[{"question":"What does a pivot query do?","options":["Columns to rows","Rows to columns","Sorts data","Filters data"],"answer":1,"explanation":"Pivot transforms row values into column headers."},{"question":"What is the most portable pivot technique?","options":["crosstab()","FILTER clause","CASE aggregation","PIVOT keyword"],"answer":2,"explanation":"CASE-based conditional aggregation works in all SQL databases."},{"question":"What PostgreSQL extension provides crosstab?","options":["tablefunc","pivot","crosstab","matricies"],"answer":0,"explanation":"The tablefunc extension provides the crosstab() function."},{"question":"How do you create dynamic pivot columns?","options":["crosstab()","jsonb_object_agg()","FILTER clause","Multiple CASE"],"answer":1,"explanation":"jsonb_object_agg creates flexible JSON pivots for dynamic columns."},{"question":"What is required for crosstab() source SQL?","options":["Any order","Sorted by row then category","Sorted by value","Grouped"],"answer":1,"explanation":"The source query must return rows sorted by row_name then category."},{"question":"What PostgreSQL syntax is cleaner than CASE for pivots?","options":["PIVOT","FILTER","crosstab","UNPIVOT"],"answer":1,"explanation":"The FILTER clause provides cleaner aggregate pivot syntax."}]};
TOPICS_DATA["sql"]["sql-er-diagrams"] = {"id":"sql-er-diagrams","title":"ER Diagrams & Database Design","difficulty":"intermediate","estimatedMinutes":25,"tldr":["Entity-Relationship (ER) diagrams visually represent database structure: entities (tables), attributes (columns), and relationships (foreign keys).","Chen notation and Crow's Foot notation are the two most common ER diagram styles.","Relationships: one-to-one (1:1), one-to-many (1:N), many-to-many (M:N). Many-to-many requires a junction table.","Good database design considers normal forms, indexing strategy, naming conventions, and future scalability."],"laymanDefinition":"An ER diagram is like a blueprint for a building. Before you start constructing tables, you draw how they connect. A Customer \"has many\" Orders (one-to-many). An Order \"has many\" Products through Order_Items (many-to-many). The blueprint ensures you build the right structure.","deepDive":[{"heading":"Entities and Attributes","text":"Entity: a real-world object (Customer, Order, Product). Represented as a table. Attribute: a property of an entity (Customer.name, Order.date). Represented as columns. Key attribute: uniquely identifies an entity (primary key)."},{"heading":"Relationships and Cardinality","text":"One-to-One (1:1): User has one Profile. One-to-Many (1:N): Customer has many Orders. Many-to-Many (M:N): Student takes many Courses, Course has many Students. M:N uses junction table: Student_Courses with composite PK."},{"heading":"Crow\\'s Foot Notation","text":"|| — one (exactly one). >|— — one (zero or one). —< — many. ||—< — one to many. >|—< — many to many. Lines connect entities with crow\\'s foot symbols at the \"many\" end."},{"heading":"Design Process","text":"1. Identify entities. 2. Define relationships. 3. Add attributes. 4. Assign keys. 5. Normalize to 3NF. 6. Add indexes. 7. Document with naming conventions. 8. Review with stakeholders."},{"heading":"Naming Conventions","text":"Tables: plural nouns (users, orders, products). Columns: snake_case lower_case (first_name, order_date). Primary keys: id or table_name_id. Foreign keys: referenced_table_id. Junction tables: table1_table2 (students_courses)."}],"interviewAnswer":"ER diagrams and thoughtful database design are the foundation of any well-functioning application. Invest time in the design phase — it is much cheaper than migrating data from a poorly designed schema later.","interviewQuestions":[{"question":"What is an ER diagram?","answer":"Entity-Relationship diagram — a visual representation of database entities, attributes, and relationships."},{"question":"What is an entity?","answer":"A real-world object or concept that can be distinctly identified. Represented as a table in the database."},{"question":"What is an attribute?","answer":"A property or characteristic of an entity. Represented as a column in a table."},{"question":"What does one-to-many mean?","answer":"One record in table A relates to many records in table B. Example: one customer has many orders."},{"question":"What is a many-to-many relationship?","answer":"Multiple records in table A relate to multiple records in table B. Requires a junction table."},{"question":"What is a junction table?","answer":"A table that resolves many-to-many relationships. Contains foreign keys to both related tables."},{"question":"What are the two common ER notation styles?","answer":"Chen notation (entities in rectangles, relationships in diamonds). Crow\\'s Foot notation (lines with symbols)."},{"question":"What is Crow\\'s Foot notation?","answer":"A notation using lines with symbols (crow\\'s feet) to indicate relationship cardinality."},{"question":"What naming convention is recommended for tables?","answer":"Plural snake_case: users, orders, products. Consistent naming improves readability and maintenance."},{"question":"What is the first step in database design?","answer":"Identify the entities (nouns) in the system domain. Then define their relationships."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">ER Diagrams & Database Design</text><rect x=\"10\" y=\"35\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"60\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Entities</text><text x=\"60\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Tables</text><rect x=\"10\" y=\"65\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"60\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Attributes</text><text x=\"60\" y=\"93\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Columns</text><rect x=\"10\" y=\"95\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"60\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Relations</text><text x=\"60\" y=\"123\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">FK links</text><rect x=\"10\" y=\"125\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"60\" y=\"141\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Cardinality</text><text x=\"60\" y=\"153\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">1:1, 1:N, M:N</text><rect x=\"10\" y=\"155\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1\"/><text x=\"60\" y=\"171\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Normalize</text><text x=\"60\" y=\"183\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">3NF design</text><line x1=\"110\" y1=\"48\" x2=\"140\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"110\" y1=\"78\" x2=\"140\" y2=\"78\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"110\" y1=\"108\" x2=\"140\" y2=\"108\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"110\" y1=\"138\" x2=\"140\" y2=\"138\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"110\" y1=\"168\" x2=\"140\" y2=\"168\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"150\" y=\"35\" width=\"230\" height=\"155\" rx=\"4\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1\"/><text x=\"265\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">ER Diagrams & Design</text><text x=\"265\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Visual database blueprint: entities, relationships, cardinality, and normalization.</text><text x=\"240\" y=\"220\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">ER Diagrams: Visual database design with entities, relationships, and cardinality.</text></svg>","codeExamples":[{"title":"Simple Schema Example","useCase":"E-commerce database design.","code":"-- E-commerce schema (3NF)\n\nCREATE TABLE customers (\n  id SERIAL PRIMARY KEY,\n  name VARCHAR(100) NOT NULL,\n  email VARCHAR(255) UNIQUE NOT NULL\n);\n\nCREATE TABLE orders (\n  id SERIAL PRIMARY KEY,\n  customer_id INT NOT NULL REFERENCES customers(id),\n  order_date DATE DEFAULT CURRENT_DATE,\n  status VARCHAR(20) DEFAULT 'pending'\n);\n\nCREATE TABLE products (\n  id SERIAL PRIMARY KEY,\n  name VARCHAR(100) NOT NULL,\n  price DECIMAL(10,2) NOT NULL\n);\n\n-- Junction table for M:N relationship\nCREATE TABLE order_items (\n  order_id INT REFERENCES orders(id) ON DELETE CASCADE,\n  product_id INT REFERENCES products(id),\n  quantity INT NOT NULL DEFAULT 1,\n  PRIMARY KEY (order_id, product_id)\n);","description":"Complete normalized e-commerce schema with 1:N and M:N relationships."},{"title":"Implementing 1:1 Relationship","useCase":"User and profile.","code":"CREATE TABLE users (\n  id SERIAL PRIMARY KEY,\n  username VARCHAR(50) UNIQUE NOT NULL,\n  password_hash TEXT NOT NULL\n);\n\nCREATE TABLE user_profiles (\n  id SERIAL PRIMARY KEY,\n  user_id INT UNIQUE NOT NULL REFERENCES users(id),\n  first_name VARCHAR(50),\n  last_name VARCHAR(50),\n  avatar_url TEXT,\n  bio TEXT\n);\n\n-- UNIQUE on user_id enforces 1:1","description":"One-to-one relationship enforced by UNIQUE constraint on the foreign key."},{"title":"Resolving M:N with Junction Table","useCase":"Students and courses.","code":"CREATE TABLE students (\n  id SERIAL PRIMARY KEY,\n  name VARCHAR(100),\n  enrolled_date DATE\n);\n\nCREATE TABLE courses (\n  id SERIAL PRIMARY KEY,\n  title VARCHAR(100),\n  credits INT\n);\n\n-- Junction table with extra attribute (grade)\nCREATE TABLE enrollments (\n  student_id INT REFERENCES students(id),\n  course_id INT REFERENCES courses(id),\n  grade CHAR(1),\n  enrolled_at TIMESTAMP DEFAULT NOW(),\n  PRIMARY KEY (student_id, course_id)\n);","description":"Many-to-many relationship with a junction table containing additional attributes."},{"title":"Self-Referential Relationship","useCase":"Category hierarchy.","code":"CREATE TABLE categories (\n  id SERIAL PRIMARY KEY,\n  name VARCHAR(100) NOT NULL,\n  parent_id INT REFERENCES categories(id),\n  sort_order INT DEFAULT 0\n);\n\n-- Insert hierarchy\nINSERT INTO categories (name, parent_id) VALUES\n  ('Electronics', NULL),\n  ('Computers', 1),\n  ('Laptops', 2),\n  ('Desktops', 2),\n  ('Phones', 1);\n\n-- Use recursive CTE to traverse","description":"Self-referential foreign key enables parent-child hierarchies in a single table."},{"title":"ER Diagram in Text","useCase":"Visualize relationships.","code":"┌──────────────┐       ┌────────────────┐\n│  customers   │       │    orders      │\n├──────────────┤       ├────────────────┤\n│  id (PK)     │──1:N──│  id (PK)       │\n│  name        │       │  customer_id   │\n│  email       │       │  order_date    │\n└──────────────┘       │  status        │\n                       └───────┬────────┘\n                               │\n                      ┌────────┴────────┐\n                      │   order_items   │\n                      ├────────────────┤\n                      │  order_id (PK)  │\n                      │  product_id(PK) │\n                      │  quantity       │\n                      └───┬────┬────┬───┘\n              M:N──────────┘    │    └──────────M:N\n              ┌─────────────────┴─────────────────┐\n              │             products              │\n              ├──────────────────────────────────┤\n              │  id (PK)                         │\n              │  name                            │\n              │  price                           │\n              └──────────────────────────────────┘","description":"Text-based ER diagram showing the relationships in the e-commerce schema."}],"mcqQuestions":[{"question":"What does an ER diagram represent?","options":["Query plans","Database structure visually","Index usage","Query performance"],"answer":1,"explanation":"ER diagrams show database entities and their relationships visually."},{"question":"What is a many-to-many relationship?","options":["One to one","Multiple to multiple via junction","One to multiple","Multiple to one"],"answer":1,"explanation":"M:N requires a junction table with foreign keys to both related tables."},{"question":"What enforces a one-to-one relationship?","options":["PRIMARY KEY","UNIQUE on FK","NOT NULL","CHECK constraint"],"answer":1,"explanation":"A UNIQUE constraint on the foreign key enforces one-to-one."},{"question":"What is a junction table?","options":["Single table join","Resolves M:N relationships","Temporary table","Indexed view"],"answer":1,"explanation":"Junction tables bridge many-to-many relationships."},{"question":"Which cardinality needs a junction table?","options":["1:1","1:N","M:N","All of the above"],"answer":2,"explanation":"Many-to-many (M:N) relationships require a junction table."},{"question":"What is a self-referential FK?","options":["FK to different table","FK to the same table","Circular reference","Composite FK"],"answer":1,"explanation":"A self-referential foreign key references the same table (hierarchies)."}]};
TOPICS_DATA["sql"]["sql-null-handling"] = {"id":"sql-null-handling","title":"NULL Handling & Three-Valued Logic","difficulty":"intermediate","estimatedMinutes":20,"tldr":["NULL represents missing or unknown data in SQL. It is not a value — it is the absence of a value.","Three-valued logic: comparisons with NULL return UNKNOWN (neither TRUE nor FALSE). WHERE filters out rows where the condition is UNKNOWN.","NULL is not equal to NULL. NULL = NULL returns UNKNOWN, not TRUE. Use IS NULL to check for NULL.","Aggregate functions (except COUNT(*)) ignore NULLs. String concatenation with NULL returns NULL (in most databases)."],"laymanDefinition":"NULL is like an empty box in a storage unit. You cannot tell if the box is empty by comparing it to another empty box — \"is this empty box the same as that empty box?\" has no meaningful answer. You need to check each box individually with IS NULL.","deepDive":[{"heading":"NULL = NULL is Not TRUE","text":"NULL = NULL evaluates to UNKNOWN, not TRUE. NULL <> NULL also evaluates to UNKNOWN. This is the most common source of SQL bugs. Use IS NULL / IS NOT NULL for NULL checks. Use IS DISTINCT FROM (PostgreSQL) for NULL-safe equality comparison."},{"heading":"Three-Valued Logic Truth Tables","text":"TRUE AND UNKNOWN = UNKNOWN. FALSE AND UNKNOWN = FALSE. TRUE OR UNKNOWN = TRUE. FALSE OR UNKNOWN = UNKNOWN. NOT UNKNOWN = UNKNOWN. WHERE clause includes rows only where the condition evaluates to TRUE."},{"heading":"NULL in WHERE Clauses","text":"WHERE column = NULL returns no rows (because NULL = NULL is UNKNOWN). WHERE column <> NULL also returns no rows. WHERE column IS NULL correctly finds NULL rows. Always use IS NULL/NOT NULL for NULL checks."},{"heading":"NULL in Aggregates","text":"COUNT(*) counts all rows including NULLs. COUNT(column) counts non-NULL values. SUM, AVG, MIN, MAX ignore NULLs. AVG of all NULLs returns NULL. Use COALESCE: AVG(COALESCE(column, 0)) to handle NULLs."},{"heading":"NULL in Expressions","text":"NULL + 5 = NULL. NULL || \\'text\\' = NULL (PostgreSQL). CONCAT ignores NULLs (standard SQL). CASE WHEN NULL THEN ... END — the WHEN condition is NULL, which is UNKNOWN, so it falls to ELSE. IN with NULL: NULL IN (1,2,3) returns UNKNOWN."}],"interviewAnswer":"NULL handling is one of the most important and misunderstood SQL concepts. Every SQL developer should understand three-valued logic, IS NULL vs = NULL, and how NULLs behave in WHERE, JOIN, aggregation, and expressions.","interviewQuestions":[{"question":"What is NULL in SQL?","answer":"A marker indicating missing or unknown data. It is not a value — it represents the absence of a value."},{"question":"Why does NULL = NULL return UNKNOWN?","answer":"NULL represents unknown. Comparing two unknown values has no meaningful result. SQL uses three-valued logic: TRUE, FALSE, UNKNOWN."},{"question":"How do you check for NULL?","answer":"Use IS NULL or IS NOT NULL. Never use = NULL or <> NULL."},{"question":"What is IS DISTINCT FROM?","answer":"A PostgreSQL operator that treats NULL as a comparable value. NULL IS DISTINCT FROM NULL is FALSE, unlike NULL = NULL which is UNKNOWN."},{"question":"How do aggregate functions handle NULLs?","answer":"COUNT(*) includes NULLs. COUNT(column) excludes NULLs. SUM, AVG, MIN, MAX ignore NULLs."},{"question":"What happens when NULL appears in a WHERE clause?","answer":"Rows where the WHERE condition evaluates to UNKNOWN (from NULL comparisons) are excluded. Only TRUE rows are included."},{"question":"What does NULL + 5 return?","answer":"NULL. Any arithmetic with NULL yields NULL. Use COALESCE to provide a default."},{"question":"What does NOT IN with NULL subquery return?","answer":"If the subquery returns any NULL, NOT IN returns no rows. Use NOT EXISTS instead for safe NULL handling."},{"question":"How does CASE handle NULL?","answer":"CASE WHEN NULL THEN ... is UNKNOWN, so it falls to the next WHEN or ELSE. Use WHEN expr IS NULL THEN ... for explicit NULL handling."},{"question":"What is COALESCE?","answer":"Returns the first non-NULL argument. COALESCE(NULL, 5, 10) returns 5. Useful for providing default values for NULL columns."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">NULL Handling & Three-Valued Logic</text><rect x=\"10\" y=\"35\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"60\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">= NULL?</text><text x=\"60\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">UNKNOWN</text><rect x=\"10\" y=\"65\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"60\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">IS NULL</text><text x=\"60\" y=\"93\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Correct check</text><rect x=\"10\" y=\"95\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"60\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">AND/OR</text><text x=\"60\" y=\"123\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">3VL logic</text><rect x=\"10\" y=\"125\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"60\" y=\"141\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">COALESCE</text><text x=\"60\" y=\"153\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Default val</text><rect x=\"10\" y=\"155\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1\"/><text x=\"60\" y=\"171\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">NOT IN</text><text x=\"60\" y=\"183\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">NULL trap</text><line x1=\"110\" y1=\"48\" x2=\"140\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"110\" y1=\"78\" x2=\"140\" y2=\"78\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"110\" y1=\"108\" x2=\"140\" y2=\"108\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"110\" y1=\"138\" x2=\"140\" y2=\"138\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"110\" y1=\"168\" x2=\"140\" y2=\"168\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"150\" y=\"35\" width=\"230\" height=\"155\" rx=\"4\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1\"/><text x=\"265\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">NULL & Three-Valued Logic</text><text x=\"265\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">NULL is not a value. Understand three-valued logic to avoid the #1 SQL bug.</text><text x=\"240\" y=\"220\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">NULL Handling: Three-valued logic, IS NULL, COALESCE, and the NULL pitfalls to avoid.</text></svg>","codeExamples":[{"title":"NULL = NULL Trap","useCase":"Demonstrating the issue.","code":"-- Create test data\nCREATE TABLE test (id INT, name TEXT);\nINSERT INTO test VALUES (1, 'Alice'), (2, NULL);\n\n-- This returns NO rows:\nSELECT * FROM test WHERE name = NULL;\n\n-- This also returns NO rows:\nSELECT * FROM test WHERE name <> NULL;\n\n-- This correctly finds NULL rows:\nSELECT * FROM test WHERE name IS NULL; -- returns id=2\n\n-- This finds non-NULL rows:\nSELECT * FROM test WHERE name IS NOT NULL; -- returns id=1","description":"Demonstrates why = NULL never works and IS NULL is required."},{"title":"NOT IN vs NOT EXISTS","useCase":"The NULL trap.","code":"-- NOT IN with NULL in subquery returns nothing:\nSELECT * FROM employees\nWHERE dept_id NOT IN (\n  SELECT id FROM departments WHERE status = 'inactive'\n);\n-- If any dept id is NULL, this returns 0 rows!\n\n-- Safe alternative with NOT EXISTS:\nSELECT * FROM employees e\nWHERE NOT EXISTS (\n  SELECT 1 FROM departments d\n  WHERE d.id = e.dept_id AND d.status = 'inactive'\n);","description":"NOT IN with NULL subquery returns no rows — use NOT EXISTS instead."},{"title":"COALESCE and NULLIF","useCase":"Practical NULL handling.","code":"-- COALESCE: first non-NULL value\nSELECT\n  name,\n  COALESCE(phone, email, 'No contact') AS contact,\n  COALESCE(salary, 0) AS salary\nFROM employees;\n\n-- NULLIF: create NULL when equal\nSELECT\n  department,\n  SUM(salary) / NULLIF(COUNT(*), 0) AS avg_salary\nFROM employees\nGROUP BY department;","description":"COALESCE provides defaults; NULLIF prevents division by zero."},{"title":"IS DISTINCT FROM","useCase":"NULL-safe comparison (PostgreSQL).","code":"-- Regular comparison (NULL unsafe):\nSELECT * FROM products WHERE price = 100; -- misses NULL prices\n\n-- NULL-safe comparison:\nSELECT * FROM products WHERE price IS NOT DISTINCT FROM 100;\n-- Returns rows where price = 100 OR price IS NULL\n\n-- Opposite:\nSELECT * FROM products WHERE price IS DISTINCT FROM 100;\n-- Returns rows where price <> 100 AND price IS NOT NULL","description":"IS DISTINCT FROM treats NULL as a comparable value."},{"title":"NULL in JOIN Conditions","useCase":"How NULLs affect JOINs.","code":"-- INNER JOIN with NULL FK:\nSELECT e.name, d.department_name\nFROM employees e\nJOIN departments d ON e.dept_id = d.id;\n-- Employees with NULL dept_id are EXCLUDED\n\n-- LEFT JOIN shows NULL dept:\nSELECT e.name, d.department_name\nFROM employees e\nLEFT JOIN departments d ON e.dept_id = d.id;\n-- NULL dept_id shows department_name as NULL","description":"INNER JOIN silently drops rows with NULL foreign keys; LEFT JOIN preserves them."}],"mcqQuestions":[{"question":"What does NULL = NULL evaluate to?","options":["TRUE","FALSE","UNKNOWN","NULL"],"answer":2,"explanation":"NULL = NULL evaluates to UNKNOWN in three-valued logic."},{"question":"How do you correctly check for NULL?","options":["= NULL","IS NULL","== NULL","EQUALS NULL"],"answer":1,"explanation":"Use IS NULL to check for NULL values."},{"question":"Which aggregate includes NULLs?","options":["COUNT(column)","COUNT(*)","SUM","AVG"],"answer":1,"explanation":"COUNT(*) counts all rows including NULLs."},{"question":"What does COALESCE(NULL, 5, 10) return?","options":["NULL","5","10","Error"],"answer":1,"explanation":"COALESCE returns the first non-NULL value, which is 5."},{"question":"What happens with NOT IN if the subquery has NULL?","options":["Works normally","Returns no rows","Errors","Ignores NULL"],"answer":1,"explanation":"NOT IN with NULL in the subquery returns zero rows."},{"question":"What PostgreSQL operator is NULL-safe?","options":["<=>","IS DISTINCT FROM","===","IS NOT"],"answer":1,"explanation":"IS DISTINCT FROM treats NULL as a comparable value."}]};
TOPICS_DATA["sql"]["sql-lateral-joins"] = {"id":"sql-lateral-joins","title":"LATERAL Joins","difficulty":"advanced","estimatedMinutes":25,"tldr":["LATERAL allows a subquery in the FROM clause to reference columns from preceding FROM items, enabling row-by-row subquery execution.","Without LATERAL, subqueries in FROM execute independently. With LATERAL, they can reference columns from tables/CTEs listed before them.","LATERAL is powerful for: top-N per group, applying functions per row, and complex joins that depend on outer row values.","PostgreSQL, Oracle, and SQL Server support LATERAL. MySQL does not support it (before 8.0.14)."],"laymanDefinition":"A regular subquery in FROM is like a caterer who brings the same food to every table regardless of who is sitting there. A LATERAL subquery is like a chef who asks each table what they want and customizes the dish individually based on the table's preferences.","deepDive":[{"heading":"Basic LATERAL Syntax","text":"SELECT * FROM table1 t1, LATERAL (SELECT * FROM table2 WHERE t2.id = t1.id) sub. The LATERAL subquery runs once for each row in t1. Can also use JOIN LATERAL ... ON true for explicit join syntax."},{"heading":"Top-N Per Group with LATERAL","text":"SELECT d.name, sub.* FROM departments d, LATERAL (SELECT * FROM employees WHERE dept_id = d.id ORDER BY salary DESC LIMIT 3) sub. Gets top 3 earners per department without complex window functions."},{"heading":"LATERAL with Set-Returning Functions","text":"SELECT t.id, f.value FROM table t, LATERAL jsonb_array_elements(t.data) AS f(value). Expands JSON arrays per row. Also works with generate_series, unnest, and other set-returning functions."},{"heading":"LATERAL vs Correlated Subquery","text":"LATERAL subqueries can return multiple columns and rows (like a table). Correlated subqueries in WHERE/SELECT return scalar values. LATERAL in FROM can reference multiple preceding tables."},{"heading":"Multiple LATERAL Subqueries","text":"SELECT * FROM table t, LATERAL (SELECT ... WHERE ... = t.id) sub1, LATERAL (SELECT ... WHERE ... = sub1.id) sub2. Each subsequent LATERAL can reference all preceding FROM items."}],"interviewAnswer":"LATERAL is one of PostgreSQL's most powerful features. It enables per-row subquery execution, top-N per group queries, and clean expansion of array/JSON data. It often replaces complex window functions and correlated subqueries with more readable code.","interviewQuestions":[{"question":"What is LATERAL?","answer":"A keyword that allows a FROM subquery to reference columns from preceding FROM items, enabling per-row execution."},{"question":"How is LATERAL different from a regular subquery?","answer":"Regular subqueries in FROM execute independently. LATERAL subqueries can reference columns from tables listed before them."},{"question":"What is the LATERAL syntax?","answer":"FROM table1 t1, LATERAL (SELECT ... WHERE col = t1.col) sub. Or: FROM table1 t1 JOIN LATERAL (...) sub ON true."},{"question":"What is a common use for LATERAL?","answer":"Top-N per group: for each department, get top 3 employees by salary. Best performing employees per team, etc."},{"question":"How does LATERAL work with set-returning functions?","answer":"LATERAL is automatically applied when using set-returning functions in FROM: FROM table, jsonb_array_elements(data)."},{"question":"Can you have multiple LATERAL subqueries?","answer":"Yes. Each subsequent one can reference all preceding FROM items including previous LATERAL subqueries."},{"question":"Does MySQL support LATERAL?","answer":"MySQL 8.0.14+ supports LATERAL (limited). Not fully supported in older versions."},{"question":"What is the alternative to LATERAL for top-N?","answer":"Window functions with ROW_NUMBER() in a subquery/CTE, then filter WHERE rn <= N. LATERAL is often more readable."},{"question":"Can LATERAL reference CTEs?","answer":"Yes. WITH cte AS (...) SELECT * FROM cte, LATERAL (SELECT ... WHERE ... = cte.id)."},{"question":"Can LATERAL return multiple rows?","answer":"Yes. LATERAL subqueries can return multiple rows, causing the outer query to multiply rows (like JOIN)."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">LATERAL Joins</text><rect x=\"10\" y=\"35\" width=\"120\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"70\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">FROM t1, LATERAL</text><text x=\"70\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Row-by-row</text><line x1=\"130\" y1=\"48\" x2=\"160\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"170\" y=\"35\" width=\"120\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"230\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Top-N/Group</text><text x=\"230\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Per group LIMIT</text><rect x=\"170\" y=\"65\" width=\"120\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"230\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Set-Return</text><text x=\"230\" y=\"93\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">jsonb, unnest</text><rect x=\"170\" y=\"95\" width=\"120\" height=\"25\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"230\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Multiple</text><text x=\"230\" y=\"123\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Chain LATERALs</text><rect x=\"10\" y=\"100\" width=\"120\" height=\"25\" rx=\"4\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1\"/><text x=\"70\" y=\"116\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">vs Correlated</text><text x=\"70\" y=\"128\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Multi-row/col</text><line x1=\"290\" y1=\"48\" x2=\"320\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"290\" y1=\"78\" x2=\"320\" y2=\"78\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"290\" y1=\"108\" x2=\"320\" y2=\"108\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"330\" y=\"35\" width=\"150\" height=\"100\" rx=\"4\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1\"/><text x=\"405\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">LATERAL Joins</text><text x=\"405\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Row-by-row subqueries that can reference preceding FROM items.</text><text x=\"240\" y=\"195\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">LATERAL: Per-row subquery execution for top-N per group and set-returning functions.</text></svg>","codeExamples":[{"title":"Top-N Per Department","useCase":"3 highest paid per dept.","code":"SELECT d.department_name, sub.name, sub.salary\nFROM departments d,\nLATERAL (\n  SELECT name, salary\n  FROM employees\n  WHERE dept_id = d.id\n  ORDER BY salary DESC\n  LIMIT 3\n) sub\nORDER BY d.department_name, sub.salary DESC;","description":"Gets top 3 employees per department using LATERAL. Cleaner than ROW_NUMBER() approach."},{"title":"LATERAL with JSONB","useCase":"Expand JSON arrays per row.","code":"CREATE TABLE orders (\n  id INT,\n  items JSONB -- [{\"product\": \"A\", \"qty\": 2}, {\"product\": \"B\", \"qty\": 1}]\n);\n\nSELECT o.id, item->>'product' AS product,\n  (item->>'qty')::INT AS quantity\nFROM orders o,\nLATERAL jsonb_array_elements(o.items) AS item;","description":"Expands JSON array into rows using LATERAL with set-returning function."},{"title":"LATERAL with generate_series","useCase":"Fill missing dates.","code":"-- Generate last 7 days for each product\nSELECT p.name, d.date\nFROM products p,\nLATERAL generate_series(\n  CURRENT_DATE - 6, CURRENT_DATE, '1 day'\n) AS d(date)\nWHERE p.status = 'active'\nORDER BY p.name, d.date;","description":"Creates date/product cross-product using LATERAL with generate_series."},{"title":"Multiple LATERAL References","useCase":"Chained subqueries.","code":"SELECT e.name, e.salary,\n  sub1.dept_avg, sub2.company_max\nFROM employees e,\nLATERAL (\n  SELECT AVG(salary) AS dept_avg\n  FROM employees WHERE dept_id = e.dept_id\n) sub1,\nLATERAL (\n  SELECT MAX(salary) AS company_max\n  FROM employees\n) sub2;","description":"Each LATERAL subquery builds on the previous, computing per-row statistics."},{"title":"LATERAL with LIMIT for Recommendations","useCase":"Related products.","code":"SELECT c.name AS customer, rp.name AS recommended\nFROM customers c,\nLATERAL (\n  SELECT DISTINCT p2.name\n  FROM orders o1\n  JOIN order_items oi1 ON o1.id = oi1.order_id\n  JOIN products p1 ON oi1.product_id = p1.id\n  JOIN order_items oi2 ON oi1.product_id <> oi2.product_id\n  JOIN products p2 ON oi2.product_id = p2.id\n  JOIN orders o2 ON oi2.order_id = o2.id\n  WHERE o1.customer_id = c.id\n  AND o2.customer_id = c.id\n  ORDER BY RANDOM()\n  LIMIT 3\n) rp;","description":"Recommends 3 related products per customer based on purchase history."}],"mcqQuestions":[{"question":"What keyword enables per-row subqueries in FROM?","options":["CROSS","LATERAL","ROW","PER ROW"],"answer":1,"explanation":"LATERAL allows FROM subqueries to reference preceding columns."},{"question":"What is LATERAL commonly used for?","options":["Simple filtering","Top-N per group","Bulk updates","Table creation"],"answer":1,"explanation":"LATERAL excels at top-N per group queries."},{"question":"Can LATERAL return multiple rows?","options":["Yes","No","Only one column","Only scalars"],"answer":0,"explanation":"LATERAL subqueries can return multiple rows like a joined table."},{"question":"What databases support LATERAL?","options":["MySQL only","PostgreSQL, Oracle, SQL Server","SQLite only","All databases"],"answer":1,"explanation":"PostgreSQL, Oracle, and SQL Server support LATERAL."},{"question":"How does LATERAL differ from a correlated subquery?","options":["Same thing","LATERAL can return multiple cols/rows","Correlated is faster","LATERAL is only for WHERE"],"answer":1,"explanation":"LATERAL can return multiple columns and rows; correlated scalar subqueries return single values."},{"question":"Is LATERAL automatic with set-returning functions?","options":["Yes","No","Only in PostgreSQL","Only in Oracle"],"answer":0,"explanation":"Set-returning functions in FROM automatically use LATERAL behavior."}]};
TOPICS_DATA["sql"]["sql-locking-concurrency"] = {"id":"sql-locking-concurrency","title":"Locking & Concurrency","difficulty":"intermediate","estimatedMinutes":25,"tldr":["PostgreSQL uses Multi-Version Concurrency Control (MVCC) — each transaction sees a snapshot of data as of when it started.","Row-level locks: FOR UPDATE (write lock), FOR NO KEY UPDATE, FOR SHARE (read lock), FOR KEY SHARE.","SKIP LOCKED skips rows locked by other transactions — useful for job queues. NOWAIT errors immediately if row is locked.","Deadlocks occur when two transactions wait for each other's locks. PostgreSQL detects and resolves them automatically."],"laymanDefinition":"Locking is like a bathroom key at a restaurant. When you use the bathroom (update a row), you lock the door (row lock). Others wait. MVCC is like a window that shows the bathroom as it was when you entered — even if someone else changes it later, you still see the old state until you leave.","deepDive":[{"heading":"MVCC (Multi-Version Concurrency Control)","text":"Each transaction sees a snapshot of data at its start time. Readers never block writers; writers never block readers. Old row versions remain visible to concurrent transactions that started before the change. Cleaned up by VACUUM."},{"heading":"Row-Level Lock Types","text":"FOR UPDATE — strongest lock, prevents other transactions from updating, deleting, or locking the row. FOR NO KEY UPDATE — weaker than FOR UPDATE (allows other FOR KEY SHARE locks). FOR SHARE — read lock, prevents writes. FOR KEY SHARE — weakest, allows NO KEY UPDATE."},{"heading":"SKIP LOCKED and NOWAIT","text":"SELECT ... FOR UPDATE SKIP LOCKED — skip rows locked by others, only return available rows. Perfect for job queues. SELECT ... FOR UPDATE NOWAIT — error immediately if any selected row is locked (no waiting)."},{"heading":"Deadlock Detection","text":"PostgreSQL checks for deadlock cycles every deadlock_timeout (default 1 second). When detected, one transaction is aborted with ERROR: deadlock detected. The aborted transaction can be retried. Prevention: consistent lock ordering."},{"heading":"Advisory Locks","text":"pg_advisory_lock(key) — application-level locks not tied to rows. pg_try_advisory_lock — non-blocking attempt. Useful for coordinating across transactions or applications. Session-level or transaction-level variants."}],"interviewAnswer":"PostgreSQL's MVCC means SELECT queries never block writes and writes never block SELECTs. Row-level locking with FOR UPDATE is for explicit coordination. SKIP LOCKED is ideal for queue systems. Always design for the lowest lock level that ensures correctness.","interviewQuestions":[{"question":"What is MVCC?","answer":"Multi-Version Concurrency Control — each transaction sees a consistent snapshot. Readers don\\'t block writers."},{"question":"What does FOR UPDATE do?","answer":"Locks selected rows exclusively. Other transactions cannot UPDATE, DELETE, or lock the rows until the lock is released."},{"question":"What is the difference between FOR UPDATE and FOR SHARE?","answer":"FOR UPDATE is an exclusive write lock. FOR SHARE is a shared read lock — other transactions can also read-lock but cannot write-lock."},{"question":"What does SKIP LOCKED do?","answer":"Skips rows that are already locked by other transactions, returning only available rows."},{"question":"What does NOWAIT do?","answer":"Returns an error immediately if any selected row is locked, instead of waiting for the lock to be released."},{"question":"What causes a deadlock?","answer":"Two or more transactions each holding locks that the others need. PostgreSQL detects and resolves by aborting one transaction."},{"question":"How do you prevent deadlocks?","answer":"Access tables in a consistent order across all transactions. Keep transactions short. Use the lowest lock level needed."},{"question":"What is an advisory lock?","answer":"An application-level lock not tied to specific rows. Useful for coordinating access to shared resources across transactions."},{"question":"Does SELECT block INSERT?","answer":"No. Under MVCC, SELECT reads a snapshot. INSERT adds new rows. Readers and writers do not block each other."},{"question":"What is the default lock timeout?","answer":"PostgreSQL has no default lock timeout — it waits indefinitely. Set lock_timeout in postgresql.conf or per session."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Locking & Concurrency</text><rect x=\"10\" y=\"35\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"65\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">MVCC</text><text x=\"65\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Snapshots</text><rect x=\"10\" y=\"65\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"65\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">FOR UPDATE</text><text x=\"65\" y=\"93\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Write lock</text><rect x=\"10\" y=\"95\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"65\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">FOR SHARE</text><text x=\"65\" y=\"123\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Read lock</text><rect x=\"10\" y=\"125\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"65\" y=\"141\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">SKIP LOCKED</text><text x=\"65\" y=\"153\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Queue</text><rect x=\"10\" y=\"155\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1\"/><text x=\"65\" y=\"171\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Deadlock</text><text x=\"65\" y=\"183\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Detection</text><line x1=\"120\" y1=\"48\" x2=\"150\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"78\" x2=\"150\" y2=\"78\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"108\" x2=\"150\" y2=\"108\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"138\" x2=\"150\" y2=\"138\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"168\" x2=\"150\" y2=\"168\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"35\" width=\"220\" height=\"155\" rx=\"4\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1\"/><text x=\"270\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Locking & Concurrency</text><text x=\"270\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">MVCC, row locks, SKIP LOCKED, and deadlock handling in PostgreSQL.</text><text x=\"240\" y=\"220\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Locking & Concurrency: MVCC, FOR UPDATE, SKIP LOCKED, and deadlock prevention.</text></svg>","codeExamples":[{"title":"FOR UPDATE with SKIP LOCKED","useCase":"Job queue worker.","code":"-- Worker picks next available job (queue pattern)\nBEGIN;\n\nSELECT id, payload FROM job_queue\nWHERE status = 'pending'\nORDER BY created_at ASC\nLIMIT 1\nFOR UPDATE SKIP LOCKED;\n\n-- If row found, update status\nUPDATE job_queue SET status = 'processing',\n  started_at = NOW()\nWHERE id = <selected_id>;\n\nCOMMIT;\n\n-- SKIP LOCKED ensures workers don't fight over the same job","description":"Concurrent job queue with SKIP LOCKED — each worker gets a unique job."},{"title":"Locking for Inventory","useCase":"Prevent overselling.","code":"BEGIN;\n\n-- Lock the product row\nSELECT quantity FROM products WHERE id = 10\nFOR UPDATE;\n\n-- Check stock\n-- quantity = 5\n\n-- Decrement safely\nUPDATE products SET quantity = quantity - 1\nWHERE id = 10 AND quantity > 0;\n\n-- Insert order\nINSERT INTO orders (product_id, quantity)\nVALUES (10, 1);\n\nCOMMIT;","description":"FOR UPDATE prevents two concurrent buyers from purchasing the last item."},{"title":"NOWAIT for Immediate Feedback","useCase":"Fail fast if locked.","code":"-- Try to lock, error immediately if locked\nSELECT * FROM employees WHERE id = 5\nFOR UPDATE NOWAIT;\n\n-- If another transaction holds a lock:\n-- ERROR: could not obtain lock on row in relation \"employees\"\n-- Application catches this and retries later","description":"NOWAIT provides immediate feedback instead of waiting for potentially long-held locks."},{"title":"Advisory Lock for Application Coordinatio","useCase":"Cross-session locking.","code":"-- Lock application resource\nSELECT pg_advisory_lock(12345);\n\n-- Critical section\nUPDATE accounts SET balance = balance + 100 WHERE id = 1;\n\n-- Release lock\nSELECT pg_advisory_unlock(12345);\n\n-- Non-blocking version:\nSELECT pg_try_advisory_lock(12345);\n-- Returns true if lock acquired, false if already locked","description":"Advisory locks coordinate access across transactions without row-level locking."},{"title":"Deadlock Example","useCase":"How deadlocks happen.","code":"-- Transaction A:\nBEGIN;\nUPDATE accounts SET balance = 0 WHERE id = 1;\n-- (holds lock on account 1)\n\n-- Transaction B:\nBEGIN;\nUPDATE accounts SET balance = 0 WHERE id = 2;\n-- (holds lock on account 2)\n\n-- Transaction A:\nUPDATE accounts SET balance = 100 WHERE id = 2;\n-- (waits for B's lock on account 2)\n\n-- Transaction B:\nUPDATE accounts SET balance = 100 WHERE id = 1;\n-- (waits for A's lock on account 1)\n-- DEADLOCK! PostgreSQL kills one transaction","description":"Classic deadlock scenario. Prevention: always lock accounts in the same order."}],"mcqQuestions":[{"question":"What does MVCC stand for?","options":["Multi-Value Consistency Check","Multi-Version Concurrency Control","Multi-View Consistent Copy","Main Version Control Cache"],"answer":1,"explanation":"MVCC stands for Multi-Version Concurrency Control."},{"question":"What does FOR UPDATE do?","options":["Read lock","Write (exclusive) lock","Table lock","Schema lock"],"answer":1,"explanation":"FOR UPDATE acquires an exclusive write lock on selected rows."},{"question":"What does SKIP LOCKED skip?","options":["Locked tables","Locked rows","NULL values","Indexes"],"answer":1,"explanation":"SKIP LOCKED returns only unlocked rows, skipping those with locks."},{"question":"How does PostgreSQL handle deadlocks?","options":["Ignores them","Detects and aborts one transaction","Waits forever","Rolls back both"],"answer":1,"explanation":"PostgreSQL detects deadlocks automatically and aborts one transaction."},{"question":"What lock level allows concurrent reads?","options":["FOR UPDATE","FOR SHARE","FOR NO KEY UPDATE","All of the above"],"answer":1,"explanation":"FOR SHARE allows other transactions to also take FOR SHARE locks."},{"question":"What type of lock is not tied to rows?","options":["Row lock","Table lock","Advisory lock","Page lock"],"answer":2,"explanation":"Advisory locks are application-level locks not associated with specific rows."}]};
TOPICS_DATA["sql"]["sql-pattern-matching"] = {"id":"sql-pattern-matching","title":"Advanced Pattern Matching","difficulty":"intermediate","estimatedMinutes":20,"tldr":["PostgreSQL offers multiple pattern matching methods: LIKE (basic), SIMILAR TO (regex-like), POSIX regex (~), and full-text search.","LIKE: % (any sequence), _ (single char). ILIKE is case-insensitive LIKE.","SIMILAR TO: SQL standard with regex features: | (OR), * (quantifier), [chars] (character class).","POSIX Regular Expressions: ~ (matches), ~* (case-insensitive), !~ (not matches), !~* (not matches, case-insensitive)."],"laymanDefinition":"Pattern matching in SQL ranges from simple wildcards to full regular expressions. LIKE is like searching for a file with *.txt — simple and fast. SIMILAR TO adds OR and quantifiers. POSIX regex is the full power of regular expressions — like grep inside your database.","deepDive":[{"heading":"LIKE and ILIKE","text":"LIKE \\'prefix%\\' — starts with. LIKE \\'%suffix\\' — ends with. LIKE \\'%contains%\\' — contains anywhere. LIKE \\'A_\\' — two chars starting with A. ILIKE — case-insensitive version. Backslash escapes special chars. All patterns are full-string matches."},{"heading":"SIMILAR TO","text":"Intermediate between LIKE and regex. Supports: | (alternation), * (0+ repetitions), + (1+), ? (0 or 1), [a-z] (character class), [^a-z] (negation). Must match entire string (like LIKE). Example: SIMILAR TO \\'(abc|def)%\\' starts with abc or def."},{"heading":"POSIX Regex (~ Operator)","text":"~ \\'pattern\\' — matches (case-sensitive). ~* \\'pattern\\' — matches (case-insensitive). !~ \\'pattern\\' — does not match. !~* \\'pattern\\' — does not match (case-insensitive). Partial match (unlike LIKE which requires full match)."},{"heading":"Regex Functions","text":"REGEXP_MATCH(string, pattern) — returns first match as text[]. REGEXP_MATCHES — returns all matches. REGEXP_REPLACE — substitution. REGEXP_SPLIT_TO_TABLE — split into rows. REGEXP_SPLIT_TO_ARRAY — split into array."},{"heading":"Performance Considerations","text":"LIKE with prefix pattern (\\'abc%\\') can use B-tree index. ILIKE and regex patterns can use GIN or GiST indexes with pg_trgm extension. SIMILAR TO is typically slower than LIKE or regex. Avoid heavy regex on large unindexed tables."}],"interviewAnswer":"Use LIKE for simple wildcard matching (it is the fastest and can use indexes). Use POSIX regex (~) for complex patterns. Use SIMILAR TO mainly for SQL standard compliance — it bridges LIKE and regex. Consider pg_trgm extension for fuzzy search at scale.","interviewQuestions":[{"question":"What does LIKE \\'A%\\' match?","answer":"Any string starting with A. % matches any sequence of characters."},{"question":"What is ILIKE?","answer":"PostgreSQL-specific case-insensitive version of LIKE. Same syntax, but ignores case."},{"question":"What does _ match in LIKE?","answer":"A single character. LIKE \\'A_B\\' matches any 3-char string starting with A and ending with B."},{"question":"What is SIMILAR TO?","answer":"SQL standard pattern matching with simple regex features like |, *, +, and character classes."},{"question":"What does the ~ operator do?","answer":"POSIX regex match. ~ \\'^A.*B$\\' matches strings starting with A and ending with B."},{"question":"What is the difference between LIKE and ~?","answer":"LIKE requires full string match. ~ is a partial match (use ^ and $ for full match). LIKE has limited wildcards; ~ supports full regex."},{"question":"How do you do case-insensitive regex?","answer":"Use ~* (tilde asterisk). !~* for negated case-insensitive match."},{"question":"What does REGEXP_REPLACE do?","answer":"Replaces regex matches with replacement text. REGEXP_REPLACE(\\'abc123\\', \\'[0-9]\\', \\'\\', \\'g\\') removes digits."},{"question":"How do you split a string into rows?","answer":"REGEXP_SPLIT_TO_TABLE(string, delimiter_pattern) — splits string and returns each part as a row."},{"question":"What extension improves regex performance?","answer":"pg_trgm (trigram) extension enables GiST/GIN indexes for fast LIKE and regex queries."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Advanced Pattern Matching</text><rect x=\"10\" y=\"35\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"60\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">LIKE/ILIKE</text><text x=\"60\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Basic wildcard</text><rect x=\"10\" y=\"65\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"60\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">SIMILAR TO</text><text x=\"60\" y=\"93\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Simple regex</text><rect x=\"10\" y=\"95\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"60\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">~ Operator</text><text x=\"60\" y=\"123\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Full regex</text><rect x=\"10\" y=\"125\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"60\" y=\"141\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">REGEXP_*</text><text x=\"60\" y=\"153\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Functions</text><rect x=\"10\" y=\"155\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1\"/><text x=\"60\" y=\"171\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">pg_trgm</text><text x=\"60\" y=\"183\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Index fuzzy</text><line x1=\"110\" y1=\"48\" x2=\"140\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"110\" y1=\"78\" x2=\"140\" y2=\"78\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"110\" y1=\"108\" x2=\"140\" y2=\"108\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"110\" y1=\"138\" x2=\"140\" y2=\"138\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"110\" y1=\"168\" x2=\"140\" y2=\"168\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"150\" y=\"35\" width=\"230\" height=\"155\" rx=\"4\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1\"/><text x=\"265\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Pattern Matching</text><text x=\"265\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">LIKE, SIMILAR TO, POSIX regex, and regex functions for text pattern matching.</text><text x=\"240\" y=\"220\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Pattern Matching: LIKE, SIMILAR TO, POSIX Regex — from simple wildcards to full regex.</text></svg>","codeExamples":[{"title":"LIKE Basics","useCase":"Common LIKE patterns.","code":"SELECT name FROM employees WHERE name LIKE 'A%';    -- starts with A\nSELECT name FROM employees WHERE name LIKE '%son';  -- ends with son\nSELECT name FROM employees WHERE name LIKE '%mith%'; -- contains mith\nSELECT name FROM employees WHERE name LIKE 'A_';     -- A + 1 char\nSELECT name FROM employees WHERE name ILIKE 'alice%'; -- case-insensitive","description":"Common LIKE patterns for different matching scenarios."},{"title":"SIMILAR TO Examples","useCase":"Regex-like patterns.","code":"SELECT email FROM users\nWHERE email SIMILAR TO '[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\\.[A-Za-z]{2,}';\n\nSELECT name FROM products\nWHERE name SIMILAR TO '(Pro|Ultra|Max)%';","description":"SIMILAR TO with character classes and alternation for email validation."},{"title":"POSIX Regex for Complex Patterns","useCase":"Full regex power.","code":"-- Valid email format (partial match)\nSELECT email FROM users\nWHERE email ~ '^[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\\.[A-Za-z]{2,}$';\n\n-- Phone numbers (various formats)\nSELECT phone FROM contacts\nWHERE phone ~ '^\\(?[0-9]{3}\\)?[-. ]?[0-9]{3}[-. ]?[0-9]{4}$';\n\n-- Case-insensitive search\nSELECT * FROM articles WHERE body ~* 'database';","description":"POSIX regex for complex validation and search patterns."},{"title":"REGEXP_REPLACE and REGEXP_SPLIT","useCase":"Text transformation.","code":"-- Remove all non-numeric characters\nSELECT REGEXP_REPLACE(phone, '[^0-9]', '', 'g') AS clean_phone\nFROM contacts;\n\n-- Split comma-separated values into rows\nSELECT REGEXP_SPLIT_TO_TABLE('apple,banana,cherry', ',') AS fruit;\n\n-- Extract all numbers from text\nSELECT REGEXP_MATCHES('Order #123: $45.99', '[0-9]+', 'g') AS nums;","description":"Regex functions for data cleaning, splitting, and extraction."},{"title":"pg_trgm for Fuzzy Search","useCase":"Efficient fuzzy matching.","code":"CREATE EXTENSION IF NOT EXISTS pg_trgm;\n\n-- Create GiST index for fuzzy search\nCREATE INDEX idx_names_trgm ON users\nUSING GIST (name gist_trgm_ops);\n\n-- Similarity search\nSELECT *, similarity(name, 'Jonhson') AS sim\nFROM users\nWHERE name % 'Jonhson'  -- % operator means similar enough\nORDER BY sim DESC;\n\n-- Also speeds up:\nSELECT * FROM users WHERE name LIKE '%mith%'; -- with index","description":"pg_trgm extension enables fast fuzzy text search and wildcard queries at scale."}],"mcqQuestions":[{"question":"What does % match in LIKE?","options":["One character","Any sequence of characters","A digit","A word"],"answer":1,"explanation":"% matches any sequence of characters (including zero)."},{"question":"What operator does POSIX regex matching?","options":["~~","~",":=","##"],"answer":1,"explanation":"~ is the POSIX regex match operator in PostgreSQL."},{"question":"What is ILIKE?","options":["Case-sensitive LIKE","Case-insensitive LIKE","Indexed LIKE","Inverse LIKE"],"answer":1,"explanation":"ILIKE is the case-insensitive version of LIKE."},{"question":"What extension enables fuzzy search?","options":["pg_trgm","pg_fuzzy","pg_search","pg_similar"],"answer":0,"explanation":"pg_trgm provides trigram-based similarity search and GiST/GIN index support."},{"question":"What function extracts all regex matches?","options":["REGEXP_MATCH","REGEXP_MATCHES","REGEXP_EXTRACT","REGEXP_FIND"],"answer":1,"explanation":"REGEXP_MATCHES returns all matches (with g flag) as multiple rows."},{"question":"What is SIMILAR TO?","options":["SQL standard regex","Like LIKE with more features","PostgreSQL only","Same as ~ operator"],"answer":1,"explanation":"SIMILAR TO is SQL standard with OR, quantifiers, and character classes."}]};
TOPICS_DATA["sql"]["sql-pagination"] = {"id":"sql-pagination","title":"Pagination Strategies","difficulty":"intermediate","estimatedMinutes":20,"tldr":["Pagination splits large result sets into pages for UI display. Two main strategies: offset-based and keyset-based (cursor).","OFFSET/LIMIT pagination: simple, but slow for large offsets because the database scans and discards rows.","Keyset pagination (cursor-based): uses WHERE conditions on sorted columns. Fast for any page depth but requires unique sort order.","For large datasets (millions of rows), keyset pagination is dramatically faster than offset pagination."],"laymanDefinition":"OFFSET pagination is like reading a book by counting pages from the start each time — to get to page 1000, you still count 1-1000. Keyset pagination is like using a bookmark — you remember the last item and start from there. Much faster for deep pages.","deepDive":[{"heading":"OFFSET/LIMIT Pagination","text":"LIMIT 20 OFFSET 0 — page 1. LIMIT 20 OFFSET 40 — page 3. Simple to implement. Database must scan and discard OFFSET rows (sequential scan or index scan + skip). Performance degrades significantly at large offsets."},{"heading":"Keyset (Cursor) Pagination","text":"SELECT * FROM table WHERE id > last_seen_id ORDER BY id LIMIT 20. Uses index to jump directly to the starting point. No rows are scanned and discarded. Constant performance regardless of page depth."},{"heading":"Keyset with Multiple Columns","text":"WHERE (created_at, id) > (last_created_at, last_id) ORDER BY created_at, id — composite tuple comparison for tie-breaking. Requires composite unique index on the sort columns."},{"heading":"Comparison","text":"OFFSET: simple, URL-friendly (?page=3), allows jumping to any page, stable page numbers. Keyset: fast at scale, no page number jumping, sort order must be stable, requires unique sort column."},{"heading":"Hybrid Approach","text":"Use OFFSET for first few pages (users rarely go deep). Use keyset for deeper pages or infinite scroll. Many APIs use keyset (cursor) pagination exclusively: Twitter API, GitHub API, Stripe API."}],"interviewAnswer":"Choose offset pagination for small datasets and admin tables (where page jumping is needed). Choose keyset/cursor pagination for large datasets, APIs, and infinite scroll. The performance difference at scale is enormous — keyset is O(log n), offset is O(n).","interviewQuestions":[{"question":"What is offset pagination?","answer":"LIMIT n OFFSET m — skips m rows and returns n. Simple but slow for large offsets."},{"question":"What is keyset pagination?","answer":"WHERE sort_column > last_value ORDER BY sort_column LIMIT n — uses index to fast-forward."},{"question":"Why is OFFSET slow for large offsets?","answer":"The database must scan and discard all OFFSET rows. Scanning 100,000 rows to show page 500 is expensive."},{"question":"Is keyset always faster than OFFSET?","answer":"For deep pagination, yes. For the first few pages, the difference is negligible."},{"question":"What is required for keyset pagination?","answer":"A unique sort column (or unique combination). A stable sort order. An index on the sort column."},{"question":"Can keyset pagination jump to a specific page?","answer":"No. Keyset pagination cannot jump to page N arbitrarily — it requires knowing the last item of the previous page."},{"question":"What is tuple comparison for keyset?","answer":"WHERE (created_at, id) > (\\'2024-01-15\\', 100) — compares both columns for tie-breaking. Requires composite index."},{"question":"What APIs use cursor pagination?","answer":"Twitter, GitHub, Stripe, Slack — most modern APIs use cursor (keyset) pagination for their main endpoints."},{"question":"What is the hybrid approach?","answer":"Use OFFSET for first few pages (users rarely go deep). Use keyset for deeper pages or infinite scrolling."},{"question":"What is the SQL for keyset with descending order?","answer":"WHERE created_at < last_created_at OR (created_at = last_created_at AND id < last_id) ORDER BY created_at DESC, id DESC LIMIT n."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Pagination Strategies</text><rect x=\"10\" y=\"35\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"65\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">OFFSET</text><text x=\"65\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Skip rows</text><line x1=\"120\" y1=\"48\" x2=\"150\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"35\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"215\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">LIMIT</text><text x=\"215\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Page size</text><rect x=\"10\" y=\"70\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"65\" y=\"86\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Keyset</text><text x=\"65\" y=\"98\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">WHERE > last</text><rect x=\"10\" y=\"105\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"65\" y=\"121\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Tuple</text><text x=\"65\" y=\"133\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Multi-col</text><rect x=\"280\" y=\"35\" width=\"200\" height=\"100\" rx=\"4\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1\"/><text x=\"380\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Pagination</text><text x=\"380\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">OFFSET vs Keyset. Keyset is O(log n). OFFSET is O(n). Choose wisely.</text><text x=\"240\" y=\"175\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Pagination: OFFSET/LIMIT vs Keyset/Cursor — performance implications at scale.</text></svg>","codeExamples":[{"title":"OFFSET Pagination","useCase":"Simple but slow at depth.","code":"-- Page 1 (rows 1-20)\nSELECT id, name, created_at\nFROM employees\nORDER BY id\nLIMIT 20 OFFSET 0;\n\n-- Page 50 (rows 981-1000)\nSELECT id, name, created_at\nFROM employees\nORDER BY id\nLIMIT 20 OFFSET 980;\n-- Database scans 1000 rows, returns 20!","description":"OFFSET pagination — simple but inefficient for deep pages."},{"title":"Keyset Pagination","useCase":"Fast at any depth.","code":"-- Initial query (no cursor)\nSELECT id, name, created_at\nFROM employees\nORDER BY id\nLIMIT 20;\n-- Last item: id = 20\n\n-- Next page (using cursor)\nSELECT id, name, created_at\nFROM employees\nWHERE id > 20\nORDER BY id\nLIMIT 20;\n-- Direct index lookup — no scan!","description":"Keyset pagination uses the id > last_seen pattern for O(log n) performance."},{"title":"Keyset with Multiple Columns","useCase":"Tie-breaking pagination.","code":"-- Initial query\nSELECT id, name, created_at\nFROM employees\nORDER BY created_at DESC, id DESC\nLIMIT 20;\n-- Last item: created_at = '2024-06-15', id = 500\n\n-- Next page with tuple comparison\nSELECT id, name, created_at\nFROM employees\nWHERE (created_at, id) < ('2024-06-15', 500)\nORDER BY created_at DESC, id DESC\nLIMIT 20;\n\n-- Needs composite index on (created_at DESC, id DESC)","description":"Tuple comparison handles ties when multiple rows share the same sort value."},{"title":"Keyset for Forward/Backward","useCase":"Bi-directional pagination.","code":"-- Forward (next page)\nSELECT * FROM employees\nWHERE created_at < '2024-06-15'\nORDER BY created_at DESC\nLIMIT 20;\n\n-- Backward (previous page)\nSELECT * FROM employees\nWHERE created_at > '2024-06-01'\nORDER BY created_at ASC\nLIMIT 20;\n\n-- Reverse results on client side for display","description":"Bi-directional keyset pagination for both next and previous page support."},{"title":"Seek Method (Alternative)","useCase":"WHERE on unique column.","code":"-- Seek method (alternative to keyset)\nSELECT * FROM employees\nORDER BY salary DESC, id ASC\nLIMIT 20;\n-- Cursor: salary=85000, id=42\n\n-- Next page:\nSELECT * FROM employees\nWHERE salary < 85000\n   OR (salary = 85000 AND id > 42)\nORDER BY salary DESC, id ASC\nLIMIT 20;\n\n-- Requires composite index on (salary DESC, id ASC)","description":"Seek method handles complex ORDER BY with multiple columns and directions."}],"mcqQuestions":[{"question":"Why is OFFSET slow at deep pages?","options":["Network latency","Database scans discarded rows","Index lookup","Query parsing"],"answer":1,"explanation":"The database must scan and discard all rows up to the OFFSET value."},{"question":"What drives keyset pagination?","options":["LIMIT only","WHERE > last_value","OFFSET","RANDOM"],"answer":1,"explanation":"Keyset pagination uses WHERE condition on the sort column to fast-forward."},{"question":"What is required for keyset pagination?","options":["Unique sort column","Table index","Sequential IDs","Both A and B"],"answer":3,"explanation":"A unique sort column with an index is needed for reliable keyset pagination."},{"question":"Can keyset pagination jump to page N?","options":["Yes","No","Only with OFFSET","Only with cursors"],"answer":1,"explanation":"Keyset pagination cannot arbitrarily jump to a specific page number."},{"question":"What APIs commonly use cursor pagination?","options":["GitHub","Twitter","Stripe","All of the above"],"answer":3,"explanation":"Modern APIs use cursor (keyset) pagination for performance."},{"question":"What comparison handles multi-column keyset?","options":["AND","Tuple comparison","OR comparison","Subquery"],"answer":1,"explanation":"Tuple comparison (col1, col2) > (val1, val2) handles multi-column keyset."}]};
TOPICS_DATA["sql"]["sql-anti-patterns"] = {"id":"sql-anti-patterns","title":"SQL Anti-Patterns","difficulty":"intermediate","estimatedMinutes":25,"tldr":["SQL anti-patterns are common design and query practices that seem reasonable but cause problems at scale.","Anti-patterns lead to poor performance, data integrity issues, maintenance nightmares, and race conditions.","Recognizing anti-patterns is a hallmark of experienced SQL developers. The goal is not just to write SQL, but to write good SQL.","Most anti-patterns have well-known solutions or better alternatives."],"laymanDefinition":"SQL anti-patterns are like bad habits in cooking — putting your knives in the dishwasher seems convenient until they get dull. SELECT * seems quick until you break the frontend by adding a column. Each anti-pattern has a better way that you learn through experience.","deepDive":[{"heading":"SELECT * in Production","text":"Problem: returns unnecessary columns (wasted bandwidth), breaks when schema changes (new columns may cause errors), prevents index-only scans. Solution: explicitly list needed columns. Exception: EXISTS (SELECT 1) or COUNT(*) which optimize * effectively."},{"heading":"Implicit Columns / SELECT DISTINCT as Band-Aid","text":"Problem: writing SELECT * on a JOIN and adding DISTINCT to deduplicate — hides the underlying data issue (missing join condition or unintended cross product). Solution: specify exact columns needed and fix the join logic."},{"heading":"Non-Indexed Foreign Keys","text":"Problem: FK columns without indexes. Every INSERT on child table checks parent (fast enough). Every DELETE on parent checks children (full table scan on child unless indexed). Solution: always index foreign key columns."},{"heading":"Death by a Thousand ORs","text":"Problem: WHERE status = \\'x\\' OR status = \\'y\\' OR status = \\'z\\' — multiple OR conditions on the same column. Solution: use IN (status IN (\\'x\\', \\'y\\', \\'z\\')) and ensure the column is indexed."},{"heading":"Using Functions on Indexed Columns in WHERE","text":"Problem: WHERE YEAR(date_col) = 2024 prevents index usage (function must evaluate for every row). Solution: WHERE date_col >= \\'2024-01-01\\' AND date_col < \\'2025-01-01\\' (sargable — can use index)."}],"interviewAnswer":"Recognizing SQL anti-patterns comes with experience. The most common ones are easy to fix and prevent. Always measure (EXPLAIN ANALYZE) before optimizing. The biggest anti-pattern is premature optimization without understanding the actual query plan.","interviewQuestions":[{"question":"What is wrong with SELECT *?","answer":"Returns unnecessary columns (wasted bandwidth), prevents index-only scans, breaks on schema changes, and makes dependencies unclear."},{"question":"Why should you index foreign keys?","answer":"DELETE on parent requires scanning child table for references. Without index, this is a full table scan. INSERT on child also checks parent."},{"question":"What is the problem with functions in WHERE?","answer":"Functions on indexed columns prevent index usage (non-sargable). Database cannot use index because it would need to compute the function for every index entry."},{"question":"What is the problem with OR conditions?","answer":"Multiple OR conditions on the same column are less efficient than IN. IN uses a single index lookup; OR may use multiple scans or fall back to sequential scan."},{"question":"What is the EAV anti-pattern?","answer":"Entity-Attribute-Value: a general-purpose table (entity_id, attribute, value) instead of proper columns. Leads to complex queries, poor performance, and no type safety."},{"question":"What is the God Table anti-pattern?","answer":"A single table with too many columns, trying to handle multiple entity types. Leads to sparse columns, confusing schema, and maintenance issues. Solution: normalize."},{"question":"What is the implicit column problem?","answer":"Using SELECT * on JOINs and adding DISTINCT to remove duplicates masks incorrect join conditions. Always specify columns to make dependencies explicit."},{"question":"What is n+1 query problem?","answer":"Making one query to get parent rows, then N queries to get child data for each parent. Solution: use JOIN, batch queries, or eager loading in ORMs."},{"question":"What is metadata tribbles?","answer":"Adding columns for every new attribute without normalization. The table grows wider and wider with sparse columns. Solution: use JSONB for variable attributes or normalize."},{"question":"What is the rounding error anti-pattern?","answer":"Using FLOAT/DOUBLE for monetary values causes rounding errors over time. Always use DECIMAL/NUMERIC for exact precision money calculations."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">SQL Anti-Patterns</text><rect x=\"10\" y=\"35\" width=\"130\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"75\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">SELECT *</text><text x=\"75\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Bad practice</text><rect x=\"10\" y=\"65\" width=\"130\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"75\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Unindexed FK</text><text x=\"75\" y=\"93\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Slow DELETE</text><rect x=\"10\" y=\"95\" width=\"130\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"75\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Fn on col</text><text x=\"75\" y=\"123\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">No index use</text><rect x=\"10\" y=\"125\" width=\"130\" height=\"25\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"75\" y=\"141\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">EAV pattern</text><text x=\"75\" y=\"153\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Complex query</text><rect x=\"10\" y=\"155\" width=\"130\" height=\"25\" rx=\"4\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1\"/><text x=\"75\" y=\"171\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">God Table</text><text x=\"75\" y=\"183\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Too wide</text><line x1=\"140\" y1=\"48\" x2=\"170\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"140\" y1=\"78\" x2=\"170\" y2=\"78\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"140\" y1=\"108\" x2=\"170\" y2=\"108\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"140\" y1=\"138\" x2=\"170\" y2=\"138\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"140\" y1=\"168\" x2=\"170\" y2=\"168\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"180\" y=\"35\" width=\"200\" height=\"155\" rx=\"4\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1\"/><text x=\"280\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">SQL Anti-Patterns</text><text x=\"280\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Common mistakes: SELECT *, unindexed FKs, non-sargable queries, EAV, and more.</text><text x=\"240\" y=\"220\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">SQL Anti-Patterns: Common design and query mistakes and their better alternatives.</text></svg>","codeExamples":[{"title":"Non-Sargable Query","useCase":"Fix functions in WHERE.","code":"-- BAD: Function on indexed column\nSELECT * FROM orders\nWHERE EXTRACT(YEAR FROM order_date) = 2024;\n\n-- GOOD: Sargable range query\nSELECT * FROM orders\nWHERE order_date >= '2024-01-01'\n  AND order_date < '2025-01-01';\n\n-- Also bad:\nSELECT * FROM users WHERE LOWER(email) = 'alice@x.com';\n\n-- Fix: expression index\nCREATE INDEX ON users(LOWER(email));","description":"Non-sargable vs sargable queries — the latter can use indexes."},{"title":"EAV Anti-Pattern","useCase":"Entity-Attribute-Value problem.","code":"-- BAD: EAV table (anti-pattern)\nCREATE TABLE product_attributes (\n  product_id INT,\n  attribute VARCHAR(50),\n  value TEXT\n);\n\n-- Query becomes painful:\nSELECT p.name, a1.value AS color, a2.value AS weight\nFROM products p\nLEFT JOIN product_attributes a1\n  ON a1.product_id = p.id AND a1.attribute = 'color'\nLEFT JOIN product_attributes a2\n  ON a2.product_id = p.id AND a2.attribute = 'weight';\n\n-- GOOD: Proper columns\nCREATE TABLE products (\n  id INT, name TEXT, color TEXT, weight DECIMAL\n);","description":"EAV leads to painful pivot queries. Normalize properly."},{"title":"N+1 Query Problem","useCase":"Avoid in application code.","code":"// BAD: N+1 queries (application code)\nconst departments = await db.query(\"SELECT * FROM departments\");\nfor (const dept of departments) {\n  const employees = await db.query(\n    \"SELECT * FROM employees WHERE dept_id = \" + dept.id\n  );\n  // 1 query for departments + N for employees\n}\n\n// GOOD: Single JOIN query\nconst result = await db.query(\"\n  SELECT d.name AS dept, e.name AS emp\n  FROM departments d\n  JOIN employees e ON e.dept_id = d.id\n  ORDER BY d.name;\n\");","description":"N+1 problem: one query for parents, N for children. Fix with JOIN or eager loading."},{"title":"Unindexed Foreign Key","useCase":"Index FKs for DELETE performance.","code":"-- BAD: FK without index\nCREATE TABLE orders (\n  id SERIAL PRIMARY KEY,\n  customer_id INT REFERENCES customers(id) -- no index!\n);\n\n-- DELETE FROM customers WHERE id = 5\n-- must full scan orders table to check FK reference\n\n-- GOOD: FK with index\nCREATE INDEX idx_orders_customer ON orders(customer_id);\n\n-- Now DELETE is fast (index lookup on orders)","description":"Unindexed FKs cause full table scans on parent DELETE operations."},{"title":"Implicit DISTINCT Mask","useCase":"Hidden join problem.","code":"-- BAD: DISTINCT masking a join issue\nSELECT DISTINCT c.*\nFROM customers c\nJOIN orders o ON c.id = o.customer_id;\n-- DISTINCT is needed because customers appear multiple times\n-- But why? Do we actually want all customers with orders?\n\n-- GOOD: Be explicit\nSELECT c.* FROM customers c\nWHERE EXISTS (\n  SELECT 1 FROM orders o WHERE o.customer_id = c.id\n);\n\n-- Or if duplicates are expected:\nSELECT DISTINCT c.* FROM customers c\nJOIN orders o ON c.id = o.customer_id","description":"DISTINCT often masks unintended row multiplication. Use EXISTS for existence checks."}],"mcqQuestions":[{"question":"What is wrong with SELECT *?","options":["Faster queries","Returns unnecessary columns","Uses less memory","Better for indexes"],"answer":1,"explanation":"SELECT * returns unnecessary columns and prevents index-only scans."},{"question":"What does non-sargable mean?","options":["Uses indexes","Cannot use index efficiently","Very fast","Uses sequential scan"],"answer":1,"explanation":"Non-sargable queries cannot use indexes because of functions on indexed columns."},{"question":"What is the EAV anti-pattern?","options":["Entity-Attribute-Value design","Eager loading pattern","Error handling pattern","Execution plan view"],"answer":0,"explanation":"EAV is a general-purpose table design that leads to complex queries."},{"question":"What problem does n+1 describe?","options":["1 + N queries for parent + children","N + 1 table join","N + 1 indexes","1 + N columns"],"answer":0,"explanation":"N+1: one query for parents, N queries for children."},{"question":"What is the solution to unindexed foreign keys?","options":["Remove the FK","Add an index","Use a view","Denormalize"],"answer":1,"explanation":"Always add an index on foreign key columns."},{"question":"Why avoid functions on indexed columns in WHERE?","options":["They error","They prevent index usage","They are slow syntax","They return wrong results"],"answer":1,"explanation":"Functions on indexed columns make the query non-sargable — indexes cannot be used."}]};
TOPICS_DATA["sql"]["sql-db-comparison"] = {"id":"sql-db-comparison","title":"PostgreSQL vs MySQL vs SQL Server","difficulty":"beginner","estimatedMinutes":20,"tldr":["PostgreSQL: most advanced open-source RDBMS, strict SQL standards compliance, extensible, feature-rich.","MySQL: fast for simple read-heavy workloads, widespread LAMP stack usage, simpler replication.","SQL Server: excellent tooling (SSMS), deep .NET integration, business intelligence features.","SQLite: embedded database, zero configuration, file-based, ideal for mobile and small applications."],"laymanDefinition":"Choosing a database is like choosing a vehicle. PostgreSQL is a heavy-duty truck — powerful, can handle any job, but takes more skill. MySQL is a reliable sedan — simple, fast for commuting, and easy to maintain. SQLite is a bicycle — perfect for short trips, no fuel needed.","deepDive":[{"heading":"PostgreSQL Strengths","text":"Advanced features: JSONB, full-text search, window functions, CTEs, recursion, GiST/GIN indexes, table inheritance, foreign data wrappers. Strict ACID compliance. Extensible: custom types, operators, functions. Best open-source choice for complex workloads."},{"heading":"MySQL Strengths","text":"Simple and fast for basic CRUD. Widespread hosting support. Easy replication (built-in). Lighter memory footprint. Great ecosystem (WordPress, Drupal, Laravel). InnoDB with ACID. Good for read-heavy applications."},{"heading":"SQL Server Strengths","text":"Best tooling: SSMS, SSIS, SSRS, SSAS. Deep .NET integration (Entity Framework). T-SQL with advanced analytics. Columnstore indexes for data warehousing. Always On availability groups. Best for Microsoft shops."},{"heading":"Feature Comparison","text":"CTEs: PostgreSQL (with recursion), SQL Server (with recursion), MySQL 8+ (no recursion). Window functions: all three modern versions. JSON: PostgreSQL (JSONB best), MySQL (JSON type), SQL Server (JSON functions). Array type: PostgreSQL only."},{"heading":"Performance Characteristics","text":"MySQL: faster for simple SELECT/INSERT with good indexes. PostgreSQL: faster for complex queries, joins, aggregations. SQL Server: excellent optimizer, best with large data warehouses. SQLite: fastest for single-user/small datasets."}],"interviewAnswer":"PostgreSQL is the best general-purpose choice for new applications — it is the most feature-rich, standards-compliant, and extensible open-source database. MySQL is a proven choice for simple web applications. SQL Server is the choice for Microsoft ecosystems.","interviewQuestions":[{"question":"What is PostgreSQL best at?","answer":"Advanced queries, JSON, full-text search, CTEs, window functions, extensibility, and standards compliance."},{"question":"What is MySQL best at?","answer":"Simple read-heavy workloads, LAMP stack applications, ubiquitous hosting support, easy replication."},{"question":"What is SQL Server best at?","answer":".NET integration, BI/analytics, SSMS tooling, columnstore indexes, enterprise features."},{"question":"Which database has the best JSON support?","answer":"PostgreSQL with JSONB — indexed, fast operators, binary format."},{"question":"Does MySQL support CTEs?","answer":"MySQL 8.0+ supports non-recursive CTEs but not recursive CTEs."},{"question":"Which database supports array types?","answer":"Only PostgreSQL has native array types among the major databases."},{"question":"What is the best database for a new web application?","answer":"PostgreSQL — best combination of features, performance, and community."},{"question":"What is SQLite best for?","answer":"Mobile apps, embedded systems, testing, small-scale applications, single-user desktop apps."},{"question":"Which has the best query optimizer?","answer":"PostgreSQL and SQL Server both have excellent optimizers. MySQL\\'s optimizer has improved significantly."},{"question":"Which database has the best free tooling?","answer":"PostgreSQL: pgAdmin, DBeaver. MySQL: MySQL Workbench. SQL Server: SSMS (best overall tooling)."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">PostgreSQL vs MySQL vs SQL Server</text><rect x=\"10\" y=\"35\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"65\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">PostgreSQL</text><text x=\"65\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Feature-rich</text><rect x=\"10\" y=\"65\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"65\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">MySQL</text><text x=\"65\" y=\"93\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Simple/fast</text><rect x=\"10\" y=\"95\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"65\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">SQL Server</text><text x=\"65\" y=\"123\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Enterprise</text><rect x=\"10\" y=\"125\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"65\" y=\"141\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">SQLite</text><text x=\"65\" y=\"153\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Embedded</text><rect x=\"10\" y=\"155\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1\"/><text x=\"65\" y=\"171\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Choose</text><text x=\"65\" y=\"183\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Match needs</text><line x1=\"120\" y1=\"48\" x2=\"150\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"78\" x2=\"150\" y2=\"78\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"108\" x2=\"150\" y2=\"108\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"138\" x2=\"150\" y2=\"138\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"168\" x2=\"150\" y2=\"168\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"35\" width=\"220\" height=\"155\" rx=\"4\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1\"/><text x=\"270\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Database Comparison</text><text x=\"270\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">PostgreSQL vs MySQL vs SQL Server vs SQLite — choose the right tool.</text><text x=\"240\" y=\"220\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Database Comparison: Strengths, weaknesses, and use cases for each major SQL database.</text></svg>","codeExamples":[{"title":"Feature Comparison Table","useCase":"Key features across databases.","code":"-- Feature           | PostgreSQL | MySQL  | SQL Server |\n-- CTEs (Recursive) | Yes        | 8+ only| Yes        |\n-- Window Functions | Yes        | 8+     | Yes        |\n-- JSON/JSONB       | Yes (best) | Yes    | Functions  |\n-- Array Type       | Yes        | No     | No         |\n-- Full-Text Search | Excellent  | Basic  | Excellent  |\n-- GIN/GiST Index   | Yes        | No     | No         |\n-- FDW/Linked Srvr  | Yes (FDW)  | FEDERATED| Linked Svr|\n-- Materialized View| Yes        | No     | Yes        |\n-- Table Partition  | Yes        | Yes    | Yes        |\n-- UUID Type        | Native     | Binary | GUID       |\n-- License          | Open (MIT) | Dual   | Commercial |\n-- Default Port     | 5432       | 3306   | 1433       |","description":"Feature comparison across major SQL databases."},{"title":"Migration Paths","useCase":"Moving between databases.","code":"-- PostgreSQL to MySQL:\n--   Replace SERIAL with AUTO_INCREMENT\n--   Replace || with CONCAT()\n--   Replace ILIKE with LOWER() + LIKE\n--   Remove RETURNING, change order\n\n-- MySQL to PostgreSQL:\n--   Replace AUTO_INCREMENT with SERIAL\n--   Replace CONCAT() with ||\n--   Add explicit type casts\n--   Change backtick quoting to double quotes\n\n-- Common gotchas:\n--   LIMIT/OFFSET syntax is the same\n--   JOIN syntax is standard across all\n--   String comparison: PostgreSQL is case-sensitive","description":"Key differences when migrating between databases."},{"title":"Sample Query Comparison","useCase":"Same query in different dialects.","code":"-- PostgreSQL:\nSELECT name, salary FROM employees\nWHERE salary > (SELECT AVG(salary) FROM employees)\nORDER BY salary DESC LIMIT 10;\n\n-- MySQL (same, but backtick quoting):\nSELECT `name`, `salary` FROM `employees`\nWHERE `salary` > (SELECT AVG(`salary`) FROM `employees`)\nORDER BY `salary` DESC LIMIT 10;\n\n-- SQL Server (TOP instead of LIMIT):\nSELECT TOP 10 name, salary FROM employees\nWHERE salary > (SELECT AVG(salary) FROM employees)\nORDER BY salary DESC;","description":"Syntax differences for the same query across databases."},{"title":"Benchmarking Advice","useCase":"How to choose.","code":"-- Read-heavy web app: MySQL or PostgreSQL\n-- Complex analytics/reporting: PostgreSQL or SQL Server\n-- .NET / Microsoft ecosystem: SQL Server\n-- Embedded / mobile: SQLite\n-- Full-text search heavy: PostgreSQL\n-- JSON document needs: PostgreSQL (JSONB is best)\n-- Budget constrained: PostgreSQL (free, full-featured)\n-- Enterprise with support needs: SQL Server or MySQL (Oracle)\n\n-- Best practice: benchmark with YOUR workload,\n-- not generic benchmarks","description":"Decision guide for choosing the right database for your project."},{"title":"SQLite for Testing","useCase":"SQLite in development.","code":"-- Why SQLite for testing:\n--   No server setup needed\n--   In-memory option for tests\n--   Fast test execution\n--   File-based for easy clean-up\n\n-- Gotchas when using SQLite vs PostgreSQL:\n--   No array type\n--   Limited ALTER TABLE\n--   No JSON functions (before 3.38)\n--   Flexible type system (no type enforcement)\n--   Different date/time functions","description":"SQLite is ideal for testing but has important differences from PostgreSQL."}],"mcqQuestions":[{"question":"Which database has the best JSON support?","options":["MySQL","PostgreSQL","SQL Server","SQLite"],"answer":1,"explanation":"PostgreSQL with JSONB has the best JSON support with indexing and operators."},{"question":"Which databases support recursive CTEs?","options":["PostgreSQL and SQL Server","MySQL only","SQLite only","All of them"],"answer":0,"explanation":"PostgreSQL and SQL Server support recursive CTEs; MySQL 8+ has non-recursive only."},{"question":"What is SQLite best for?","options":["Enterprise apps","Embedded/mobile","Web apps","Data warehousing"],"answer":1,"explanation":"SQLite is ideal for embedded systems, mobile apps, and testing."},{"question":"Which database has native array types?","options":["MySQL","PostgreSQL","SQL Server","None"],"answer":1,"explanation":"PostgreSQL is the only major database with native array types."},{"question":"What port does PostgreSQL use by default?","options":["3306","5432","1433","27017"],"answer":1,"explanation":"PostgreSQL default port is 5432."},{"question":"Which database uses TOP instead of LIMIT?","options":["PostgreSQL","MySQL","SQL Server","SQLite"],"answer":2,"explanation":"SQL Server uses SELECT TOP n instead of LIMIT n."}]};
TOPICS_DATA["sql"]["sql-orms"] = {"id":"sql-orms","title":"ORMs & SQL","difficulty":"intermediate","estimatedMinutes":20,"tldr":["Object-Relational Mappers (ORMs) bridge the gap between object-oriented programming and relational databases.","Popular ORMs: Sequelize (Node.js), Prisma (Node.js), TypeORM (TypeScript), Django ORM (Python), Entity Framework (.NET).","ORMs handle: connection pooling, query generation, migration management, relationship mapping, and type casting.","ORMs are great for CRUD but can produce inefficient queries for complex operations. Know when to drop to raw SQL."],"laymanDefinition":"An ORM is like having a translator between two people who speak different languages. Your application speaks objects (JavaScript/Python classes), the database speaks tables and rows. The ORM translates: save this object → INSERT, find by id → SELECT, update fields → UPDATE.","deepDive":[{"heading":"How ORMs Work","text":"Model class maps to table. Class instances map to rows. Properties map to columns. Methods like find(), create(), update() generate SQL. Relationships defined with belongsTo, hasMany decorators. Query builder builds SQL programmatically."},{"heading":"ORM Advantages","text":"Productivity: write application code, not SQL. Type safety: TypeScript/type-checking. Migration management: version-controlled schema changes. Relationship loading: eager/lazy loading with simple method calls. Connection management built-in."},{"heading":"ORM Disadvantages","text":"N+1 query problem (if lazy loading). Inefficient queries (loading too much data). Complex queries are hard to express. Hidden performance costs (SELECT * by default). Learning SQL is still necessary to debug ORM-generated queries."},{"heading":"When to Use Raw SQL","text":"Complex aggregations and window functions. Bulk operations. Reporting queries. Full-text search. Recursive CTEs. Performance-critical paths. Any query where you need specific index usage or query plan."},{"heading":"Common ORM Patterns","text":"Eager loading: .include() or JOIN (prevents N+1). Batch operations: bulk create/update. Transactions: database-level ACID. Raw queries: .query() or .raw() for complex SQL. Pagination: built-in .paginate() or manual limit/offset."}],"interviewAnswer":"ORMs are essential for productivity but are not a replacement for SQL knowledge. Use ORMs for 80% of queries (simple CRUD). Use raw SQL for the 20% that are complex or performance-critical. Always check the actual SQL that your ORM generates.","interviewQuestions":[{"question":"What is an ORM?","answer":"Object-Relational Mapper — bridges application objects with database tables by auto-generating SQL from code."},{"question":"What are popular Node.js ORMs?","answer":"Sequelize (oldest, mature), Prisma (modern, type-safe), TypeORM (TypeScript-first), Knex (query builder)."},{"question":"What is the N+1 problem in ORMs?","answer":"Loading parent objects triggers N child queries (one per parent). Solved by eager loading (.include() or JOIN)."},{"question":"Why might an ORM be inefficient?","answer":"SELECT * by default, loading unnecessary columns. Generating multiple queries instead of JOINs. Not using indexes optimally."},{"question":"When should you use raw SQL instead of ORM?","answer":"Complex aggregations, window functions, recursive CTEs, bulk operations, reporting queries."},{"question":"What does eager loading do?","answer":"Loads related data in a single query using JOINs, preventing the N+1 problem."},{"question":"What is a migration in ORM context?","answer":"Version-controlled schema changes. Migrations are code files that describe table creation, alteration, and seeding."},{"question":"What is a query builder?","answer":"A programmatic API for constructing SQL queries (like Knex). More control than ORM but less verbose than raw SQL."},{"question":"Does every ORM support raw SQL?","answer":"Yes. All major ORMs provide a way to execute raw SQL for complex queries."},{"question":"Should you learn SQL if you use an ORM?","answer":"Absolutely. Debugging ORM issues requires understanding the generated SQL. Complex queries need raw SQL. Performance tuning requires knowledge of indexes and query plans."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">ORMs & SQL</text><rect x=\"10\" y=\"35\" width=\"120\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"70\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">ORM Layer</text><text x=\"70\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">App <-> DB</text><line x1=\"130\" y1=\"48\" x2=\"160\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"170\" y=\"35\" width=\"120\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"230\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">CRUD</text><text x=\"230\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Auto SQL</text><rect x=\"170\" y=\"65\" width=\"120\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"230\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Complex</text><text x=\"230\" y=\"93\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Raw SQL</text><rect x=\"170\" y=\"95\" width=\"120\" height=\"25\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"230\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">N+1</text><text x=\"230\" y=\"123\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Eager load</text><rect x=\"10\" y=\"95\" width=\"120\" height=\"25\" rx=\"4\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1\"/><text x=\"70\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Migration</text><text x=\"70\" y=\"123\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Schema versions</text><line x1=\"290\" y1=\"48\" x2=\"320\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"290\" y1=\"78\" x2=\"320\" y2=\"78\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"290\" y1=\"108\" x2=\"320\" y2=\"108\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"330\" y=\"35\" width=\"150\" height=\"100\" rx=\"4\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1\"/><text x=\"405\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">ORMs & SQL</text><text x=\"405\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">ORMs for productivity. Raw SQL for performance. Know both.</text><text x=\"240\" y=\"195\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">ORMs & SQL: Understanding ORM-generated SQL and knowing when to drop to raw queries.</text></svg>","codeExamples":[{"title":"Sequelize Example","useCase":"Node.js ORM in action.","code":"// Model definition\nconst User = sequelize.define('User', {\n  name: DataTypes.STRING,\n  email: { type: DataTypes.STRING, unique: true },\n  salary: DataTypes.DECIMAL(10,2)\n});\n\n// ORM generates:\n// CREATE TABLE \"Users\" (\n//   id SERIAL PRIMARY KEY,\n//   name VARCHAR(255),\n//   email VARCHAR(255) UNIQUE,\n//   salary DECIMAL(10,2),\n//   createdAt TIMESTAMPTZ,\n//   updatedAt TIMESTAMPTZ\n// );","description":"Sequelize model definition and the SQL it generates."},{"title":"Prisma Example","useCase":"Modern type-safe ORM.","code":"// Schema (schema.prisma)\nmodel User {\n  id    Int     @id @default(autoincrement())\n  name  String\n  posts Post[]\n}\n\nmodel Post {\n  id      Int  @id @default(autoincrement())\n  title   String\n  userId  Int\n  user    User @relation(fields: [userId], references: [id])\n}\n\n// Query with eager loading:\n// const users = await prisma.user.findMany({\n//   include: { posts: true }\n// });\n// Generates: SELECT u.*, p.* FROM User u LEFT JOIN Post p ...","description":"Prisma schema and eager loading prevents N+1 queries."},{"title":"N+1 vs Eager Loading","useCase":"Critical ORM pattern.","code":"// BAD: N+1 queries\nconst orders = await Order.findAll(); // 1 query\nfor (const order of orders) {\n  const customer = await order.getCustomer(); // N queries!\n}\n// Total: 1 + N queries (slow!)\n\n// GOOD: Eager loading\nconst orders = await Order.findAll({\n  include: [Customer]  // LEFT JOIN, 1 query\n});\n// Total: 1 query (fast!)","description":"Eager loading prevents the N+1 problem by using JOINs."},{"title":"Raw SQL in ORM","useCase":"When ORM is not enough.","code":"// Prisma raw query\nconst result = await prisma.$queryRaw`\n  SELECT department, COUNT(*) as count,\n    AVG(salary) as avg_salary\n  FROM employees\n  GROUP BY department\n  HAVING COUNT(*) > 5\n  ORDER BY avg_salary DESC\n`;\n\n// TypeORM raw query\nconst result = await connection.query(`\n  WITH ranked AS (\n    SELECT *, ROW_NUMBER() OVER (\n      PARTITION BY dept_id ORDER BY salary DESC\n    ) AS rn FROM employees\n  ) SELECT * FROM ranked WHERE rn <= 3\n`);","description":"Raw SQL in ORMs for complex queries like aggregations and window functions."},{"title":"Migration Example","useCase":"Version-controlled schema.","code":"// Migration file (Sequelize)\nmodule.exports = {\n  up: async (queryInterface, Sequelize) => {\n    await queryInterface.createTable('Tasks', {\n      id: { type: Sequelize.INTEGER, autoIncrement: true, primaryKey: true },\n      title: { type: Sequelize.STRING, allowNull: false },\n      status: { type: Sequelize.ENUM('todo', 'done') },\n      userId: {\n        type: Sequelize.INTEGER,\n        references: { model: 'Users', key: 'id' },\n        onDelete: 'CASCADE'\n      }\n    });\n  },\n  down: async (queryInterface) => {\n    await queryInterface.dropTable('Tasks');\n  }\n};","description":"Migrations provide version-controlled, reversible schema changes."}],"mcqQuestions":[{"question":"What does ORM stand for?","options":["Object-Relational Mapping","Object-Relational Model","Object-Resource Mapper","Online Relational Manager"],"answer":0,"explanation":"ORM stands for Object-Relational Mapping."},{"question":"What problem does eager loading solve?","options":["Slow queries","N+1 queries","Connection pooling","Type safety"],"answer":1,"explanation":"Eager loading with .include() or JOIN prevents N+1 query problems."},{"question":"When should you use raw SQL over ORM?","options":["Simple CRUD","Complex aggregations/window functions","Model definitions","Migration creation"],"answer":1,"explanation":"Use raw SQL for complex queries like aggregations, window functions, and recursive CTEs."},{"question":"What is a migration?","options":["Schema versioning","Data backup","Query optimization","Connection management"],"answer":0,"explanation":"Migrations are version-controlled, reversible schema changes."},{"question":"Which is a modern type-safe ORM for Node.js?","options":["Sequelize","Prisma","Mongoose","Knex"],"answer":1,"explanation":"Prisma is a modern type-safe ORM for Node.js and TypeScript."},{"question":"Why should you learn SQL if you use an ORM?","options":["No need","To debug and optimize ORM queries","ORMs are always perfect","SQL is obsolete"],"answer":1,"explanation":"Understanding SQL is essential for debugging ORM-generated queries and writing efficient raw queries."}]};
TOPICS_DATA["sql"]["sql-migrations"] = {"id":"sql-migrations","title":"Database Migration & Version Control","difficulty":"intermediate","estimatedMinutes":20,"tldr":["Database migrations are version-controlled scripts that evolve the database schema over time in a reproducible way.","Migrations solve: shared schema across environments, team collaboration on schema changes, rollback capability, and deployment automation.","Tools: node-pg-migrate, Flyway (Java), Alembic (Python), ActiveRecord Migrations (Rails), golang-migrate.","Best practice: one migration per change, always test both up and down, never modify existing migrations."],"laymanDefinition":"Migrations are like Git for your database schema. Just as you commit code changes incrementally, you create migration files for each schema change. \"Up\" applies the change, \"down\" reverts it. This means you can reproduce any version of your schema at any point in time.","deepDive":[{"heading":"Migration Structure","text":"Each migration has: up function (apply change) and down function (revert change). Naming: YYYYMMDDHHMMSS_description.sql or versioned numbers (001_create_users.sql). Tools track which migrations have been applied using a migrations table."},{"heading":"Migration Workflow","text":"Create migration → review → apply to dev → test → apply to staging → apply to production. Never modify an applied migration (create a new one to fix). Always test down before deploying up (ensures rollback works)."},{"heading":"Common Migration Types","text":"CREATE/ALTER/DROP TABLE. Add/drop columns. Add/drop indexes. Add/drop constraints (FK, UNIQUE). Data migrations (backfill, transform). Seed data (reference data, test data)."},{"heading":"Database Version Table","text":"Tools create a schema_migrations (or _migrations) table that records which migrations have been applied. Columns: version (unique ID), name, applied_at (timestamp), checksum. This table must never be modified manually."},{"heading":"Migration Safety","text":"Always have a tested down migration. Avoid locking large tables — use CONCURRENTLY for indexes. Test on a copy of production data. Have a rollback plan. For zero-downtime deployments: expand → migrate → contract pattern."}],"interviewAnswer":"Database migrations are essential for professional software development. They make schema changes repeatable, reviewable, and reversible. The investment in a good migration workflow pays back enormously in reduced deployment stress and incident recovery time.","interviewQuestions":[{"question":"What is a database migration?","answer":"A version-controlled, reversible script that changes the database schema."},{"question":"Why use migrations?","answer":"Reproducible schema across environments. Team collaboration. Rollback capability. Deployment automation."},{"question":"What is the up function?","answer":"Applies the migration — creates tables, adds columns, creates indexes, etc."},{"question":"What is the down function?","answer":"Reverts the migration — drops tables, removes columns, drops indexes."},{"question":"Should you modify an applied migration?","answer":"Never. Create a new migration to fix issues. Applied migrations are immutable history."},{"question":"What is a data migration?","answer":"A migration that transforms existing data — backfilling new columns, splitting fields, correcting values."},{"question":"What is a seed migration?","answer":"Populates reference data: countries, status values, admin users."},{"question":"What is the expand-migrate-contract pattern?","answer":"Zero-downtime migration: add new column (expand), migrate data gradually, remove old column (contract)."},{"question":"What tool is commonly used with Node.js?","answer":"node-pg-migrate, Knex.js migrations, Sequelize migrations, Prisma migrations."},{"question":"How do you test a migration?","answer":"Apply up, verify schema/data, apply down, verify schema is restored. Test on a copy of production data."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Database Migration & Version Control</text><rect x=\"10\" y=\"35\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"65\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Up</text><text x=\"65\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Apply change</text><rect x=\"10\" y=\"65\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"65\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Down</text><text x=\"65\" y=\"93\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Revert</text><rect x=\"10\" y=\"95\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"65\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Test</text><text x=\"65\" y=\"123\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Verify both</text><rect x=\"10\" y=\"125\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"65\" y=\"141\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Deploy</text><text x=\"65\" y=\"153\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Environments</text><rect x=\"10\" y=\"155\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1\"/><text x=\"65\" y=\"171\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Immutable</text><text x=\"65\" y=\"183\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Never modify</text><line x1=\"120\" y1=\"48\" x2=\"150\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"78\" x2=\"150\" y2=\"78\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"108\" x2=\"150\" y2=\"108\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"138\" x2=\"150\" y2=\"138\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"168\" x2=\"150\" y2=\"168\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"35\" width=\"220\" height=\"155\" rx=\"4\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1\"/><text x=\"270\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Migrations & Versioning</text><text x=\"270\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Version-controlled, reversible, and testable schema evolution.</text><text x=\"240\" y=\"220\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Database Migrations: Version-controlled schema changes with up/down for reproducibility.</text></svg>","codeExamples":[{"title":"Basic Migration (node-pg-migrate)","useCase":"Create users table.","code":"exports.up = (pgm) => {\n  pgm.createTable('users', {\n    id: 'id', // serial primary key\n    name: { type: 'varchar(100)', notNull: true },\n    email: { type: 'varchar(255)', unique: true, notNull: true },\n    created_at: { type: 'timestamptz', default: pgm.func('now()') }\n  });\n};\n\nexports.down = (pgm) => {\n  pgm.dropTable('users');\n};","description":"Basic create table migration with up (create) and down (drop)."},{"title":"Adding a Column Migration","useCase":"Schema evolution.","code":"// 002_add_salary_to_users.js\nexports.up = (pgm) => {\n  pgm.addColumn('users', {\n    salary: { type: 'decimal(10,2)', default: 0 }\n  });\n};\n\nexports.down = (pgm) => {\n  pgm.dropColumn('users', 'salary');\n};\n\n// Applied order: 001_create_users, 002_add_salary_to_users","description":"Incremental schema change — adding a column in a new migration."},{"title":"Data Migration Example","useCase":"Backfill data.","code":"// 003_backfill_full_name.js\nexports.up = async (pgm) => {\n  // Backfill full_name from first_name + last_name\n  await pgm.sql(`\n    UPDATE users\n    SET full_name = TRIM(\n      COALESCE(first_name, '') || ' ' || COALESCE(last_name, '')\n    )\n    WHERE full_name IS NULL;\n  `);\n};\n\nexports.down = (pgm) => {\n  // Data migration down is often left empty or reversed\n  pgm.sql(`UPDATE users SET full_name = NULL`);\n};","description":"Data migration for backfilling a new column from existing data."},{"title":"Migration for Index with CONCURRENTLY","useCase":"Zero-downtime index.","code":"// 004_add_index_concurrently.js\nexports.up = async (pgm) => {\n  // CREATE INDEX CONCURRENTLY does not lock the table\n  await pgm.sql(`\n    CREATE INDEX CONCURRENTLY idx_users_email\n    ON users (email);\n  `);\n};\n\nexports.down = async (pgm) => {\n  await pgm.sql(`\n    DROP INDEX CONCURRENTLY IF EXISTS idx_users_email;\n  `);\n};","description":"CONCURRENTLY allows index creation without locking the table for writes."},{"title":"Migrations Table","useCase":"How tools track state.","code":"-- Tools create a tracking table:\nSELECT * FROM schema_migrations;\n\n-- Output:\n-- version  |        applied_at\n-- ---------+----------------------------\n-- 001      | 2024-01-15 10:00:00+00\n-- 002      | 2024-01-20 14:30:00+00\n-- 003      | 2024-02-01 09:15:00+00\n\n-- To see pending migrations:\nSELECT * FROM migrations_to_apply();\n\n-- Never manually modify this table!","description":"The schema_migrations table tracks which migrations have been applied."}],"mcqQuestions":[{"question":"What is the up function in a migration?","options":["Reverts changes","Applies changes","Seeds data","Drops tables"],"answer":1,"explanation":"The up function applies the schema change."},{"question":"What is the down function for?","options":["Reverting the change","Applying again","Checking status","Optimizing"],"answer":0,"explanation":"The down function reverts the change made by up."},{"question":"Should you modify an applied migration?","options":["Yes","No, create a new one","Only the down","Only for bugs"],"answer":1,"explanation":"Never modify an applied migration — create a new one to fix issues."},{"question":"What pattern enables zero-downtime migrations?","options":["Up and down","Expand-migrate-contract","Forward only","Rolling update"],"answer":1,"explanation":"Expand-migrate-contract: add new, migrate data, remove old."},{"question":"What table tracks applied migrations?","options":["pg_tables","schema_migrations","applied_migrations","versions"],"answer":1,"explanation":"Migration tools create a schema_migrations table."},{"question":"Which keyword avoids table locking when creating an index?","options":["ONLINE","CONCURRENTLY","LOCK FREE","ASYNC"],"answer":1,"explanation":"CREATE INDEX CONCURRENTLY avoids table locks."}]};